/* AUTO-GENERATED — Vermont Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["VT"] = {"code":"VT","name":"Vermont","agency":"Vermont DMV","agencyShort":"DMV","handbook":"https://dmv.vermont.gov/sites/dmv/files/documents/VN-111-CDL_Driver_Manual.pdf","links":{},"en":[{"q":"What is the maximum legal vehicle width on Vermont highways before an over-width permit is required?","options":["8 feet (96 inches)","8 feet 6 inches (102 inches)","9 feet (108 inches)","8 feet 4 inches (100 inches)"],"answer":1,"explanation":"Under 23 V.S.A. § 1431, the maximum vehicle width in Vermont is 8 feet 6 inches (102 inches), excluding safety devices such as mirrors that extend up to 3 inches per side. Anything wider needs a DMV over-dimension permit. Source: 23 V.S.A. § 1431.","handbook":"","hbref":""},{"q":"What is the maximum legal vehicle height on Vermont highways without a permit?","options":["13 feet","14 feet","13 feet 6 inches","12 feet 6 inches"],"answer":2,"explanation":"23 V.S.A. § 1431 sets the maximum vehicle height at 13 feet 6 inches. Loads exceeding this require an over-dimension permit from the Vermont DMV. Source: 23 V.S.A. § 1431.","handbook":"","hbref":""},{"q":"In Vermont, what is the maximum overall length of a single motor vehicle (no trailer or semitrailer attached) without special permission?","options":["40 feet","53 feet","46 feet","48 feet"],"answer":2,"explanation":"Under 23 V.S.A. § 1432, no motor vehicle without a trailer or semitrailer attached that is longer than 46 feet overall may be operated on a Vermont highway except under special permission. Source: 23 V.S.A. § 1432.","handbook":"","hbref":""},{"q":"What is the maximum overall length of a combination of vehicles (truck with trailer or semitrailer) on a general Vermont highway without an over-length permit?","options":["65 feet","75 feet","70 feet","80 feet"],"answer":1,"explanation":"Under 23 V.S.A. § 1432, combinations of vehicles not exceeding 75 feet overall may operate on Vermont highways without a permit; longer combinations require an over-length permit. Source: 23 V.S.A. § 1432.","handbook":"","hbref":""},{"q":"On Vermont's Interstate and designated National Network highways, what is the maximum semitrailer length allowed in a tractor-semitrailer combination?","options":["48 feet","53 feet","45 feet","57 feet"],"answer":1,"explanation":"On the Interstate system and qualifying designated highways, Vermont applies federal component-length limits instead of the overall-length cap: the semitrailer in a tractor-semitrailer combination may be up to 53 feet. Source: 23 V.S.A. § 1432.","handbook":"","hbref":""},{"q":"For a tractor-semitrailer-trailer (twin-trailer) combination on Vermont's designated highway network, what is the maximum length of each trailer or semitrailer?","options":["28 feet each","30 feet each","27 feet each","33 feet each"],"answer":0,"explanation":"On the Interstate and designated network, twin-trailer combinations are governed by federal component limits: each trailer or semitrailer may be up to 28 feet. Source: 23 V.S.A. § 1432 (consistent with federal STAA standards).","handbook":"","hbref":""},{"q":"What is the maximum gross vehicle weight on Vermont highways for a standard commercial vehicle without a special permit?","options":["73,280 pounds","80,000 pounds","90,000 pounds","84,000 pounds"],"answer":1,"explanation":"Under 23 V.S.A. § 1392, the maximum gross vehicle weight is 80,000 pounds. Heavier loads require a DMV overweight permit or a statutory special-permit category. Source: 23 V.S.A. § 1392.","handbook":"","hbref":""},{"q":"On the federal Interstate Highway System in Vermont, what is the maximum single-axle weight, with no tolerance allowed?","options":["22,400 pounds","18,000 pounds","20,000 pounds","21,000 pounds"],"answer":2,"explanation":"Under 23 V.S.A. § 1391, on the Interstate (Eisenhower National System of Interstate and Defense Highways) the single-axle limit is 20,000 pounds with no tolerance allowed, matching federal law. Source: 23 V.S.A. § 1391.","handbook":"","hbref":""},{"q":"On the Interstate Highway System in Vermont, what is the maximum tandem-axle weight, with no tolerance allowed?","options":["36,000 pounds","34,000 pounds","32,000 pounds","38,000 pounds"],"answer":1,"explanation":"Under 23 V.S.A. § 1391, on the Interstate system the tandem-axle limit is 34,000 pounds with no tolerance allowed, consistent with federal weight standards. Source: 23 V.S.A. § 1391.","handbook":"","hbref":""},{"q":"On Vermont's non-Interstate (state and town) highways, what is the maximum single-axle weight before the 10 percent tolerance is applied?","options":["20,000 pounds","24,000 pounds","22,400 pounds","21,500 pounds"],"answer":2,"explanation":"Under 23 V.S.A. § 1391, on non-Interstate Vermont highways the single-axle limit is 22,400 pounds, with a 10 percent tolerance allowed. Source: 23 V.S.A. § 1391.","handbook":"","hbref":""},{"q":"On Vermont's non-Interstate highways, what is the maximum tandem-axle weight before the 10 percent tolerance is applied?","options":["34,000 pounds","36,000 pounds","32,000 pounds","40,000 pounds"],"answer":1,"explanation":"Under 23 V.S.A. § 1391, on non-Interstate Vermont highways the tandem-axle limit is 36,000 pounds, with a 10 percent tolerance allowed (a key state-specific difference from the Interstate 34,000-pound limit). Source: 23 V.S.A. § 1391.","handbook":"","hbref":""},{"q":"A key difference between Vermont's non-Interstate and Interstate axle-weight rules is the tolerance. What tolerance applies to the single- and tandem-axle limits on non-Interstate Vermont highways?","options":["No tolerance is allowed","A 5 percent tolerance is allowed","A 10 percent tolerance is allowed","A 15 percent tolerance is allowed"],"answer":2,"explanation":"Under 23 V.S.A. § 1391, the non-Interstate single-axle (22,400 lb) and tandem-axle (36,000 lb) limits carry a 10 percent tolerance, whereas the Interstate limits (20,000 lb / 34,000 lb) allow no tolerance. Source: 23 V.S.A. § 1391.","handbook":"","hbref":""},{"q":"What formula does Vermont use, consistent with federal law, to determine the maximum allowable gross weight for a group of axles based on their spacing and number?","options":["The Federal Bridge Formula (Formula B)","The Gross Combination Weight Rating formula","The Tandem Spacing Index","The Axle Load Equivalency formula"],"answer":0,"explanation":"Vermont applies the Federal Bridge Formula (Bridge Formula B), W = 500[LN/(N-1) + 12N + 36], to limit the weight carried on any group of axles based on the spacing (L) and number of axles (N), in addition to the single, tandem, and 80,000-lb gross limits. Source: federal Bridge Formula as applied under 23 V.S.A. ch. 13 / FHWA.","handbook":"","hbref":""},{"q":"In the Federal Bridge Formula used in Vermont, two consecutive axles are treated as a 'tandem' (rather than separate single axles) when their centers are spaced how far apart?","options":["More than 40 inches but not more than 96 inches","More than 96 inches but not more than 120 inches","Not more than 40 inches","More than 48 inches but not more than 108 inches"],"answer":0,"explanation":"Under the federal definitions applied in Vermont, a tandem axle is two or more consecutive axles whose centers are more than 40 inches but not more than 96 inches apart; axles 40 inches or less apart are treated as a single axle. Source: Federal Bridge Formula definitions / FHWA, applied under 23 V.S.A. ch. 13.","handbook":"","hbref":""},{"q":"When does a Vermont commercial vehicle operator generally need an over-dimension or overweight permit from the DMV?","options":["Only when crossing into another state","When the vehicle or load exceeds the statutory width, height, length, or weight limits","Only when the gross weight exceeds 100,000 pounds","Only at night or in winter conditions"],"answer":1,"explanation":"A Vermont DMV over-dimension/overweight permit is required whenever a vehicle or load exceeds the statutory limits (width over 8'6\", height over 13'6\", single vehicle over 46 ft, combination over 75 ft, or the applicable weight limits). Source: 23 V.S.A. ch. 13 and Vermont DMV Overweight/Overdimension Permit Rules (Code Vt. R. 14-050-019).","handbook":"","hbref":""},{"q":"Which Vermont agency issues over-dimension and overweight permits for travel on state highways and the Interstate system?","options":["The Vermont Agency of Natural Resources","The Federal Motor Carrier Safety Administration","The Vermont Department of Motor Vehicles (Commercial Vehicle Operations)","The county sheriff's department"],"answer":2,"explanation":"The Vermont DMV, through its Commercial Vehicle Operations unit (and the online VT Haul Pass system), issues over-dimension and overweight permits for state highways and the Interstate system under the Commissioner's authority. Source: Vermont DMV CVO Overweight/Overdimension Permit Rules; 23 V.S.A. § 1400.","handbook":"","hbref":""},{"q":"A trucking company needs to move oversize nondivisible loads repeatedly over the same routes throughout the year. Which Vermont permit type best fits this need?","options":["A single-trip permit","An emergency permit","A blanket (annual) permit","A registration-only permit"],"answer":2,"explanation":"Vermont DMV issues blanket (annual) permits for recurring movements of nondivisible loads, while single-trip permits cover one move within a limited window (about seven business days). Source: Vermont DMV Overweight/Overdimension Permit Rules (Code Vt. R. 14-050-019).","handbook":"","hbref":""},{"q":"For weight in excess of statutory limits on highways and bridges under a municipality's jurisdiction (other than Class 1 town highways), to whom must a Vermont overweight permit application be made?","options":["The Vermont DMV Commissioner","The municipality's appropriate legislative body (e.g., the selectboard)","The Federal Highway Administration","The Vermont State Police"],"answer":1,"explanation":"Under the Vermont permit rules, for operation exceeding weight limits on highways and bridges under a municipality's jurisdiction (except Class 1 town highways), the application is made to the appropriate municipal legislative body. Source: Code Vt. R. 14-050-019 (Overweight/Overdimension Vehicle Permits).","handbook":"","hbref":""},{"q":"Vermont's Special Excess Weight Permit (an annual permit for divisible loads) allows what maximum weight on the steering axle?","options":["10,000 pounds","12,000 pounds","14,000 pounds","20,000 pounds"],"answer":1,"explanation":"Under the Vermont Special Excess Weight Permit rule, axle limits are 12,000 pounds on the steering axle and 20,000 pounds on all other axles. Source: Vermont DMV Special Excess Weight Permit; Code Vt. R. 14-050-019.","handbook":"","hbref":""},{"q":"Vermont statute allows certain six-or-more-axle truck combinations operating under an annual special permit to reach what elevated gross weight on non-Interstate highways?","options":["85,000 pounds","108,000 pounds","99,000 pounds","95,000 pounds"],"answer":2,"explanation":"Under 23 V.S.A. § 1392, trucks with six or more load-bearing axles operating under a special annual permit may reach 99,000 pounds gross on non-Interstate highways; this Vermont-specific allowance does not apply to the Interstate system unless authorized by federal law. Source: 23 V.S.A. § 1392.","handbook":"","hbref":""},{"q":"In Vermont, a Class A CDL is required to operate which of the following?","options":["Any combination of vehicles with a GCWR of 26,001 lbs or more, where the towed unit(s) exceed 10,000 lbs GVWR","Any single vehicle with a GVWR of 26,001 lbs or more","Any vehicle designed to carry 16 or more passengers including the driver","Any vehicle of any weight that displays hazardous materials placards"],"answer":0,"explanation":"Vermont follows the federal CDL classification (49 CFR 383.91): Class A is any combination of vehicles with a GCWR of 26,001 lbs or more provided the towed vehicle(s) have a GVWR over 10,000 lbs. Source: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.91.","handbook":"","hbref":""},{"q":"Under Vermont rules, a Class B CDL covers which vehicles?","options":["Only buses carrying fewer than 16 passengers","Any single vehicle with a GVWR of 26,001 lbs or more, or such a vehicle towing a unit not over 10,000 lbs","Any combination where the trailer exceeds 10,000 lbs GVWR","Any vehicle requiring only a hazardous materials endorsement"],"answer":1,"explanation":"Vermont adopts the federal definition: Class B is any single vehicle with a GVWR of 26,001 lbs or more, or such a vehicle towing another vehicle not in excess of 10,000 lbs GVWR. Source: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.91.","handbook":"","hbref":""},{"q":"A Vermont Class C CDL is required when a vehicle does not meet the Class A or B weight definitions but is designed to transport at least how many passengers (including the driver), or carries placarded hazardous materials?","options":["10 passengers","12 passengers","16 passengers","24 passengers"],"answer":2,"explanation":"Vermont's Class C applies to a vehicle (not meeting Group A or B) designed to transport 16 or more passengers including the driver, or used to transport placarded hazardous materials. Source: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.91.","handbook":"","hbref":""},{"q":"Which endorsement does a Vermont CDL holder need to drive a vehicle transporting placarded amounts of hazardous materials?","options":["N endorsement","H endorsement","T endorsement","X endorsement"],"answer":1,"explanation":"The H (HazMat) endorsement authorizes transport of hazardous materials in placarded amounts. (The X code means combined Tank and HazMat.) Source: Vermont DMV HazMat Endorsements page / Vermont CDL Manual (VN-111).","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Vermont CDL restricted to intrastate (within-Vermont) commerce only?","options":["16 years old","17 years old","18 years old","21 years old"],"answer":2,"explanation":"Vermont requires an applicant to be at least 18 to obtain a CDL and operate a commercial motor vehicle in intrastate commerce. Source: Vermont DMV Commercial Driver's License page.","handbook":"","hbref":""},{"q":"What is the minimum age to operate a commercial motor vehicle in interstate commerce with a Vermont CDL?","options":["18 years old","19 years old","20 years old","21 years old"],"answer":3,"explanation":"A driver must be at least 21 to operate a commercial motor vehicle in interstate commerce, consistent with federal rule. Source: Vermont DMV Commercial Driver's License page / FMCSA 49 CFR 391.11.","handbook":"","hbref":""},{"q":"Before scheduling the CDL skills test, federal law (applied in Vermont) requires the applicant to hold the Commercial Learner Permit (CLP) for a minimum of how many days?","options":["7 days","14 days","30 days","60 days"],"answer":1,"explanation":"An applicant must hold the CLP for at least 14 days before taking the CDL skills test. Source: Vermont DMV CLP page / FMCSA 49 CFR 383.25.","handbook":"","hbref":""},{"q":"To apply for a Vermont Commercial Learner Permit (CLP), an applicant must already hold what?","options":["A valid Vermont Class D (regular) driver's license","A valid motorcycle endorsement","A federal TWIC card","A junior operator license"],"answer":0,"explanation":"Vermont requires CLP applicants to hold a valid Vermont Class D operator's license. Source: Vermont DMV Commercial Driver's Learner Permit page.","handbook":"","hbref":""},{"q":"For how long is a Vermont Commercial Learner Permit (CLP) valid from its date of issue?","options":["90 days","6 months","1 year","2 years"],"answer":2,"explanation":"A Vermont CLP is valid for one year (12 months) from the date of issue. Source: Vermont DMV Commercial Driver's Learner Permit page / FMCSA 49 CFR 383.25.","handbook":"","hbref":""},{"q":"While driving on public highways, the holder of a Vermont CLP must be accompanied by a person who:","options":["Holds any valid Vermont driver's license","Holds a valid CDL for the class of vehicle being driven, including the required endorsements","Is at least 25 years old","Is a certified DMV examiner"],"answer":1,"explanation":"A CLP holder must be accompanied, seated beside them, by a person holding a valid CDL for the type of vehicle being driven, with the appropriate endorsements. Source: Vermont DMV CLP page / FMCSA 49 CFR 383.25.","handbook":"","hbref":""},{"q":"Which endorsement is required to operate a tank vehicle hauling liquids or gases in bulk in Vermont?","options":["T endorsement","P endorsement","N endorsement","S endorsement"],"answer":2,"explanation":"The N (Tank Vehicle) endorsement is required to haul liquids/gases in bulk tanks. Source: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.93.","handbook":"","hbref":""},{"q":"A tank vehicle requiring the N endorsement is generally one carrying liquid or gas in a tank with an individual rated capacity over 119 gallons and an aggregate rated capacity of at least how many gallons?","options":["500 gallons","1,000 gallons","1,500 gallons","3,000 gallons"],"answer":1,"explanation":"The N endorsement applies to tanks with individual rated capacity greater than 119 gallons and aggregate rated capacity of 1,000 gallons or more of liquid or gas. Source: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.5.","handbook":"","hbref":""},{"q":"Which endorsement does a Vermont driver need to operate double or triple trailers?","options":["T endorsement","N endorsement","D endorsement","X endorsement"],"answer":0,"explanation":"The T endorsement authorizes operation of double and triple trailers and requires passing a knowledge test only. Source: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.93.","handbook":"","hbref":""},{"q":"To carry passengers (such as on a transit or charter bus) in Vermont, which endorsement is required?","options":["S endorsement","P endorsement","N endorsement","H endorsement"],"answer":1,"explanation":"The P (Passenger) endorsement is required to operate a vehicle designed to carry passengers above the CDL threshold; it requires a knowledge test and a skills test in a passenger vehicle. Source: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.93.","handbook":"","hbref":""},{"q":"In Vermont, a driver operating a school bus that transports students must hold the P endorsement plus which additional endorsement?","options":["H endorsement","T endorsement","S endorsement","N endorsement"],"answer":2,"explanation":"School bus drivers need the S (School Bus) endorsement in addition to the P endorsement. The S endorsement requires knowledge and skills testing on school bus operations. Source: Vermont DMV School Bus pages / FMCSA 49 CFR 383.93.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a HazMat (H) endorsement on a Vermont CDL?","options":["18 years old","19 years old","21 years old","25 years old"],"answer":2,"explanation":"Because hazardous materials transport requires interstate-level qualification and a federal security clearance, the HazMat endorsement requires the applicant to be at least 21. Source: Vermont DMV HazMat Endorsements page.","handbook":"","hbref":""},{"q":"Before Vermont can issue or renew a HazMat (H) endorsement, the applicant must clear what additional screening?","options":["A Transportation Security Administration (TSA) background check with fingerprinting","A state vision specialist exam","An employer road-test certification","A National Guard service review"],"answer":0,"explanation":"Under the USA PATRIOT Act, the HazMat endorsement requires a TSA security threat assessment, including fingerprinting and a background check, before issuance or renewal. Source: Vermont DMV HazMat Endorsements page / 49 CFR 1572.","handbook":"","hbref":""},{"q":"Under ELDT rules applied in Vermont, where must a first-time Class A applicant complete the required entry-level driver training?","options":["Any community college, regardless of listing","A provider listed on the FMCSA Training Provider Registry (TPR)","Only the Vermont DMV training office","Any employer-run program of the driver's choosing"],"answer":1,"explanation":"Effective Feb. 7, 2022, ELDT (theory and behind-the-wheel) must be completed with a provider listed on FMCSA's Training Provider Registry before the skills test. Source: FMCSA ELDT rule (49 CFR Part 380) / Vermont DMV CDL Training pages.","handbook":"","hbref":""},{"q":"Which of these does ELDT (Entry-Level Driver Training) NOT require before testing?","options":["First-time Class A or Class B CDL applicants","Drivers seeking a first-time H (HazMat) endorsement","Drivers upgrading from Class B to Class A","Drivers who already held the endorsement before February 7, 2022"],"answer":3,"explanation":"ELDT is not retroactive: drivers issued the CDL or S/P/H endorsement before Feb. 7, 2022 are not required to complete ELDT. It does apply to first-time Class A/B, B-to-A upgrades, and first-time S, P, and H endorsements. Source: FMCSA ELDT rule (49 CFR Part 380).","handbook":"","hbref":""},{"q":"Which set best describes the medical self-certification categories a Vermont CDL applicant must choose from?","options":["Commercial, Private, Agricultural, and Recreational","Non-excepted interstate, Excepted interstate, Non-excepted intrastate, and Excepted intrastate","Class A medical, Class B medical, Class C medical, and Exempt","Federal, State, Local, and Tribal"],"answer":1,"explanation":"CDL applicants self-certify to one of four categories: non-excepted interstate, excepted interstate, non-excepted intrastate, or excepted intrastate. Non-excepted drivers must maintain a valid medical examiner's certificate. Source: Vermont DMV CDL medical self-certification / FMCSA 49 CFR 383.71.","handbook":"","hbref":""},{"q":"While operating a commercial motor vehicle (CMV) in Vermont, what is the maximum lawful blood alcohol concentration (BAC) before the driver is considered to be operating with a prohibited alcohol level?","options":["0.04 percent","0.08 percent","0.02 percent","0.10 percent"],"answer":0,"explanation":"Vermont law makes it illegal to operate a CMV with a BAC of 0.04 percent or more, half the 0.08 limit for ordinary vehicles. Source: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.2.","handbook":"","hbref":""},{"q":"In Vermont, a CDL holder who is convicted of a FIRST major offense (such as driving a CMV with a BAC of 0.04 or more) is disqualified from operating a CMV for at least how long?","options":["1 year","60 days","6 months","3 years"],"answer":0,"explanation":"A first major offense disqualifies the driver from operating a CMV for one year. Source: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.2 (federal standard 49 CFR 383.51 adopted by Vermont).","handbook":"","hbref":""},{"q":"Under Vermont law, by operating a commercial motor vehicle a driver is deemed to have done what regarding chemical testing for alcohol?","options":["Given consent to alcohol testing","Waived the right to a CDL hearing","Agreed to a fixed $500 fine","Accepted a 30-day vehicle impound"],"answer":0,"explanation":"Vermont's implied-consent rule provides that anyone who operates a CMV is deemed to have given consent to alcohol testing. Source: Vermont CDL Manual § 1.2.2; 23 V.S.A. §§ 1202, 4116.","handbook":"","hbref":""},{"q":"If a Vermont CDL holder is convicted of a first major offense while transporting hazardous materials that require placards, the CMV disqualification period is increased to at least how long?","options":["3 years","1 year","18 months","5 years"],"answer":0,"explanation":"A first major offense committed while transporting placarded hazardous materials raises the disqualification from one year to three years. Source: 23 V.S.A. § 4116; 49 CFR 383.51 Table 1 as adopted by Vermont.","handbook":"","hbref":""},{"q":"In Vermont, what is the disqualification period for a SECOND major offense committed in a CMV (for example, a second alcohol-related offense from a separate incident)?","options":["Lifetime disqualification","3 years","10 years","5 years"],"answer":0,"explanation":"Two major offenses arising from separate incidents result in a lifetime CMV disqualification. Source: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.2.","handbook":"","hbref":""},{"q":"A Vermont CMV driver who refuses to submit to required blood alcohol testing faces what CDL consequence for that refusal?","options":["At least a 1-year CDL disqualification","A warning with no disqualification","A 30-day CDL disqualification","A $250 civil fine only"],"answer":0,"explanation":"Refusing to undergo alcohol testing is treated as a major offense, carrying a minimum one-year CMV disqualification (three years if hazmat-placarded). Source: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.2.","handbook":"","hbref":""},{"q":"How long is a Vermont CMV driver placed out-of-service if found to have any detectable amount of alcohol that is still UNDER 0.04 percent?","options":["24 hours","1 hour","72 hours","30 days"],"answer":0,"explanation":"A CMV driver with any measurable alcohol below 0.04 is placed out-of-service for 24 hours. Source: Vermont CDL Manual § 1.2.2; 49 CFR 392.5.","handbook":"","hbref":""},{"q":"In Vermont, being convicted of how many SERIOUS traffic violations within a three-year period triggers a 60-day CMV disqualification?","options":["2 serious violations","3 serious violations","4 serious violations","1 serious violation"],"answer":0,"explanation":"Two serious traffic violations within three years (separate incidents) result in a 60-day CMV disqualification. Source: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.3.","handbook":"","hbref":""},{"q":"A Vermont CDL holder convicted of THREE serious traffic violations within a three-year period is disqualified from operating a CMV for at least how long?","options":["120 days","60 days","180 days","1 year"],"answer":0,"explanation":"Three serious traffic violations within three years carry a 120-day CMV disqualification. Source: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.3.","handbook":"","hbref":""},{"q":"Under Vermont's CDL rules, speeding is a SERIOUS traffic violation when the driver exceeds the posted limit by how much?","options":["15 mph or more","10 mph or more","20 mph or more","5 mph or more"],"answer":0,"explanation":"Excessive speeding of 15 mph or more above the posted limit is a serious traffic violation. Source: Vermont CDL Manual § 1.2.3; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"Which of the following is classified as a SERIOUS traffic violation for a Vermont CDL holder?","options":["Following the vehicle ahead too closely","Parking in a no-parking zone","An expired registration sticker","A burned-out marker lamp"],"answer":0,"explanation":"Following too closely is one of the listed serious traffic violations, along with excessive speeding, reckless driving, and improper or erratic lane changes. Source: Vermont CDL Manual § 1.2.3; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"In Vermont, what is the CMV disqualification period for a FIRST conviction of a railroad-highway grade crossing violation?","options":["At least 60 days","At least 120 days","At least 30 days","At least 1 year"],"answer":0,"explanation":"A first railroad-highway grade crossing violation results in at least a 60-day disqualification. Source: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.5.","handbook":"","hbref":""},{"q":"A Vermont CMV driver commits a THIRD railroad-highway grade crossing violation within a three-year period. The minimum disqualification is:","options":["1 year","120 days","60 days","6 months"],"answer":0,"explanation":"A third railroad-highway grade crossing violation within three years carries at least a one-year disqualification (60 days first, 120 days second, one year third). Source: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.5.","handbook":"","hbref":""},{"q":"Which action is a railroad-highway grade crossing violation that can disqualify a Vermont CDL holder?","options":["Lacking enough space to drive completely through the crossing without stopping","Sounding the horn before crossing the tracks","Crossing at a speed under 10 mph","Stopping more than 50 feet before the tracks"],"answer":0,"explanation":"Failing to have sufficient space to clear the crossing without stopping is one of the six grade-crossing offenses. Source: Vermont CDL Manual § 1.2.5; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"In Vermont, what is the minimum CMV disqualification for a FIRST conviction of violating an out-of-service order (not involving hazmat or passengers)?","options":["180 days","90 days","30 days","1 year"],"answer":0,"explanation":"A first out-of-service order violation disqualifies the driver for no less than 180 days (up to one year). Source: 23 V.S.A. § 4116; 49 CFR 383.51 Table 4 as adopted by Vermont.","handbook":"","hbref":""},{"q":"A Vermont CDL holder is convicted of a SECOND out-of-service order violation within a 10-year period. The disqualification period is:","options":["2 years","1 year","180 days","5 years"],"answer":0,"explanation":"A second out-of-service order violation in 10 years (separate incidents) carries a two-year disqualification. Source: 23 V.S.A. § 4116; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"What is the Vermont CMV disqualification period for a THIRD or subsequent out-of-service order violation within a 10-year period?","options":["3 years","2 years","1 year","Lifetime"],"answer":0,"explanation":"A third or subsequent out-of-service order violation in 10 years results in a three-year disqualification. Source: 23 V.S.A. § 4116; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"Under Vermont's CDL law, using a hand-held mobile telephone while driving a CMV is best described as:","options":["A prohibited act that counts as a serious traffic violation","Allowed if the call is under one minute","Allowed only on interstate highways","A non-moving violation with no CDL impact"],"answer":0,"explanation":"Vermont prohibits texting and hand-held phone use while driving a CMV; such convictions count as serious traffic violations toward disqualification. Source: 23 V.S.A. § 4125; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"When is texting or hand-held phone use permitted while operating a CMV in Vermont?","options":["When necessary to contact law enforcement or emergency services","When stopped at a red traffic light","When traveling under 25 mph","When the load is non-hazardous"],"answer":0,"explanation":"The only exception to the texting/hand-held phone ban is communication with law enforcement officials or other emergency services. Source: 23 V.S.A. § 4125.","handbook":"","hbref":""},{"q":"A Vermont CDL holder disqualified for LIFE for two major offenses may apply to have commercial driving privileges restored only after being disqualified for at least how long, and after completing any required rehabilitation?","options":["10 years","5 years","7 years","15 years"],"answer":0,"explanation":"A lifetime CDL disqualification may be reduced after at least 10 years if the driver completes an approved rehabilitation program and meets the affidavit requirements. Source: Code of Vermont Rules 14-050-044 (Reduction of Life Disqualification); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Vermont's Move Over law, when a law enforcement or emergency vehicle approaches with its siren sounding or signal lamps displayed, what must the operator of every other vehicle do?","options":["Continue normally as long as the emergency vehicle is in a different lane","Pull to the right of the lane of traffic and come to a complete stop until it has passed","Move only one lane to the left and maintain speed","Slow to 20 mph below the posted limit and continue in the same lane"],"answer":1,"explanation":"23 V.S.A. § 1050(a) requires that on the approach of a law enforcement, ambulance, fire, or rescue vehicle sounding a siren or displaying its signal lamp, all other vehicles 'shall pull to the right of the lane of traffic and come to a complete stop until the law enforcement or emergency vehicle has passed.' Source: 23 V.S.A. § 1050(a).","handbook":"","hbref":""},{"q":"On a multilane Vermont highway, what does the Move Over law require of a driver approaching a STATIONARY emergency or towing vehicle that is displaying its warning lamps?","options":["Reduce speed to exactly 25 mph regardless of conditions","Stop only if the stationary vehicle is a police cruiser, not a tow truck","Always come to a complete stop in the travel lane until signaled to proceed","Make a lane change into a lane farther away if safety conditions permit; otherwise slow to a reasonable, safe, and prudent speed"],"answer":3,"explanation":"23 V.S.A. § 1050(b) says a driver approaching a stationary emergency vehicle (or a towing/repair vehicle displaying an amber lamp) shall proceed with caution and, if on a multilane highway and safety permits, change into a lane farther from the stationary vehicle; if a lane change is not possible, the driver shall slow to a 'reasonable, safe, and prudent speed.' Source: 23 V.S.A. § 1050(b).","handbook":"","hbref":""},{"q":"Vermont's stationary Move Over rule applies to a stopped towing and repair vehicle when it is displaying what color signal lamp?","options":["Blue","Red and white","Green","Amber"],"answer":3,"explanation":"23 V.S.A. § 1050(b) extends the move-over/slow-down duty to a 'stationary towing and repair vehicle displaying an amber signal lamp,' in addition to police (blue) and ambulance/fire/rescue (red) vehicles. Source: 23 V.S.A. § 1050(b).","handbook":"","hbref":""},{"q":"On a stopped Vermont school bus marked and equipped as required, when must approaching and overtaking traffic stop?","options":["Only if the bus's amber lights are flashing","Only when children are visibly standing in the roadway","Immediately, and remain stopped while the flashing red signal lights are in operation","Within 25 feet of the bus, then proceed slowly past it"],"answer":2,"explanation":"23 V.S.A. § 1075 requires a driver, on meeting or overtaking a properly marked school bus stopped to load or discharge schoolchildren, to 'stop his or her vehicle immediately' and keep it stationary 'while the flashing red signal lights are in operation.' Source: 23 V.S.A. § 1075.","handbook":"","hbref":""},{"q":"Under Vermont law, the only situation in which a driver need NOT stop for a school bus loading children on the opposite side is when the bus is on:","options":["Any four-lane road, divider or not","Any road where the driver is going at least 10 mph below the limit","Any road with a painted double-yellow center line","A highway with separate roadways, with the bus on a different roadway"],"answer":3,"explanation":"23 V.S.A. § 1075 excuses stopping only 'upon a highway with separate roadways' when meeting or overtaking a bus on a different roadway (or at a controlled-access loading zone where pedestrians may not cross). The roadways must be physically separated; a painted line does not qualify. Source: 23 V.S.A. § 1075.","handbook":"","hbref":""},{"q":"In Vermont, when a placarded hazardous-materials vehicle or a bus must stop at a railroad-highway crossing, where must it stop relative to the nearest rail?","options":["Exactly 10 feet from the nearest rail","Anywhere within 75 feet of the nearest rail","Within 50 feet but not less than 15 feet of the nearest rail","Within 100 feet but not less than 25 feet of the nearest rail"],"answer":2,"explanation":"Following the federal CDL/FMCSA standard applied in Vermont (49 CFR 392.10), a driver of a placarded hazmat vehicle or a bus required to stop must do so within 50 feet but not less than 15 feet of the nearest rail. Source: Vermont CDL Manual (Railroad-Highway Crossings); 49 CFR 392.10.","handbook":"","hbref":""},{"q":"While a Vermont commercial vehicle is crossing railroad tracks, what does the CDL manual instruct the driver NOT to do?","options":["Keep both hands on the wheel","Cross in a low enough gear to avoid stalling","Look and listen in both directions before entering","Shift gears while any part of the vehicle is on the tracks"],"answer":3,"explanation":"The Vermont CDL Manual instructs drivers never to shift gears while crossing the tracks, because shifting risks stalling on the crossing. The driver should select a gear before reaching the tracks and not change it until clear. Source: Vermont CDL Manual (Railroad-Highway Crossings).","handbook":"","hbref":""},{"q":"Before a Vermont CMV driver starts across a railroad crossing, the manual says the driver must be sure there is enough room on the far side so that the vehicle:","options":["Has at least one axle remaining between the rails","Can pause on the tracks to check for oncoming trains","Can stop with its front bumper on the second rail","Can completely clear the tracks without stopping on them"],"answer":3,"explanation":"The Vermont CDL Manual warns that a driver must never start across tracks without being sure the vehicle can get completely across without stopping. A driver must have room on the far side to clear the crossing entirely. Source: Vermont CDL Manual (Railroad-Highway Crossings).","handbook":"","hbref":""},{"q":"A Vermont CMV is stopped on a level, straight two-lane road. Where are the three warning devices (reflective triangles) placed?","options":["About 25 feet, 75 feet, and 150 feet to the rear","About 50 feet, 150 feet, and 300 feet to the rear","About 10 feet, 100 feet, and 200 feet to the rear toward approaching traffic","About 10 feet, 50 feet, and 100 feet to the rear"],"answer":2,"explanation":"Following the FMCSA/CDL standard used in Vermont, on a two-lane road triangles are placed about 10 feet directly behind the vehicle, about 100 feet to the rear, and about 200 feet to the rear in the direction of approaching traffic. Source: Vermont CDL Manual (Stopping on the Road); 49 CFR 392.22.","handbook":"","hbref":""},{"q":"If a Vermont CMV is stopped within 500 feet of a hill, curve, or other obstruction to the view, how should the warning devices be adjusted?","options":["Place a device toward the obstruction 100 to 500 feet from the vehicle to give ample warning","No triangles are required because the hazard is visible","Place all three devices directly behind the vehicle within 10 feet","Place a device exactly 700 feet beyond the obstruction"],"answer":0,"explanation":"The Vermont CDL Manual (per 49 CFR 392.22) directs that if a stop is within 500 feet of a curve, hill crest, or other view obstruction, the driver moves the rear-most warning device toward the obstruction so it stands 100 to 500 feet from the vehicle. Source: Vermont CDL Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"What is the maximum lawful speed limit for any motor vehicle on a Vermont limited-access (interstate) highway, unless otherwise posted?","options":["55 mph","65 mph","60 mph","70 mph"],"answer":1,"explanation":"Vermont's limited-access highway regulation sets the maximum at 65 mph: 'The maximum speed limit at which any motor vehicle may be operated on limited access highways shall be sixty-five (65) miles per hour,' unless otherwise posted. Source: Code Vt. R. 14-053-004 (limited-access facilities); 23 V.S.A. § 1081.","handbook":"","hbref":""},{"q":"Absent a posted limit or a limited-access designation, what is Vermont's default statutory maximum speed on a highway?","options":["65 mph","50 mph","45 mph","55 mph"],"answer":1,"explanation":"23 V.S.A. § 1081 establishes a default maximum of 50 mph on highways unless a different limit is posted or set under the statute. Higher limits (up to 65 mph) apply only on limited-access highways by authority of the Traffic Committee. Source: 23 V.S.A. § 1081.","handbook":"","hbref":""},{"q":"Does Vermont set a separate, lower maximum speed limit for trucks and commercial vehicles than for cars on its highways?","options":["No — the posted limit applies to all vehicles; there is no separate truck speed limit","Yes — trucks are limited to 60 mph on interstates","Yes — trucks are limited to 55 mph everywhere","Yes — trucks must stay 10 mph below the posted car limit"],"answer":0,"explanation":"Vermont does not impose a separate, lower truck speed limit. The same maximum (e.g., 65 mph on limited-access highways, 50 mph default) applies to all motor vehicles, including trucks and buses. Source: 23 V.S.A. § 1081; Code Vt. R. 14-053-004.","handbook":"","hbref":""},{"q":"On a Vermont limited-access highway, a truck or bus may travel below the posted minimum speed because of grade only if it:","options":["Displays its four-way flashing signals while doing so","Moves entirely onto the left shoulder","Sounds its horn continuously","First obtains an oversize travel permit"],"answer":0,"explanation":"Vermont's limited-access regulation excuses motor trucks and buses from the minimum-speed rule when the grade makes that speed impracticable, but only if the vehicle displays four-way flashing signals during that time. Source: Code Vt. R. 14-053-004 (limited-access facilities).","handbook":"","hbref":""},{"q":"Vermont Route 108 through Smugglers' Notch is closed to which vehicles?","options":["Any vehicle wider than 8 feet 6 inches","Single-frame vehicles over 40 feet and tractor-trailer combinations over 45 feet in total length","All vehicles over 26,000 pounds GVWR","Buses carrying more than 15 passengers"],"answer":1,"explanation":"23 V.S.A. § 1006b prohibits single-frame motor vehicles over 40 feet in length, and tractor units with one or more trailers exceeding 45 feet total, from the Smugglers' Notch segment of Vermont Route 108. The narrow mountain pass cannot accommodate them. Source: 23 V.S.A. § 1006b; Vermont Agency of Transportation (vtrans.vermont.gov/notch).","handbook":"","hbref":""},{"q":"A trucker who ignores GPS and gets a tractor-trailer stuck in Smugglers' Notch on Vermont Route 108 faces a civil penalty that, for substantially blocking traffic, is scheduled to rise on July 1, 2026 to:","options":["$2,000","$50,000","$20,000","$5,000"],"answer":2,"explanation":"Under 23 V.S.A. § 1006b the base fine was $1,000, or $2,000 if the violation substantially impedes traffic; legislation raises these to $10,000 and $20,000 (traffic-blocking) effective July 1, 2026. Source: 23 V.S.A. § 1006b; Vermont Agency of Transportation.","handbook":"","hbref":""},{"q":"Without an oversize permit, what is the maximum legal vehicle width on Vermont highways?","options":["8 feet 0 inches","8 feet 6 inches","10 feet 0 inches","9 feet 0 inches"],"answer":1,"explanation":"Vermont's legal maximum vehicle width without a permit is 8 feet 6 inches (102 inches); legal height is 13 feet 6 inches and legal gross weight is 80,000 pounds. Exceeding these requires a DMV Commercial Vehicle Operations oversize/overweight permit. Source: Vermont DMV CVO Oversize/Overweight Permit Rules (CVO-110).","handbook":"","hbref":""},{"q":"Vermont oversize/overweight permits generally authorize movement only during what hours?","options":["From one-half hour before sunrise to one-half hour after sunset","Only between midnight and 6:00 a.m.","24 hours a day with no restriction","Only on weekends and legal holidays"],"answer":0,"explanation":"Vermont's permit rules limit oversize/overweight travel to daylight hours: from one-half hour before sunrise to one-half hour after sunset, with added restrictions on the largest loads during weekends and holidays. Source: Vermont DMV CVO Oversize/Overweight Permit Rules (CVO-110).","handbook":"","hbref":""},{"q":"On a Vermont roadway, where must a truck moving slower than the normal speed of traffic be driven?","options":["In the right-hand lane available, or as close as practicable to the right edge, except when passing or preparing to turn left","In the left lane so faster traffic can merge right","On the paved shoulder until traffic clears","In the center lane of any multilane road at all times"],"answer":0,"explanation":"Vermont's keep-right rule requires a vehicle traveling below the normal speed of traffic to be driven in the right-hand lane, or as close as practicable to the right curb or edge, except when overtaking and passing or preparing for a left turn. Source: 23 V.S.A. § 1038 / § 1031.","handbook":"","hbref":""},{"q":"Under Vermont law, who may require tire chains on specified state highways during winter weather, and for which vehicles?","options":["Chains are required only on town roads, never state highways","Only the federal government can mandate chains, and only on interstates","State officials may require chains for vehicles over 26,000 pounds GVWR or GCWR on designated highway portions","Chains are mandatory for every passenger car from December through March"],"answer":2,"explanation":"23 V.S.A. § 1006c authorizes the Secretary of Transportation, Commissioner of Motor Vehicles, or Commissioner of Public Safety (or designees) to require tire chains on specified portions of state highways during winter weather for vehicles over 26,000 pounds GVWR or GCWR, with advance signage. Source: 23 V.S.A. § 1006c.","handbook":"","hbref":""},{"q":"In Vermont, which agency issues Commercial Driver Licenses (CDLs) and administers the required tests?","options":["The Vermont Department of Motor Vehicles (DMV)","The Vermont Agency of Transportation (VTrans)","The Federal Motor Carrier Safety Administration (FMCSA)","The Vermont State Police Commercial Vehicle Unit"],"answer":0,"explanation":"The Vermont Department of Motor Vehicles (DMV) issues CDLs and administers the knowledge and skills tests in the state. FMCSA sets the federal CDL standards but does not issue the license. Source: Vermont DMV, Commercial Driver's License (CDL) page; Vermont CDL Driver Manual (VN-111).","handbook":"","hbref":""},{"q":"Before a person can take the CDL skills test in Vermont, what permit must they first obtain and hold?","options":["A Commercial Learner's Permit (CLP)","A regular Vermont learner's permit only","A temporary interstate operating permit","An oversize/overweight load permit"],"answer":0,"explanation":"Vermont requires applicants to obtain a Commercial Learner's Permit (CLP), which authorizes supervised practice in a commercial motor vehicle before the skills test. Source: Vermont DMV, Commercial Driver's Learner Permit (CLP) page; Vermont CDL Driver Manual (VN-111).","handbook":"","hbref":""},{"q":"After receiving a Commercial Learner's Permit in Vermont, what is the minimum number of days a driver must hold it before taking the CDL skills test?","options":["14 days","7 days","30 days","60 days"],"answer":0,"explanation":"A CLP holder must wait a minimum of 14 days after the CLP is issued before taking the skills test for the CDL. Source: Vermont DMV, Commercial Driver's Learner Permit (CLP) and Renewals/Transfers/Upgrades pages; federal 49 CFR 383.25.","handbook":"","hbref":""},{"q":"The Vermont CDL skills test is made up of which three parts?","options":["Pre-trip inspection, basic vehicle control, and on-road driving","Written knowledge test, eye exam, and on-road driving","Air brake check, hazmat handling, and night driving","Pre-trip inspection, parallel parking, and a highway-speed test"],"answer":0,"explanation":"Vermont's CDL skills test has three parts, all of which must be passed: the pre-trip vehicle inspection, basic vehicle control maneuvers, and the on-road driving test. Source: Vermont DMV CDL pages; Vermont CDL Driver Manual (VN-111).","handbook":"","hbref":""},{"q":"Which form does a driver submit to self-certify their type of driving and medical status with the Vermont DMV?","options":["The CDL Medical Certification form (VL-033)","The federal Medical Examiner's Certificate alone","A notarized affidavit of fitness","The TSA hazardous materials background form"],"answer":0,"explanation":"Vermont CDL holders and applicants self-certify their driving type and medical status by completing and submitting the CDL Medical Certification form, VL-033, to the DMV. Source: Vermont DMV, CDL Medical Requirements page and Form VL-033.","handbook":"","hbref":""},{"q":"When self-certifying with the Vermont DMV, how many driving categories may a CDL applicant choose from?","options":["Four","Two","Three","Five"],"answer":0,"explanation":"There are four self-certification categories: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), and Excepted Intrastate (EA). The driver selects one on Form VL-033. Source: Vermont DMV CDL Medical Certification (Form VL-033); 49 CFR 383.71.","handbook":"","hbref":""},{"q":"A Vermont CDL applicant who drives in interstate commerce and is subject to the federal physical qualification rules (49 CFR Part 391) should self-certify as which category?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"answer":0,"explanation":"A driver who operates in interstate commerce and is subject to 49 CFR Part 391 self-certifies as Non-Excepted Interstate (NI) and must provide a current Medical Examiner's Certificate. Source: Vermont DMV Form VL-033; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Which self-certification category in Vermont requires the driver to provide a current 'Vermont Only' Medical Examiner's Certificate?","options":["Non-Excepted Intrastate (NA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)"],"answer":0,"explanation":"A Non-Excepted Intrastate (NA) driver operates only within Vermont and must meet medical standards by providing a current 'Vermont Only' Medical Examiner's Certificate. Source: Vermont DMV CDL Medical Certification (Form VL-033).","handbook":"","hbref":""},{"q":"Who is authorized to perform the DOT physical exam that produces a CDL Medical Examiner's Certificate accepted in Vermont?","options":["A medical examiner listed on the FMCSA National Registry of Certified Medical Examiners","Any licensed physician chosen by the driver","A Vermont DMV examiner at the testing site","The driver's employer's safety officer"],"answer":0,"explanation":"The physical must be performed by a medical examiner listed on the FMCSA National Registry of Certified Medical Examiners. Source: Vermont DMV, CDL Medical Requirements page; 49 CFR 390.103 / Part 391.","handbook":"","hbref":""},{"q":"What is the maximum period a standard DOT Medical Examiner's Certificate can be valid for a Vermont CDL holder?","options":["Up to 2 years","Up to 1 year","Up to 3 years","Up to 5 years"],"answer":0,"explanation":"A standard Medical Examiner's Certificate is valid for up to 2 years, though an examiner may issue one for a shorter period if a condition needs monitoring. Source: Vermont DMV, CDL Medical Requirements page; 49 CFR Part 391.","handbook":"","hbref":""},{"q":"What can happen to a Vermont CDL if the holder fails to keep a current medical certificate on file with the DMV?","options":["The CDL may be downgraded or the driving privilege suspended","Nothing, as long as the license itself has not expired","The driver is automatically issued an Excepted Interstate status","Only a written warning is mailed with no license effect"],"answer":0,"explanation":"If current medical documentation is not maintained on file, the Vermont DMV may downgrade the CDL (remove commercial privileges) and/or suspend the driving privilege. Source: Vermont DMV, CDL Medical Requirements page; 49 CFR 383.73.","handbook":"","hbref":""},{"q":"Which training must a first-time Class A or Class B CDL applicant complete before being allowed to take the Vermont skills test?","options":["Entry-Level Driver Training (ELDT) from an FMCSA-registered provider","A defensive driving course approved by the Vermont DMV","An eight-hour classroom course taught by the DMV","An apprenticeship logged with the employer only"],"answer":0,"explanation":"First-time Class A/B applicants (and certain endorsements) must complete Entry-Level Driver Training (ELDT) from a provider on the FMCSA Training Provider Registry before taking the CDL skills test. Source: Vermont DMV CDL pages; 49 CFR Part 380 Subpart F.","handbook":"","hbref":""},{"q":"For a first-time HazMat (H) endorsement, when must the required Entry-Level Driver Training be completed?","options":["Before taking the HazMat knowledge test","Before the on-road skills test only","Within 30 days after the license is issued","Only after the TSA background check is approved"],"answer":0,"explanation":"Because the HazMat endorsement has no skills test, ELDT for a first-time H endorsement must be completed before the applicant takes the HazMat knowledge test. Source: Vermont DMV CDL pages; 49 CFR Part 380 Subpart F.","handbook":"","hbref":""},{"q":"Which knowledge test must every Vermont CDL applicant pass regardless of class or endorsement?","options":["The General Knowledge test","The Air Brakes test","The Combination Vehicles test","The Hazardous Materials test"],"answer":0,"explanation":"Every CDL applicant must pass the General Knowledge written test; additional tests such as Air Brakes, Combination Vehicles, and endorsement tests apply only as relevant to the vehicle or endorsement. Source: Vermont CDL Driver Manual (VN-111); Vermont DMV CDL pages.","handbook":"","hbref":""},{"q":"What minimum score is required to pass a Vermont CDL knowledge (written) test?","options":["80 percent","70 percent","75 percent","90 percent"],"answer":0,"explanation":"Vermont CDL knowledge tests require a passing score of at least 80 percent of the questions answered correctly. Source: Vermont CDL Driver Manual (VN-111); Vermont DMV CDL testing information.","handbook":"","hbref":""},{"q":"A Vermont CDL must be renewed using which method?","options":["In person at a Vermont DMV office","Online only through the DMV website","By mail using the renewal notice only","Automatically, with no action by the driver"],"answer":0,"explanation":"A CDL must be renewed in person at a Vermont DMV customer service office; the driver brings the signed renewal notice and fee. Source: Vermont DMV, Renewals, Transfers & Upgrades page.","handbook":"","hbref":""},{"q":"For how many years may a Vermont CDL be renewed at a time?","options":["Two or four years","One or two years","Five years","Eight years"],"answer":0,"explanation":"Vermont CDL renewals are issued on a two-year or four-year cycle, with any remaining full years on the current credential credited toward the renewal fee. Source: Vermont DMV, Renewals, Transfers & Upgrades page.","handbook":"","hbref":""},{"q":"A person holding a valid CDL from another state who moves to Vermont must transfer it to a Vermont CDL within how long after establishing residency?","options":["30 days","10 days","60 days","90 days"],"answer":0,"explanation":"Under state and federal law, a person holding an out-of-state CDL must transfer it to a Vermont CDL within 30 days of establishing Vermont residency. Source: Vermont DMV, Renewals, Transfers & Upgrades page; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"When upgrading an existing Vermont CDL to a higher class, what must the driver do regarding a permit?","options":["Obtain a Commercial Learner's Permit and hold it for at least 14 days","Nothing; the existing CDL is sufficient to test for the upgrade","Obtain only a regular operator's learner permit","Hold the new permit for a minimum of 90 days"],"answer":0,"explanation":"To upgrade to a higher CDL class, the driver must obtain a Commercial Learner's Permit, hold it at least 14 days, and pass the appropriate knowledge and skills tests. Source: Vermont DMV, Renewals, Transfers & Upgrades page.","handbook":"","hbref":""},{"q":"Why does the Vermont DMV advise CDL applicants to treat published license and testing fees as subject to change?","options":["Fee amounts are set by statute and DMV schedules that can be revised, so the current posted fee should always be confirmed","Vermont charges no fees for CDL services, so any posted amount is an error","Fees are negotiated individually at the counter for each applicant","Only the federal government, not Vermont, may set or change CDL fees"],"answer":0,"explanation":"CDL and testing fees are established by Vermont statute and DMV fee schedules that may be updated, so applicants should confirm the current amount with the DMV rather than rely on a fixed figure. Source: Vermont DMV fee information; 23 V.S.A. (motor vehicle fee statutes).","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная допустимая ширина транспортного средства на дорогах штата Вермонт, превышение которой требует разрешения на негабарит по ширине?","options":["8 футов (96 дюймов)","8 футов 6 дюймов (102 дюйма)","9 футов (108 дюймов)","8 футов 4 дюйма (100 дюймов)"],"explanation":"Согласно 23 V.S.A. § 1431, максимальная ширина транспортного средства в Вермонте составляет 8 футов 6 дюймов (102 дюйма), не считая устройств безопасности, таких как зеркала, выступающие до 3 дюймов с каждой стороны. Всё, что шире, требует разрешения на негабарит от Vermont DMV. Источник: 23 V.S.A. § 1431."},"1":{"q":"Какова максимальная допустимая высота транспортного средства на дорогах штата Вермонт без разрешения?","options":["13 футов","14 футов","13 футов 6 дюймов","12 футов 6 дюймов"],"explanation":"23 V.S.A. § 1431 устанавливает максимальную высоту транспортного средства в 13 футов 6 дюймов. Грузы, превышающие эту высоту, требуют разрешения на негабарит от Vermont DMV. Источник: 23 V.S.A. § 1431."},"2":{"q":"Какова в Вермонте максимальная общая длина одиночного автотранспортного средства (без прицепа или полуприцепа) без специального разрешения?","options":["40 футов","53 фута","46 футов","48 футов"],"explanation":"Согласно 23 V.S.A. § 1432, ни одно автотранспортное средство без прицепа или полуприцепа, общая длина которого превышает 46 футов, не может эксплуатироваться на дороге Вермонта, кроме как по специальному разрешению. Источник: 23 V.S.A. § 1432."},"3":{"q":"Какова максимальная общая длина состава транспортных средств (грузовик с прицепом или полуприцепом) на обычной дороге Вермонта без разрешения на негабарит по длине?","options":["65 футов","75 футов","70 футов","80 футов"],"explanation":"Согласно 23 V.S.A. § 1432, составы транспортных средств общей длиной не более 75 футов могут эксплуатироваться на дорогах Вермонта без разрешения; более длинные составы требуют разрешения на негабарит по длине. Источник: 23 V.S.A. § 1432."},"4":{"q":"На межштатных автомагистралях Вермонта и обозначенных дорогах Национальной сети какова максимальная допустимая длина полуприцепа в составе тягача с полуприцепом?","options":["48 футов","53 фута","45 футов","57 футов"],"explanation":"На системе межштатных автомагистралей и подходящих обозначенных дорогах Вермонт применяет федеральные ограничения по длине компонентов вместо ограничения по общей длине: полуприцеп в составе тягача с полуприцепом может иметь длину до 53 футов. Источник: 23 V.S.A. § 1432."},"5":{"q":"Для состава «тягач — полуприцеп — прицеп» (сдвоенный прицеп) на обозначенной дорожной сети Вермонта какова максимальная длина каждого прицепа или полуприцепа?","options":["по 28 футов каждый","по 30 футов каждый","по 27 футов каждый","по 33 фута каждый"],"explanation":"На межштатных автомагистралях и обозначенной сети сдвоенные составы регулируются федеральными ограничениями по компонентам: каждый прицеп или полуприцеп может иметь длину до 28 футов. Источник: 23 V.S.A. § 1432 (в соответствии с федеральными стандартами STAA)."},"6":{"q":"Каков максимальный полный вес транспортного средства на дорогах Вермонта для стандартного коммерческого транспортного средства без специального разрешения?","options":["73,280 pounds","80,000 pounds","90,000 pounds","84,000 pounds"],"explanation":"Согласно 23 V.S.A. § 1392, максимальный полный вес транспортного средства составляет 80,000 pounds. Более тяжёлые грузы требуют разрешения на перегруз от DMV или законодательно установленной категории специального разрешения. Источник: 23 V.S.A. § 1392."},"7":{"q":"На федеральной системе межштатных автомагистралей в Вермонте какова максимальная нагрузка на одиночную ось, без допускаемых отклонений?","options":["22,400 pounds","18,000 pounds","20,000 pounds","21,000 pounds"],"explanation":"Согласно 23 V.S.A. § 1391, на межштатных автомагистралях (Eisenhower National System of Interstate and Defense Highways) предел нагрузки на одиночную ось составляет 20,000 pounds без каких-либо допускаемых отклонений, что соответствует федеральному законодательству. Источник: 23 V.S.A. § 1391."},"8":{"q":"На системе межштатных автомагистралей в Вермонте какова максимальная нагрузка на сдвоенную ось, без допускаемых отклонений?","options":["36,000 pounds","34,000 pounds","32,000 pounds","38,000 pounds"],"explanation":"Согласно 23 V.S.A. § 1391, на системе межштатных автомагистралей предел нагрузки на сдвоенную ось составляет 34,000 pounds без каких-либо допускаемых отклонений, что соответствует федеральным стандартам веса. Источник: 23 V.S.A. § 1391."},"9":{"q":"На дорогах Вермонта, не относящихся к межштатным (дороги штата и городов), какова максимальная нагрузка на одиночную ось до применения 10-процентного допуска?","options":["20,000 pounds","24,000 pounds","22,400 pounds","21,500 pounds"],"explanation":"Согласно 23 V.S.A. § 1391, на дорогах Вермонта, не относящихся к межштатным, предел нагрузки на одиночную ось составляет 22,400 pounds, с допускаемым 10-процентным отклонением. Источник: 23 V.S.A. § 1391."},"10":{"q":"На дорогах Вермонта, не относящихся к межштатным, какова максимальная нагрузка на сдвоенную ось до применения 10-процентного допуска?","options":["34,000 pounds","36,000 pounds","32,000 pounds","40,000 pounds"],"explanation":"Согласно 23 V.S.A. § 1391, на дорогах Вермонта, не относящихся к межштатным, предел нагрузки на сдвоенную ось составляет 36,000 pounds, с допускаемым 10-процентным отклонением (ключевое специфичное для штата отличие от предела 34,000 pounds на межштатных дорогах). Источник: 23 V.S.A. § 1391."},"11":{"q":"Ключевым различием между правилами Вермонта по нагрузке на ось для немежштатных и межштатных дорог является допуск. Какой допуск применяется к пределам нагрузки на одиночную и сдвоенную ось на немежштатных дорогах Вермонта?","options":["Допуск не разрешён","Разрешён 5-процентный допуск","Разрешён 10-процентный допуск","Разрешён 15-процентный допуск"],"explanation":"Согласно 23 V.S.A. § 1391, немежштатные пределы для одиночной оси (22,400 lb) и сдвоенной оси (36,000 lb) допускают 10-процентное отклонение, тогда как межштатные пределы (20,000 lb / 34,000 lb) не допускают никакого отклонения. Источник: 23 V.S.A. § 1391."},"12":{"q":"Какую формулу использует Вермонт, в соответствии с федеральным законодательством, для определения максимально допустимого полного веса для группы осей с учётом их расположения и количества?","options":["Федеральную мостовую формулу (Формулу B)","Формулу полной массы автопоезда (GCWR)","Индекс расстояния между сдвоенными осями","Формулу эквивалентности осевой нагрузки"],"explanation":"Вермонт применяет Федеральную мостовую формулу (Bridge Formula B), W = 500[LN/(N-1) + 12N + 36], для ограничения веса, приходящегося на любую группу осей, исходя из расстояния (L) и количества осей (N), в дополнение к пределам для одиночной, сдвоенной осей и полному весу в 80,000 lb. Источник: федеральная мостовая формула в применении согласно 23 V.S.A. ch. 13 / FHWA."},"13":{"q":"В Федеральной мостовой формуле, используемой в Вермонте, две последовательные оси считаются «сдвоенными» (а не отдельными одиночными осями), когда их центры расположены на каком расстоянии друг от друга?","options":["Более 40 дюймов, но не более 96 дюймов","Более 96 дюймов, но не более 120 дюймов","Не более 40 дюймов","Более 48 дюймов, но не более 108 дюймов"],"explanation":"Согласно федеральным определениям, применяемым в Вермонте, сдвоенная ось — это две или более последовательных осей, центры которых расположены более чем в 40 дюймах, но не более чем в 96 дюймах друг от друга; оси на расстоянии 40 дюймов или менее считаются одиночной осью. Источник: определения Федеральной мостовой формулы / FHWA, применяемые согласно 23 V.S.A. ch. 13."},"14":{"q":"Когда оператору коммерческого транспортного средства в Вермонте, как правило, требуется разрешение на негабарит или перегруз от DMV?","options":["Только при выезде в другой штат","Когда транспортное средство или груз превышает установленные законом пределы по ширине, высоте, длине или весу","Только когда полный вес превышает 100,000 pounds","Только ночью или в зимних условиях"],"explanation":"Разрешение Vermont DMV на негабарит/перегруз требуется всякий раз, когда транспортное средство или груз превышает установленные законом пределы (ширина более 8'6\", высота более 13'6\", одиночное транспортное средство более 46 ft, состав более 75 ft или применимые пределы по весу). Источник: 23 V.S.A. ch. 13 и Vermont DMV Overweight/Overdimension Permit Rules (Code Vt. R. 14-050-019)."},"15":{"q":"Какое ведомство Вермонта выдаёт разрешения на негабарит и перегруз для движения по дорогам штата и системе межштатных автомагистралей?","options":["Vermont Agency of Natural Resources","Federal Motor Carrier Safety Administration","Vermont Department of Motor Vehicles (Commercial Vehicle Operations)","Управление шерифа округа"],"explanation":"Vermont DMV, через своё подразделение Commercial Vehicle Operations (и онлайн-систему VT Haul Pass), выдаёт разрешения на негабарит и перегруз для дорог штата и системы межштатных автомагистралей в рамках полномочий Уполномоченного. Источник: Vermont DMV CVO Overweight/Overdimension Permit Rules; 23 V.S.A. § 1400."},"16":{"q":"Транспортной компании необходимо в течение года неоднократно перевозить негабаритные неделимые грузы по одним и тем же маршрутам. Какой тип разрешения Вермонта лучше всего подходит для этой потребности?","options":["Разрешение на одну поездку","Аварийное разрешение","Общее (годовое) разрешение","Разрешение только на регистрацию"],"explanation":"Vermont DMV выдаёт общие (годовые) разрешения для повторяющихся перевозок неделимых грузов, тогда как разрешения на одну поездку охватывают одну перевозку в ограниченные сроки (около семи рабочих дней). Источник: Vermont DMV Overweight/Overdimension Permit Rules (Code Vt. R. 14-050-019)."},"17":{"q":"Для веса, превышающего установленные законом пределы на дорогах и мостах, находящихся в юрисдикции муниципалитета (кроме городских дорог Class 1), кому в Вермонте должна подаваться заявка на разрешение на перегруз?","options":["Уполномоченному Vermont DMV","Соответствующему законодательному органу муниципалитета (например, совету села)","Federal Highway Administration","Полиции штата Вермонт"],"explanation":"Согласно правилам выдачи разрешений Вермонта, для движения с превышением пределов по весу на дорогах и мостах, находящихся в юрисдикции муниципалитета (кроме городских дорог Class 1), заявка подаётся в соответствующий муниципальный законодательный орган. Источник: Code Vt. R. 14-050-019 (Overweight/Overdimension Vehicle Permits)."},"18":{"q":"Специальное разрешение Вермонта на превышение веса (Special Excess Weight Permit, годовое разрешение для делимых грузов) допускает какой максимальный вес на управляемой оси?","options":["10,000 pounds","12,000 pounds","14,000 pounds","20,000 pounds"],"explanation":"Согласно правилу Vermont Special Excess Weight Permit, пределы нагрузки на ось составляют 12,000 pounds на управляемой оси и 20,000 pounds на всех остальных осях. Источник: Vermont DMV Special Excess Weight Permit; Code Vt. R. 14-050-019."},"19":{"q":"Закон Вермонта допускает, что определённые грузовые составы с шестью или более осями, работающие по годовому специальному разрешению, могут достигать какого повышенного полного веса на немежштатных дорогах?","options":["85,000 pounds","108,000 pounds","99,000 pounds","95,000 pounds"],"explanation":"Согласно 23 V.S.A. § 1392, грузовики с шестью или более несущими нагрузку осями, работающие по специальному годовому разрешению, могут достигать полного веса 99,000 pounds на немежштатных дорогах; это специфичное для Вермонта допущение не распространяется на систему межштатных автомагистралей, если только это не разрешено федеральным законодательством. Источник: 23 V.S.A. § 1392."},"20":{"q":"В Вермонте CDL класса A требуется для управления каким из следующих?","options":["Любым составом транспортных средств с GCWR 26,001 lbs или более, где буксируемые единицы превышают 10,000 lbs GVWR","Любым одиночным транспортным средством с GVWR 26,001 lbs или более","Любым транспортным средством, рассчитанным на перевозку 16 или более пассажиров, включая водителя","Любым транспортным средством любого веса с табличками опасных грузов (placards)"],"explanation":"Вермонт следует федеральной классификации CDL (49 CFR 383.91): класс A — это любой состав транспортных средств с GCWR 26,001 lbs или более при условии, что буксируемые транспортные средства имеют GVWR более 10,000 lbs. Источник: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.91."},"21":{"q":"Согласно правилам Вермонта, CDL класса B охватывает какие транспортные средства?","options":["Только автобусы, перевозящие менее 16 пассажиров","Любое одиночное транспортное средство с GVWR 26,001 lbs или более, либо такое транспортное средство, буксирующее единицу не более 10,000 lbs","Любой состав, где прицеп превышает 10,000 lbs GVWR","Любое транспортное средство, требующее только подтверждения на опасные грузы"],"explanation":"Вермонт принимает федеральное определение: класс B — это любое одиночное транспортное средство с GVWR 26,001 lbs или более, либо такое транспортное средство, буксирующее другое транспортное средство не свыше 10,000 lbs GVWR. Источник: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.91."},"22":{"q":"CDL класса C в Вермонте требуется, когда транспортное средство не соответствует весовым определениям класса A или B, но рассчитано на перевозку как минимум скольких пассажиров (включая водителя), либо перевозит опасные грузы с табличками (placards)?","options":["10 пассажиров","12 пассажиров","16 пассажиров","24 пассажира"],"explanation":"Класс C в Вермонте применяется к транспортному средству (не соответствующему группе A или B), рассчитанному на перевозку 16 или более пассажиров, включая водителя, либо используемому для перевозки опасных грузов с табличками (placards). Источник: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.91."},"23":{"q":"Какое подтверждение (endorsement) требуется владельцу CDL в Вермонте, чтобы управлять транспортным средством, перевозящим опасные грузы в количествах, требующих табличек (placards)?","options":["Подтверждение N","Подтверждение H","Подтверждение T","Подтверждение X"],"explanation":"Подтверждение H (HazMat) даёт право на перевозку опасных грузов в количествах, требующих табличек (placards). (Код X означает совмещённые подтверждения Tank и HazMat.) Источник: Vermont DMV HazMat Endorsements page / Vermont CDL Manual (VN-111)."},"24":{"q":"Каков минимальный возраст для получения CDL в Вермонте с ограничением только на внутриштатные (в пределах Вермонта) перевозки?","options":["16 лет","17 лет","18 лет","21 год"],"explanation":"Вермонт требует, чтобы заявителю было не менее 18 лет для получения CDL и управления коммерческим автотранспортным средством во внутриштатных перевозках. Источник: Vermont DMV Commercial Driver's License page."},"25":{"q":"Каков минимальный возраст для управления коммерческим автотранспортным средством в межштатных перевозках с CDL Вермонта?","options":["18 лет","19 лет","20 лет","21 год"],"explanation":"Водителю должно быть не менее 21 года для управления коммерческим автотранспортным средством в межштатных перевозках, в соответствии с федеральным правилом. Источник: Vermont DMV Commercial Driver's License page / FMCSA 49 CFR 391.11."},"26":{"q":"Прежде чем назначить экзамен на навыки CDL, федеральный закон (применяемый в Вермонте) требует, чтобы заявитель владел коммерческим ученическим разрешением (CLP) минимум сколько дней?","options":["7 дней","14 дней","30 дней","60 дней"],"explanation":"Заявитель должен владеть CLP не менее 14 дней, прежде чем сдавать экзамен на навыки CDL. Источник: Vermont DMV CLP page / FMCSA 49 CFR 383.25."},"27":{"q":"Чтобы подать заявление на коммерческое ученическое разрешение (CLP) в Вермонте, заявитель должен уже владеть чем?","options":["Действующими водительскими правами Вермонта класса D (обычными)","Действующим подтверждением на управление мотоциклом","Федеральной картой TWIC","Юношескими водительскими правами"],"explanation":"Вермонт требует, чтобы заявители на CLP владели действующими водительскими правами Вермонта класса D. Источник: Vermont DMV Commercial Driver's Learner Permit page."},"28":{"q":"В течение какого срока действует коммерческое ученическое разрешение (CLP) Вермонта с даты выдачи?","options":["90 дней","6 месяцев","1 год","2 года"],"explanation":"CLP Вермонта действует один год (12 месяцев) с даты выдачи. Источник: Vermont DMV Commercial Driver's Learner Permit page / FMCSA 49 CFR 383.25."},"29":{"q":"При вождении по дорогам общего пользования владелец CLP Вермонта должен сопровождаться лицом, которое:","options":["Владеет любыми действующими водительскими правами Вермонта","Владеет действующим CDL для класса управляемого транспортного средства, включая необходимые подтверждения","Старше 25 лет","Является сертифицированным экзаменатором DMV"],"explanation":"Владелец CLP должен сопровождаться сидящим рядом лицом, владеющим действующим CDL для типа управляемого транспортного средства, с соответствующими подтверждениями. Источник: Vermont DMV CLP page / FMCSA 49 CFR 383.25."},"30":{"q":"Какое подтверждение требуется для управления цистерной, перевозящей жидкости или газы наливом в Вермонте?","options":["Подтверждение T","Подтверждение P","Подтверждение N","Подтверждение S"],"explanation":"Подтверждение N (Tank Vehicle) требуется для перевозки жидкостей/газов наливом в цистернах. Источник: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.93."},"31":{"q":"Цистерна, требующая подтверждения N, — это, как правило, та, что перевозит жидкость или газ в ёмкости с индивидуальной номинальной вместимостью более 119 галлонов и суммарной номинальной вместимостью не менее скольких галлонов?","options":["500 галлонов","1,000 галлонов","1,500 галлонов","3,000 галлонов"],"explanation":"Подтверждение N применяется к цистернам с индивидуальной номинальной вместимостью более 119 галлонов и суммарной номинальной вместимостью 1,000 галлонов или более жидкости или газа. Источник: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.5."},"32":{"q":"Какое подтверждение нужно водителю в Вермонте для управления сдвоенными или строенными прицепами?","options":["Подтверждение T","Подтверждение N","Подтверждение D","Подтверждение X"],"explanation":"Подтверждение T даёт право на управление сдвоенными и строенными прицепами и требует сдачи только теоретического экзамена. Источник: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.93."},"33":{"q":"Чтобы перевозить пассажиров (например, на городском или чартерном автобусе) в Вермонте, какое подтверждение требуется?","options":["Подтверждение S","Подтверждение P","Подтверждение N","Подтверждение H"],"explanation":"Подтверждение P (Passenger) требуется для управления транспортным средством, рассчитанным на перевозку пассажиров выше порога CDL; оно требует сдачи теоретического экзамена и экзамена на навыки на пассажирском транспортном средстве. Источник: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.93."},"34":{"q":"В Вермонте водитель, управляющий школьным автобусом, перевозящим учеников, должен владеть подтверждением P плюс каким дополнительным подтверждением?","options":["Подтверждением H","Подтверждением T","Подтверждением S","Подтверждением N"],"explanation":"Водителям школьных автобусов нужно подтверждение S (School Bus) в дополнение к подтверждению P. Подтверждение S требует сдачи теоретического экзамена и экзамена на навыки по эксплуатации школьного автобуса. Источник: Vermont DMV School Bus pages / FMCSA 49 CFR 383.93."},"35":{"q":"Каков минимальный возраст для получения подтверждения HazMat (H) на CDL Вермонта?","options":["18 лет","19 лет","21 год","25 лет"],"explanation":"Поскольку перевозка опасных грузов требует квалификации межштатного уровня и федерального допуска по безопасности, подтверждение HazMat требует, чтобы заявителю было не менее 21 года. Источник: Vermont DMV HazMat Endorsements page."},"36":{"q":"Прежде чем Вермонт сможет выдать или продлить подтверждение HazMat (H), заявитель должен пройти какую дополнительную проверку?","options":["Проверку благонадёжности Transportation Security Administration (TSA) со снятием отпечатков пальцев","Экзамен у государственного специалиста по зрению","Сертификацию дорожного теста от работодателя","Проверку службы в Национальной гвардии"],"explanation":"Согласно USA PATRIOT Act, подтверждение HazMat требует оценки угрозы безопасности от TSA, включая снятие отпечатков пальцев и проверку биографии, до выдачи или продления. Источник: Vermont DMV HazMat Endorsements page / 49 CFR 1572."},"37":{"q":"Согласно правилам ELDT, применяемым в Вермонте, где впервые подающий заявление кандидат на класс A должен пройти обязательное начальное обучение водителей?","options":["В любом муниципальном колледже, независимо от его наличия в реестре","У провайдера, внесённого в реестр провайдеров обучения FMCSA (TPR)","Только в учебном офисе Vermont DMV","В любой программе работодателя по выбору водителя"],"explanation":"С 7 февраля 2022 года ELDT (теория и обучение за рулём) должно быть пройдено у провайдера, внесённого в Training Provider Registry (TPR) FMCSA, до экзамена на навыки. Источник: FMCSA ELDT rule (49 CFR Part 380) / Vermont DMV CDL Training pages."},"38":{"q":"Для кого из перечисленных ELDT (Entry-Level Driver Training) НЕ требуется перед сдачей экзамена?","options":["Впервые подающих заявление кандидатов на CDL класса A или класса B","Водителей, впервые получающих подтверждение H (HazMat)","Водителей, повышающих категорию с класса B до класса A","Водителей, которые уже имели это подтверждение до 7 февраля 2022 года"],"explanation":"ELDT не имеет обратной силы: водители, получившие CDL или подтверждение S/P/H до 7 февраля 2022 года, не обязаны проходить ELDT. Оно применяется к впервые получающим класс A/B, повышению с B до A, а также к впервые получаемым подтверждениям S, P и H. Источник: FMCSA ELDT rule (49 CFR Part 380)."},"39":{"q":"Какой набор лучше всего описывает категории медицинской самосертификации, из которых должен выбирать кандидат на CDL в Вермонте?","options":["Коммерческая, Частная, Сельскохозяйственная и Рекреационная","Non-excepted interstate, Excepted interstate, Non-excepted intrastate и Excepted intrastate","Медицинская класса A, медицинская класса B, медицинская класса C и Освобождённая","Федеральная, штата, местная и племенная"],"explanation":"Кандидаты на CDL самостоятельно сертифицируют себя по одной из четырёх категорий: non-excepted interstate, excepted interstate, non-excepted intrastate или excepted intrastate. Водители категории non-excepted должны иметь действующий сертификат медицинского эксперта. Источник: Vermont DMV CDL medical self-certification / FMCSA 49 CFR 383.71."},"40":{"q":"При управлении коммерческим автотранспортным средством (CMV) в Вермонте какова максимальная допустимая концентрация алкоголя в крови (BAC), до достижения которой водитель не считается управляющим с запрещённым уровнем алкоголя?","options":["0.04 percent","0.08 percent","0.02 percent","0.10 percent"],"explanation":"Закон Вермонта делает незаконным управление CMV с BAC 0.04 percent или более, что вдвое меньше предела 0.08 для обычных транспортных средств. Источник: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.2."},"41":{"q":"В Вермонте владелец CDL, осуждённый за ПЕРВОЕ серьёзное правонарушение (например, управление CMV с BAC 0.04 или более), лишается права управления CMV как минимум на какой срок?","options":["1 год","60 дней","6 месяцев","3 года"],"explanation":"Первое серьёзное правонарушение лишает водителя права управления CMV на один год. Источник: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.2 (федеральный стандарт 49 CFR 383.51, принятый Вермонтом)."},"42":{"q":"Согласно закону Вермонта, управляя коммерческим автотранспортным средством, водитель считается сделавшим что в отношении химического тестирования на алкоголь?","options":["Давшим согласие на тестирование на алкоголь","Отказавшимся от права на слушание по CDL","Согласившимся на фиксированный штраф $500","Принявшим 30-дневное изъятие транспортного средства"],"explanation":"Правило подразумеваемого согласия Вермонта предусматривает, что любой, кто управляет CMV, считается давшим согласие на тестирование на алкоголь. Источник: Vermont CDL Manual § 1.2.2; 23 V.S.A. §§ 1202, 4116."},"43":{"q":"Если владелец CDL Вермонта осуждён за первое серьёзное правонарушение при перевозке опасных грузов, требующих табличек (placards), период лишения права управления CMV увеличивается как минимум до какого срока?","options":["3 года","1 год","18 месяцев","5 лет"],"explanation":"Первое серьёзное правонарушение, совершённое при перевозке опасных грузов с табличками (placards), увеличивает срок лишения с одного года до трёх лет. Источник: 23 V.S.A. § 4116; 49 CFR 383.51 Table 1 в редакции, принятой Вермонтом."},"44":{"q":"В Вермонте каков период лишения права управления за ВТОРОЕ серьёзное правонарушение, совершённое на CMV (например, второе правонарушение, связанное с алкоголем, в отдельном случае)?","options":["Пожизненное лишение права","3 года","10 лет","5 лет"],"explanation":"Два серьёзных правонарушения, возникших из отдельных случаев, приводят к пожизненному лишению права управления CMV. Источник: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.2."},"45":{"q":"Водитель CMV в Вермонте, который отказывается пройти обязательное тестирование на содержание алкоголя в крови, какое последствие для CDL несёт за этот отказ?","options":["Не менее чем 1-летнее лишение права на CDL","Предупреждение без лишения права","30-дневное лишение права на CDL","Только гражданский штраф $250"],"explanation":"Отказ от прохождения тестирования на алкоголь рассматривается как серьёзное правонарушение, влекущее минимальное лишение права управления CMV на один год (три года при перевозке опасных грузов с табличками). Источник: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.2."},"46":{"q":"На какой срок водитель CMV в Вермонте отстраняется от работы (out-of-service), если у него обнаружено любое определяемое количество алкоголя, всё ещё НИЖЕ 0.04 percent?","options":["24 часа","1 час","72 часа","30 дней"],"explanation":"Водитель CMV с любым измеримым количеством алкоголя ниже 0.04 отстраняется от работы (out-of-service) на 24 часа. Источник: Vermont CDL Manual § 1.2.2; 49 CFR 392.5."},"47":{"q":"В Вермонте осуждение за сколько СЕРЬЁЗНЫХ нарушений правил дорожного движения в течение трёхлетнего периода влечёт 60-дневное лишение права управления CMV?","options":["2 серьёзных нарушения","3 серьёзных нарушения","4 серьёзных нарушения","1 серьёзное нарушение"],"explanation":"Два серьёзных нарушения правил дорожного движения в течение трёх лет (отдельные случаи) приводят к 60-дневному лишению права управления CMV. Источник: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.3."},"48":{"q":"Владелец CDL Вермонта, осуждённый за ТРИ серьёзных нарушения правил дорожного движения в течение трёхлетнего периода, лишается права управления CMV как минимум на какой срок?","options":["120 дней","60 дней","180 дней","1 год"],"explanation":"Три серьёзных нарушения правил дорожного движения в течение трёх лет влекут 120-дневное лишение права управления CMV. Источник: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.3."},"49":{"q":"Согласно правилам CDL Вермонта, превышение скорости является СЕРЬЁЗНЫМ нарушением правил дорожного движения, когда водитель превышает установленный предел на сколько?","options":["15 mph или более","10 mph или более","20 mph или более","5 mph или более"],"explanation":"Чрезмерное превышение скорости на 15 mph или более выше установленного предела является серьёзным нарушением правил дорожного движения. Источник: Vermont CDL Manual § 1.2.3; 49 CFR 383.51 Table 2."},"50":{"q":"Что из следующего классифицируется как СЕРЬЁЗНОЕ нарушение правил дорожного движения для владельца CDL Вермонта?","options":["Слишком близкое следование за впереди идущим транспортным средством","Парковка в зоне, где парковка запрещена","Просроченный стикер регистрации","Перегоревший габаритный фонарь"],"explanation":"Слишком близкое следование является одним из перечисленных серьёзных нарушений правил дорожного движения наряду с чрезмерным превышением скорости, безрассудным вождением и неправильной или беспорядочной сменой полос. Источник: Vermont CDL Manual § 1.2.3; 49 CFR 383.51 Table 2."},"51":{"q":"В Вермонте каков период лишения права управления CMV за ПЕРВОЕ осуждение за нарушение на железнодорожном переезде?","options":["Не менее 60 дней","Не менее 120 дней","Не менее 30 дней","Не менее 1 года"],"explanation":"Первое нарушение на железнодорожном переезде приводит как минимум к 60-дневному лишению права. Источник: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.5."},"52":{"q":"Водитель CMV в Вермонте совершает ТРЕТЬЕ нарушение на железнодорожном переезде в течение трёхлетнего периода. Минимальный срок лишения права составляет:","options":["1 год","120 дней","60 дней","6 месяцев"],"explanation":"Третье нарушение на железнодорожном переезде в течение трёх лет влечёт как минимум одногодичное лишение права (60 дней за первое, 120 дней за второе, один год за третье). Источник: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.5."},"53":{"q":"Какое действие является нарушением на железнодорожном переезде, которое может лишить владельца CDL Вермонта права управления?","options":["Отсутствие достаточного пространства, чтобы проехать переезд полностью без остановки","Подача звукового сигнала перед проездом через пути","Проезд на скорости менее 10 mph","Остановка более чем за 50 футов до путей"],"explanation":"Отсутствие достаточного пространства, чтобы освободить переезд без остановки, является одним из шести нарушений на переезде. Источник: Vermont CDL Manual § 1.2.5; 49 CFR 383.51 Table 3."},"54":{"q":"В Вермонте каково минимальное лишение права управления CMV за ПЕРВОЕ осуждение за нарушение предписания об отстранении от работы (out-of-service order), не связанное с опасными грузами или пассажирами?","options":["180 дней","90 дней","30 дней","1 год"],"explanation":"Первое нарушение предписания об отстранении от работы (out-of-service order) лишает водителя права не менее чем на 180 дней (до одного года). Источник: 23 V.S.A. § 4116; 49 CFR 383.51 Table 4 в редакции, принятой Вермонтом."},"55":{"q":"Владелец CDL Вермонта осуждён за ВТОРОЕ нарушение предписания об отстранении от работы (out-of-service order) в течение 10-летнего периода. Период лишения права составляет:","options":["2 года","1 год","180 дней","5 лет"],"explanation":"Второе нарушение предписания об отстранении от работы (out-of-service order) в течение 10 лет (отдельные случаи) влечёт двухлетнее лишение права. Источник: 23 V.S.A. § 4116; 49 CFR 383.51 Table 4."},"56":{"q":"Каков период лишения права управления CMV в Вермонте за ТРЕТЬЕ или последующее нарушение предписания об отстранении от работы (out-of-service order) в течение 10-летнего периода?","options":["3 года","2 года","1 год","Пожизненно"],"explanation":"Третье или последующее нарушение предписания об отстранении от работы (out-of-service order) в течение 10 лет приводит к трёхлетнему лишению права. Источник: 23 V.S.A. § 4116; 49 CFR 383.51 Table 4."},"57":{"q":"Согласно закону Вермонта о CDL, использование портативного мобильного телефона во время управления CMV лучше всего описывается как:","options":["Запрещённое действие, которое засчитывается как серьёзное нарушение правил дорожного движения","Разрешённое, если разговор длится менее одной минуты","Разрешённое только на межштатных автомагистралях","Нарушение, не связанное с движением, без последствий для CDL"],"explanation":"Вермонт запрещает отправку текстовых сообщений и использование портативного телефона во время управления CMV; такие осуждения засчитываются как серьёзные нарушения правил дорожного движения для целей лишения права. Источник: 23 V.S.A. § 4125; 49 CFR 383.51 Table 2."},"58":{"q":"Когда отправка текстовых сообщений или использование портативного телефона разрешены при управлении CMV в Вермонте?","options":["Когда необходимо связаться с правоохранительными органами или экстренными службами","Когда стоишь на красный сигнал светофора","При движении со скоростью менее 25 mph","Когда груз не является опасным"],"explanation":"Единственным исключением из запрета на отправку текстовых сообщений/использование портативного телефона является связь с сотрудниками правоохранительных органов или другими экстренными службами. Источник: 23 V.S.A. § 4125."},"59":{"q":"Владелец CDL Вермонта, ПОЖИЗНЕННО лишённый права за два серьёзных правонарушения, может подать заявление о восстановлении права коммерческого вождения только после того, как был лишён права не менее чем на какой срок, и после прохождения любой требуемой реабилитации?","options":["10 лет","5 лет","7 лет","15 лет"],"explanation":"Пожизненное лишение права на CDL может быть сокращено по истечении не менее 10 лет, если водитель проходит утверждённую программу реабилитации и выполняет требования по аффидевиту. Источник: Code of Vermont Rules 14-050-044 (Reduction of Life Disqualification); 49 CFR 383.51."},"60":{"q":"Согласно закону штата Вермонт об уступке дороги (Move Over), что должен сделать водитель любого другого транспортного средства при приближении полицейского или аварийно-спасательного автомобиля с включённой сиреной или световыми сигналами?","options":["Продолжать движение в обычном режиме, пока аварийный автомобиль находится в другой полосе","Прижаться вправо в пределах полосы движения и полностью остановиться, пока он не проедет","Перестроиться только на одну полосу влево и сохранять скорость","Снизить скорость на 20 mph ниже установленного ограничения и продолжать движение в той же полосе"],"explanation":"23 V.S.A. § 1050(a) требует, чтобы при приближении полицейского, машины скорой помощи, пожарного или спасательного автомобиля с включённой сиреной или световым сигналом все остальные транспортные средства «прижались вправо в пределах полосы движения и полностью остановились, пока полицейский или аварийный автомобиль не проедет». Источник: 23 V.S.A. § 1050(a)."},"61":{"q":"На многополосной автомагистрали штата Вермонт, что требует закон об уступке дороги (Move Over) от водителя, приближающегося к НЕПОДВИЖНОМУ аварийному или буксировочному автомобилю с включёнными аварийными огнями?","options":["Снизить скорость ровно до 25 mph независимо от условий","Остановиться только если неподвижное транспортное средство — это полицейская машина, а не эвакуатор","Всегда полностью останавливаться в полосе движения до получения сигнала продолжить движение","Перестроиться в более удалённую полосу, если позволяют условия безопасности; в противном случае снизить скорость до разумной, безопасной и осмотрительной"],"explanation":"23 V.S.A. § 1050(b) предписывает водителю, приближающемуся к неподвижному аварийному автомобилю (или буксировочному/ремонтному автомобилю с включённым жёлтым проблесковым маячком), действовать осторожно и, если он находится на многополосной автомагистрали и это позволяют условия безопасности, перестроиться в полосу подальше от неподвижного транспортного средства; если перестроение невозможно, водитель должен снизить скорость до «разумной, безопасной и осмотрительной». Источник: 23 V.S.A. § 1050(b)."},"62":{"q":"Правило штата Вермонт об уступке дороги неподвижному транспортному средству применяется к остановившемуся буксировочному и ремонтному автомобилю, когда на нём включён проблесковый маячок какого цвета?","options":["Синий","Красно-белый","Зелёный","Жёлтый (янтарный)"],"explanation":"23 V.S.A. § 1050(b) распространяет обязанность перестроиться/снизить скорость на «неподвижный буксировочный и ремонтный автомобиль с включённым жёлтым проблесковым маячком», в дополнение к полицейским (синий) и машинам скорой помощи/пожарным/спасательным (красный) автомобилям. Источник: 23 V.S.A. § 1050(b)."},"63":{"q":"Когда транспорт, приближающийся к остановившемуся школьному автобусу штата Вермонт, имеющему необходимую разметку и оборудование, либо обгоняющий его, должен остановиться?","options":["Только если на автобусе мигают жёлтые огни","Только когда дети явно стоят на проезжей части","Немедленно, и оставаться остановившимся, пока работают мигающие красные сигнальные огни","В пределах 25 feet от автобуса, затем медленно проехать мимо него"],"explanation":"23 V.S.A. § 1075 требует, чтобы водитель при встрече или обгоне должным образом обозначенного школьного автобуса, остановившегося для посадки или высадки школьников, «немедленно остановил своё транспортное средство» и оставлял его неподвижным «пока работают мигающие красные сигнальные огни». Источник: 23 V.S.A. § 1075."},"64":{"q":"Согласно закону штата Вермонт, единственная ситуация, в которой водитель НЕ обязан останавливаться перед школьным автобусом, ведущим посадку детей на противоположной стороне, — это когда автобус находится на:","options":["Любой четырёхполосной дороге, с разделителем или без","Любой дороге, где водитель движется как минимум на 10 mph ниже ограничения","Любой дороге с нарисованной двойной жёлтой осевой линией","Автомагистрали с раздельными проезжими частями, при этом автобус находится на другой проезжей части"],"explanation":"23 V.S.A. § 1075 освобождает от остановки только «на автомагистрали с раздельными проезжими частями» при встрече или обгоне автобуса на другой проезжей части (или в зоне посадки с контролируемым доступом, где пешеходам запрещён переход). Проезжие части должны быть физически разделены; нарисованная линия не считается. Источник: 23 V.S.A. § 1075."},"65":{"q":"В штате Вермонт, когда транспортное средство с табличками опасных грузов или автобус обязаны остановиться на железнодорожном переезде, где они должны остановиться относительно ближайшего рельса?","options":["Ровно в 10 feet от ближайшего рельса","В любом месте в пределах 75 feet от ближайшего рельса","В пределах 50 feet, но не ближе 15 feet от ближайшего рельса","В пределах 100 feet, но не ближе 25 feet от ближайшего рельса"],"explanation":"В соответствии с федеральным стандартом CDL/FMCSA, применяемым в штате Вермонт (49 CFR 392.10), водитель транспортного средства с табличками опасных грузов или автобуса, обязанный остановиться, должен сделать это в пределах 50 feet, но не ближе 15 feet от ближайшего рельса. Источник: Vermont CDL Manual (Railroad-Highway Crossings); 49 CFR 392.10."},"66":{"q":"Когда коммерческое транспортное средство штата Вермонт пересекает железнодорожные пути, что руководство CDL предписывает водителю НЕ делать?","options":["Держать обе руки на руле","Пересекать на достаточно низкой передаче, чтобы избежать остановки двигателя","Смотреть и слушать в обе стороны перед въездом","Переключать передачи, пока любая часть транспортного средства находится на путях"],"explanation":"Руководство Vermont CDL Manual предписывает водителям никогда не переключать передачи при пересечении путей, поскольку переключение создаёт риск заглохнуть на переезде. Водитель должен выбрать передачу до достижения путей и не менять её, пока не освободит переезд. Источник: Vermont CDL Manual (Railroad-Highway Crossings)."},"67":{"q":"Прежде чем водитель CMV в штате Вермонт начнёт пересекать железнодорожный переезд, руководство гласит, что водитель должен убедиться в наличии достаточного места на другой стороне, чтобы транспортное средство:","options":["Имело как минимум одну ось, остающуюся между рельсами","Могло остановиться на путях, чтобы проверить наличие приближающихся поездов","Могло остановиться с передним бампером на втором рельсе","Могло полностью освободить пути, не останавливаясь на них"],"explanation":"Руководство Vermont CDL Manual предупреждает, что водитель никогда не должен начинать пересечение путей, не убедившись, что транспортное средство сможет полностью проехать, не останавливаясь. Водитель должен иметь место на другой стороне, чтобы полностью освободить переезд. Источник: Vermont CDL Manual (Railroad-Highway Crossings)."},"68":{"q":"CMV в штате Вермонт остановилось на ровной прямой двухполосной дороге. Где размещаются три предупредительных устройства (светоотражающие треугольники)?","options":["Примерно в 25 feet, 75 feet и 150 feet позади","Примерно в 50 feet, 150 feet и 300 feet позади","Примерно в 10 feet, 100 feet и 200 feet позади в сторону приближающегося транспорта","Примерно в 10 feet, 50 feet и 100 feet позади"],"explanation":"В соответствии со стандартом FMCSA/CDL, применяемым в штате Вермонт, на двухполосной дороге треугольники размещаются примерно в 10 feet прямо за транспортным средством, примерно в 100 feet позади и примерно в 200 feet позади в направлении приближающегося транспорта. Источник: Vermont CDL Manual (Stopping on the Road); 49 CFR 392.22."},"69":{"q":"Если CMV в штате Вермонт остановилось в пределах 500 feet от холма, поворота или иного препятствия для обзора, как следует скорректировать размещение предупредительных устройств?","options":["Разместить устройство в сторону препятствия на расстоянии от 100 до 500 feet от транспортного средства, чтобы обеспечить достаточное предупреждение","Треугольники не требуются, поскольку опасность видна","Разместить все три устройства прямо за транспортным средством в пределах 10 feet","Разместить устройство ровно в 700 feet за препятствием"],"explanation":"Руководство Vermont CDL Manual (согласно 49 CFR 392.22) предписывает, что если остановка происходит в пределах 500 feet от поворота, вершины холма или иного препятствия для обзора, водитель перемещает самое заднее предупредительное устройство в сторону препятствия так, чтобы оно находилось на расстоянии от 100 до 500 feet от транспортного средства. Источник: Vermont CDL Manual; 49 CFR 392.22."},"70":{"q":"Каково максимальное законное ограничение скорости для любого автотранспортного средства на автомагистрали с ограниченным доступом (межштатной) в штате Вермонт, если не указано иное?","options":["55 mph","65 mph","60 mph","70 mph"],"explanation":"Регламент штата Вермонт об автомагистралях с ограниченным доступом устанавливает максимум 65 mph: «Максимальное ограничение скорости, с которой любое автотранспортное средство может двигаться по автомагистралям с ограниченным доступом, составляет шестьдесят пять (65) миль в час», если не указано иное. Источник: Code Vt. R. 14-053-004 (объекты с ограниченным доступом); 23 V.S.A. § 1081."},"71":{"q":"При отсутствии установленного ограничения или статуса дороги с ограниченным доступом, каков предусмотренный законом максимум скорости по умолчанию на автодороге в штате Вермонт?","options":["65 mph","50 mph","45 mph","55 mph"],"explanation":"23 V.S.A. § 1081 устанавливает максимум по умолчанию 50 mph на автодорогах, если не установлено или не вывешено иное ограничение согласно закону. Более высокие ограничения (до 65 mph) применяются только на автомагистралях с ограниченным доступом по решению Дорожного комитета. Источник: 23 V.S.A. § 1081."},"72":{"q":"Устанавливает ли штат Вермонт отдельное, более низкое максимальное ограничение скорости для грузовиков и коммерческих транспортных средств, чем для легковых автомобилей на своих автодорогах?","options":["Нет — установленное ограничение применяется ко всем транспортным средствам; отдельного ограничения скорости для грузовиков нет","Да — грузовики ограничены 60 mph на межштатных дорогах","Да — грузовики ограничены 55 mph повсюду","Да — грузовики должны держаться на 10 mph ниже ограничения для легковых автомобилей"],"explanation":"Штат Вермонт не устанавливает отдельного, более низкого ограничения скорости для грузовиков. Один и тот же максимум (например, 65 mph на автомагистралях с ограниченным доступом, 50 mph по умолчанию) применяется ко всем автотранспортным средствам, включая грузовики и автобусы. Источник: 23 V.S.A. § 1081; Code Vt. R. 14-053-004."},"73":{"q":"На автомагистрали с ограниченным доступом в штате Вермонт грузовик или автобус может двигаться ниже установленной минимальной скорости из-за уклона только если он:","options":["Включает свою аварийную сигнализацию (четыре мигающих указателя) во время этого","Полностью съезжает на левую обочину","Непрерывно подаёт звуковой сигнал","Сначала получает разрешение на движение негабаритного транспорта"],"explanation":"Регламент штата Вермонт об автомагистралях с ограниченным доступом освобождает грузовики и автобусы от правила минимальной скорости, когда уклон делает эту скорость неосуществимой, но только если транспортное средство в это время включает аварийную сигнализацию (четыре мигающих указателя). Источник: Code Vt. R. 14-053-004 (объекты с ограниченным доступом)."},"74":{"q":"Дорога Vermont Route 108 через Smugglers' Notch закрыта для каких транспортных средств?","options":["Любого транспортного средства шириной более 8 feet 6 inches","Одиночных транспортных средств длиной более 40 feet и автопоездов (тягач с прицепом) общей длиной более 45 feet","Всех транспортных средств с GVWR более 26,000 pounds","Автобусов, перевозящих более 15 пассажиров"],"explanation":"23 V.S.A. § 1006b запрещает одиночным автотранспортным средствам длиной более 40 feet и тягачам с одним или несколькими прицепами общей длиной более 45 feet движение по участку Smugglers' Notch дороги Vermont Route 108. Узкий горный перевал не может их вместить. Источник: 23 V.S.A. § 1006b; Vermont Agency of Transportation (vtrans.vermont.gov/notch)."},"75":{"q":"Водитель грузовика, который игнорирует GPS и застревает автопоездом в Smugglers' Notch на дороге Vermont Route 108, подвергается гражданскому штрафу, который за существенное блокирование движения с 1 июля 2026 года повышается до:","options":["$2,000","$50,000","$20,000","$5,000"],"explanation":"Согласно 23 V.S.A. § 1006b базовый штраф составлял $1,000, или $2,000, если нарушение существенно затрудняет движение; законодательство повышает их до $10,000 и $20,000 (за блокирование движения) с 1 июля 2026 года. Источник: 23 V.S.A. § 1006b; Vermont Agency of Transportation."},"76":{"q":"Без разрешения на негабаритный груз, какова максимальная законная ширина транспортного средства на автодорогах штата Вермонт?","options":["8 feet 0 inches","8 feet 6 inches","10 feet 0 inches","9 feet 0 inches"],"explanation":"Законный максимум ширины транспортного средства в штате Вермонт без разрешения составляет 8 feet 6 inches (102 inches); законная высота — 13 feet 6 inches, а законная полная масса — 80,000 pounds. Превышение этих значений требует разрешения на негабаритный/перегруженный транспорт от DMV Commercial Vehicle Operations. Источник: Vermont DMV CVO Oversize/Overweight Permit Rules (CVO-110)."},"77":{"q":"Разрешения на негабаритный/перегруженный транспорт в штате Вермонт обычно допускают движение только в какие часы?","options":["С получаса до восхода солнца до получаса после захода солнца","Только между полуночью и 6:00 утра","24 часа в сутки без ограничений","Только по выходным и официальным праздникам"],"explanation":"Правила выдачи разрешений в штате Вермонт ограничивают движение негабаритного/перегруженного транспорта светлым временем суток: с получаса до восхода солнца до получаса после захода солнца, с дополнительными ограничениями для самых крупных грузов в выходные и праздничные дни. Источник: Vermont DMV CVO Oversize/Overweight Permit Rules (CVO-110)."},"78":{"q":"На проезжей части в штате Вермонт, где должен двигаться грузовик, движущийся медленнее обычного потока транспорта?","options":["В крайней правой доступной полосе или как можно ближе к правому краю, за исключением обгона или подготовки к левому повороту","В левой полосе, чтобы более быстрый транспорт мог перестраиваться вправо","По мощёной обочине, пока поток не рассеется","В центральной полосе любой многополосной дороги в любое время"],"explanation":"Правило штата Вермонт о движении справа требует, чтобы транспортное средство, движущееся ниже обычной скорости потока, двигалось в правой полосе или как можно ближе к правому бордюру или краю, за исключением случаев обгона или подготовки к левому повороту. Источник: 23 V.S.A. § 1038 / § 1031."},"79":{"q":"Согласно закону штата Вермонт, кто может требовать установки цепей противоскольжения на определённых дорогах штата в зимнюю погоду и для каких транспортных средств?","options":["Цепи требуются только на местных дорогах, никогда на дорогах штата","Только федеральное правительство может предписывать цепи, и только на межштатных дорогах","Должностные лица штата могут требовать цепи для транспортных средств с GVWR или GCWR более 26,000 pounds на определённых участках дорог","Цепи обязательны для каждого легкового автомобиля с декабря по март"],"explanation":"23 V.S.A. § 1006c уполномочивает Секретаря по транспорту, Комиссара по автотранспортным средствам или Комиссара общественной безопасности (или их представителей) требовать установки цепей противоскольжения на определённых участках дорог штата в зимнюю погоду для транспортных средств с GVWR или GCWR более 26,000 pounds, с заблаговременной установкой знаков. Источник: 23 V.S.A. § 1006c."},"80":{"q":"В штате Вермонт, какое ведомство выдаёт коммерческие водительские удостоверения (CDL) и проводит обязательные тесты?","options":["Управление автотранспортных средств штата Вермонт (DMV)","Транспортное агентство штата Вермонт (VTrans)","Федеральное управление безопасности автомобильных перевозчиков (FMCSA)","Подразделение коммерческого транспорта полиции штата Вермонт"],"explanation":"Управление автотранспортных средств штата Вермонт (DMV) выдаёт CDL и проводит тесты на знание и навыки в штате. FMCSA устанавливает федеральные стандарты CDL, но не выдаёт удостоверение. Источник: Vermont DMV, страница Commercial Driver's License (CDL); Vermont CDL Driver Manual (VN-111)."},"81":{"q":"Прежде чем человек сможет сдать практический экзамен на CDL в штате Вермонт, какое разрешение он должен сначала получить и иметь при себе?","options":["Коммерческое ученическое разрешение (CLP)","Только обычное ученическое разрешение штата Вермонт","Временное разрешение на межштатную эксплуатацию","Разрешение на негабаритный/перегруженный груз"],"explanation":"Штат Вермонт требует, чтобы заявители получили Коммерческое ученическое разрешение (CLP), которое допускает практику под наблюдением на коммерческом автотранспортном средстве перед практическим экзаменом. Источник: Vermont DMV, страница Commercial Driver's Learner Permit (CLP); Vermont CDL Driver Manual (VN-111)."},"82":{"q":"После получения Коммерческого ученического разрешения в штате Вермонт, каково минимальное количество дней, в течение которых водитель должен владеть им перед сдачей практического экзамена на CDL?","options":["14 days","7 days","30 days","60 days"],"explanation":"Владелец CLP должен подождать минимум 14 days после выдачи CLP, прежде чем сдавать практический экзамен на CDL. Источник: Vermont DMV, страницы Commercial Driver's Learner Permit (CLP) и Renewals/Transfers/Upgrades; федеральное 49 CFR 383.25."},"83":{"q":"Из каких трёх частей состоит практический экзамен на CDL в штате Вермонт?","options":["Предрейсовый осмотр, базовое управление транспортным средством и вождение на дороге","Письменный тест на знания, проверка зрения и вождение на дороге","Проверка пневматических тормозов, обращение с опасными грузами и ночное вождение","Предрейсовый осмотр, параллельная парковка и тест на шоссейной скорости"],"explanation":"Практический экзамен на CDL в штате Вермонт состоит из трёх частей, все из которых необходимо сдать: предрейсовый осмотр транспортного средства, базовые манёвры управления транспортным средством и тест по вождению на дороге. Источник: страницы Vermont DMV CDL; Vermont CDL Driver Manual (VN-111)."},"84":{"q":"Какую форму подаёт водитель для самостоятельного подтверждения типа своего вождения и медицинского статуса в Vermont DMV?","options":["Форму медицинской сертификации CDL (VL-033)","Только федеральный сертификат медицинского эксперта (Medical Examiner's Certificate)","Нотариально заверенный аффидевит о пригодности","Форму проверки биографии для опасных материалов TSA"],"explanation":"Владельцы и заявители CDL в штате Вермонт самостоятельно подтверждают тип своего вождения и медицинский статус, заполняя и подавая форму медицинской сертификации CDL, VL-033, в DMV. Источник: Vermont DMV, страница CDL Medical Requirements и Форма VL-033."},"85":{"q":"При самостоятельной сертификации в Vermont DMV, из скольких категорий вождения может выбирать заявитель на CDL?","options":["Четыре","Две","Три","Пять"],"explanation":"Существует четыре категории самостоятельной сертификации: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) и Excepted Intrastate (EA). Водитель выбирает одну в Форме VL-033. Источник: Vermont DMV CDL Medical Certification (Форма VL-033); 49 CFR 383.71."},"86":{"q":"Заявитель на CDL в штате Вермонт, который занимается межштатными перевозками и подпадает под федеральные правила физической квалификации (49 CFR Part 391), должен самостоятельно сертифицироваться по какой категории?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Водитель, который осуществляет межштатные перевозки и подпадает под 49 CFR Part 391, самостоятельно сертифицируется как Non-Excepted Interstate (NI) и должен предоставить действующий сертификат медицинского эксперта (Medical Examiner's Certificate). Источник: Vermont DMV Форма VL-033; 49 CFR 383.71."},"87":{"q":"Какая категория самостоятельной сертификации в штате Вермонт требует, чтобы водитель предоставил действующий сертификат медицинского эксперта (Medical Examiner's Certificate) с пометкой «Vermont Only»?","options":["Non-Excepted Intrastate (NA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)"],"explanation":"Водитель категории Non-Excepted Intrastate (NA) осуществляет перевозки только в пределах штата Вермонт и должен соответствовать медицинским стандартам, предоставив действующий сертификат медицинского эксперта (Medical Examiner's Certificate) с пометкой «Vermont Only». Источник: Vermont DMV CDL Medical Certification (Форма VL-033)."},"88":{"q":"Кто уполномочен проводить медицинский осмотр DOT, по результатам которого выдаётся сертификат медицинского эксперта CDL, принимаемый в штате Вермонт?","options":["Медицинский эксперт, числящийся в FMCSA National Registry of Certified Medical Examiners","Любой лицензированный врач по выбору водителя","Экзаменатор Vermont DMV на месте проведения тестирования","Сотрудник по безопасности работодателя водителя"],"explanation":"Медицинский осмотр должен проводиться медицинским экспертом, числящимся в FMCSA National Registry of Certified Medical Examiners. Источник: Vermont DMV, страница CDL Medical Requirements; 49 CFR 390.103 / Part 391."},"89":{"q":"Каков максимальный срок действия стандартного сертификата медицинского эксперта DOT для владельца CDL в штате Вермонт?","options":["До 2 years","До 1 year","До 3 years","До 5 years"],"explanation":"Стандартный сертификат медицинского эксперта (Medical Examiner's Certificate) действителен до 2 years, хотя эксперт может выдать его на более короткий срок, если состояние требует наблюдения. Источник: Vermont DMV, страница CDL Medical Requirements; 49 CFR Part 391."},"90":{"q":"Что может произойти с CDL в штате Вермонт, если его владелец не поддерживает действующий медицинский сертификат в реестре DMV?","options":["CDL может быть понижен в категории или право вождения может быть приостановлено","Ничего, пока само удостоверение не истекло","Водителю автоматически присваивается статус Excepted Interstate","Высылается только письменное предупреждение без последствий для удостоверения"],"explanation":"Если действующая медицинская документация не поддерживается в реестре, Vermont DMV может понизить категорию CDL (отозвать коммерческие привилегии) и/или приостановить право вождения. Источник: Vermont DMV, страница CDL Medical Requirements; 49 CFR 383.73."},"91":{"q":"Какое обучение должен пройти впервые подающий заявление на CDL класса A или класса B, прежде чем ему будет разрешено сдавать практический экзамен в штате Вермонт?","options":["Entry-Level Driver Training (ELDT) от провайдера, зарегистрированного в FMCSA","Курс безопасного вождения, одобренный Vermont DMV","Восьмичасовой аудиторный курс, преподаваемый DMV","Стажировку, зарегистрированную только у работодателя"],"explanation":"Впервые подающие заявление на класс A/B (и определённые отметки) должны пройти Entry-Level Driver Training (ELDT) у провайдера из реестра FMCSA Training Provider Registry перед сдачей практического экзамена на CDL. Источник: страницы Vermont DMV CDL; 49 CFR Part 380 Subpart F."},"92":{"q":"Для впервые получаемой отметки HazMat (H), когда должно быть завершено обязательное Entry-Level Driver Training?","options":["Перед сдачей теста на знания HazMat","Только перед практическим экзаменом по вождению на дороге","В течение 30 days после выдачи удостоверения","Только после одобрения проверки биографии TSA"],"explanation":"Поскольку отметка HazMat не предусматривает практического экзамена, ELDT для впервые получаемой отметки H должно быть завершено до того, как заявитель сдаёт тест на знания HazMat. Источник: страницы Vermont DMV CDL; 49 CFR Part 380 Subpart F."},"93":{"q":"Какой тест на знания должен сдать каждый заявитель на CDL в штате Вермонт независимо от класса или отметки?","options":["Тест на общие знания (General Knowledge)","Тест на пневматические тормоза (Air Brakes)","Тест на составные транспортные средства (Combination Vehicles)","Тест на опасные материалы (Hazardous Materials)"],"explanation":"Каждый заявитель на CDL должен сдать письменный тест на общие знания (General Knowledge); дополнительные тесты, такие как Air Brakes, Combination Vehicles и тесты на отметки, применяются только в зависимости от транспортного средства или отметки. Источник: Vermont CDL Driver Manual (VN-111); страницы Vermont DMV CDL."},"94":{"q":"Какой минимальный балл требуется для сдачи теста на знания (письменного) на CDL в штате Вермонт?","options":["80 percent","70 percent","75 percent","90 percent"],"explanation":"Тесты на знания на CDL в штате Вермонт требуют проходного балла не менее 80 percent правильно отвеченных вопросов. Источник: Vermont CDL Driver Manual (VN-111); информация о тестировании Vermont DMV CDL."},"95":{"q":"Каким способом необходимо продлевать CDL в штате Вермонт?","options":["Лично в офисе Vermont DMV","Только онлайн через веб-сайт DMV","По почте, используя только уведомление о продлении","Автоматически, без действий со стороны водителя"],"explanation":"CDL необходимо продлевать лично в офисе обслуживания клиентов Vermont DMV; водитель приносит подписанное уведомление о продлении и оплату. Источник: Vermont DMV, страница Renewals, Transfers & Upgrades."},"96":{"q":"На сколько лет за раз может быть продлён CDL в штате Вермонт?","options":["Два или четыре года","Один или два года","Пять лет","Восемь лет"],"explanation":"Продление CDL в штате Вермонт оформляется на двухлетний или четырёхлетний цикл, при этом любые оставшиеся полные годы текущего удостоверения засчитываются в счёт сбора за продление. Источник: Vermont DMV, страница Renewals, Transfers & Upgrades."},"97":{"q":"Лицо, имеющее действующий CDL другого штата и переезжающее в Вермонт, должно перевести его в CDL штата Вермонт в течение какого срока после установления места жительства?","options":["30 days","10 days","60 days","90 days"],"explanation":"Согласно законам штата и федеральным законам, лицо, имеющее CDL другого штата, должно перевести его в CDL штата Вермонт в течение 30 days после установления места жительства в Вермонте. Источник: Vermont DMV, страница Renewals, Transfers & Upgrades; 49 CFR 383.71."},"98":{"q":"При повышении категории существующего CDL штата Вермонт до более высокого класса, что должен сделать водитель в отношении разрешения?","options":["Получить Коммерческое ученическое разрешение (CLP) и владеть им не менее 14 days","Ничего; существующего CDL достаточно для сдачи экзамена на повышение","Получить только обычное ученическое разрешение водителя","Владеть новым разрешением минимум 90 days"],"explanation":"Чтобы повысить категорию до более высокого класса CDL, водитель должен получить Коммерческое ученическое разрешение (CLP), владеть им не менее 14 days и сдать соответствующие тесты на знания и навыки. Источник: Vermont DMV, страница Renewals, Transfers & Upgrades."},"99":{"q":"Почему Vermont DMV советует заявителям на CDL рассматривать опубликованные сборы за удостоверение и тестирование как подлежащие изменению?","options":["Размеры сборов устанавливаются законом и графиками DMV, которые могут пересматриваться, поэтому всегда следует уточнять текущий вывешенный сбор","Вермонт не взимает плату за услуги CDL, поэтому любая вывешенная сумма является ошибкой","Сборы согласовываются индивидуально у стойки для каждого заявителя","Только федеральное правительство, а не штат Вермонт, может устанавливать или изменять сборы за CDL"],"explanation":"Сборы за CDL и тестирование устанавливаются законом штата Вермонт и графиками сборов DMV, которые могут обновляться, поэтому заявителям следует уточнять текущую сумму в DMV, а не полагаться на фиксированное значение. Источник: информация о сборах Vermont DMV; 23 V.S.A. (статуты о сборах за автотранспортные средства)."}},"tr":{"0":{"q":"Vermont karayollarında, aşırı genişlik izni gerekmeden önce izin verilen azami yasal araç genişliği nedir?","options":["8 fit (96 inç)","8 fit 6 inç (102 inç)","9 fit (108 inç)","8 fit 4 inç (100 inç)"],"explanation":"23 V.S.A. § 1431 uyarınca, Vermont'ta azami araç genişliği 8 fit 6 inç'tir (102 inç); her bir yandan 3 inç'e kadar uzanan aynalar gibi güvenlik aygıtları bu sınıra dahil değildir. Bundan daha geniş olan herhangi bir araç, DMV'den aşırı boyut izni gerektirir. Kaynak: 23 V.S.A. § 1431."},"1":{"q":"Vermont karayollarında izin gerekmeden izin verilen azami yasal araç yüksekliği nedir?","options":["13 fit","14 fit","13 fit 6 inç","12 fit 6 inç"],"explanation":"23 V.S.A. § 1431, azami araç yüksekliğini 13 fit 6 inç olarak belirler. Bunu aşan yükler, Vermont DMV'den aşırı boyut izni gerektirir. Kaynak: 23 V.S.A. § 1431."},"2":{"q":"Vermont'ta, özel izin olmadan tek bir motorlu aracın (römork veya yarı römork takılı olmadan) izin verilen azami toplam uzunluğu nedir?","options":["40 fit","53 fit","46 fit","48 fit"],"explanation":"23 V.S.A. § 1432 uyarınca, römork veya yarı römork takılı olmayan ve toplam uzunluğu 46 fitten fazla olan hiçbir motorlu araç, özel izin olmaksızın bir Vermont karayolunda kullanılamaz. Kaynak: 23 V.S.A. § 1432."},"3":{"q":"Genel bir Vermont karayolunda, aşırı uzunluk izni olmadan bir araç kombinasyonunun (römork veya yarı römorklu kamyon) izin verilen azami toplam uzunluğu nedir?","options":["65 fit","75 fit","70 fit","80 fit"],"explanation":"23 V.S.A. § 1432 uyarınca, toplam uzunluğu 75 fiti aşmayan araç kombinasyonları Vermont karayollarında izin olmadan kullanılabilir; daha uzun kombinasyonlar aşırı uzunluk izni gerektirir. Kaynak: 23 V.S.A. § 1432."},"4":{"q":"Vermont'un Eyaletlerarası (Interstate) ve belirlenmiş Ulusal Ağ (National Network) karayollarında, çekici-yarı römork kombinasyonunda izin verilen azami yarı römork uzunluğu nedir?","options":["48 fit","53 fit","45 fit","57 fit"],"explanation":"Eyaletlerarası sistemde ve uygun belirlenmiş karayollarında, Vermont toplam uzunluk üst sınırı yerine federal bileşen uzunluğu sınırlarını uygular: çekici-yarı römork kombinasyonundaki yarı römork 53 fite kadar olabilir. Kaynak: 23 V.S.A. § 1432."},"5":{"q":"Vermont'un belirlenmiş karayolu ağında bir çekici-yarı römork-römork (çift römorklu) kombinasyonu için her bir römork veya yarı römorkun azami uzunluğu nedir?","options":["Her biri 28 fit","Her biri 30 fit","Her biri 27 fit","Her biri 33 fit"],"explanation":"Eyaletlerarası ve belirlenmiş ağda, çift römork kombinasyonları federal bileşen sınırlarına tabidir: her römork veya yarı römork 28 fite kadar olabilir. Kaynak: 23 V.S.A. § 1432 (federal STAA standartlarıyla uyumlu)."},"6":{"q":"Vermont karayollarında standart bir ticari araç için özel izin olmadan izin verilen azami brüt araç ağırlığı nedir?","options":["73,280 pound","80,000 pound","90,000 pound","84,000 pound"],"explanation":"23 V.S.A. § 1392 uyarınca, azami brüt araç ağırlığı 80,000 pounddur. Daha ağır yükler, bir DMV aşırı ağırlık izni veya yasal bir özel izin kategorisi gerektirir. Kaynak: 23 V.S.A. § 1392."},"7":{"q":"Vermont'taki federal Eyaletlerarası Karayolu Sistemi'nde (Interstate Highway System), hiçbir tolerans tanınmaksızın izin verilen azami tek aks ağırlığı nedir?","options":["22,400 pound","18,000 pound","20,000 pound","21,000 pound"],"explanation":"23 V.S.A. § 1391 uyarınca, Eyaletlerarası sistemde (Eisenhower National System of Interstate and Defense Highways) tek aks sınırı, federal yasayla uyumlu olarak, hiçbir tolerans tanınmaksızın 20,000 pounddur. Kaynak: 23 V.S.A. § 1391."},"8":{"q":"Vermont'taki Eyaletlerarası Karayolu Sistemi'nde, hiçbir tolerans tanınmaksızın izin verilen azami tandem aks ağırlığı nedir?","options":["36,000 pound","34,000 pound","32,000 pound","38,000 pound"],"explanation":"23 V.S.A. § 1391 uyarınca, Eyaletlerarası sistemde tandem aks sınırı, federal ağırlık standartlarıyla uyumlu olarak, hiçbir tolerans tanınmaksızın 34,000 pounddur. Kaynak: 23 V.S.A. § 1391."},"9":{"q":"Vermont'un Eyaletlerarası olmayan (eyalet ve kasaba) karayollarında, yüzde 10 tolerans uygulanmadan önce izin verilen azami tek aks ağırlığı nedir?","options":["20,000 pound","24,000 pound","22,400 pound","21,500 pound"],"explanation":"23 V.S.A. § 1391 uyarınca, Eyaletlerarası olmayan Vermont karayollarında tek aks sınırı, yüzde 10 tolerans tanınmak üzere, 22,400 pounddur. Kaynak: 23 V.S.A. § 1391."},"10":{"q":"Vermont'un Eyaletlerarası olmayan karayollarında, yüzde 10 tolerans uygulanmadan önce izin verilen azami tandem aks ağırlığı nedir?","options":["34,000 pound","36,000 pound","32,000 pound","40,000 pound"],"explanation":"23 V.S.A. § 1391 uyarınca, Eyaletlerarası olmayan Vermont karayollarında tandem aks sınırı, yüzde 10 tolerans tanınmak üzere, 36,000 pounddur (Eyaletlerarası 34,000 poundluk sınırından eyalete özgü önemli bir farktır). Kaynak: 23 V.S.A. § 1391."},"11":{"q":"Vermont'un Eyaletlerarası olmayan ve Eyaletlerarası aks ağırlığı kuralları arasındaki temel fark toleranstır. Eyaletlerarası olmayan Vermont karayollarındaki tek ve tandem aks sınırlarına hangi tolerans uygulanır?","options":["Hiçbir tolerans tanınmaz","Yüzde 5 tolerans tanınır","Yüzde 10 tolerans tanınır","Yüzde 15 tolerans tanınır"],"explanation":"23 V.S.A. § 1391 uyarınca, Eyaletlerarası olmayan tek aks (22,400 lb) ve tandem aks (36,000 lb) sınırları yüzde 10 tolerans taşırken, Eyaletlerarası sınırlar (20,000 lb / 34,000 lb) hiçbir tolerans tanımaz. Kaynak: 23 V.S.A. § 1391."},"12":{"q":"Vermont, bir aks grubunun aralığına ve sayısına göre izin verilen azami brüt ağırlığı belirlemek için, federal yasayla uyumlu olarak hangi formülü kullanır?","options":["Federal Köprü Formülü (Formül B)","Brüt Kombinasyon Ağırlığı Derecelendirme formülü","Tandem Aralık Endeksi","Aks Yükü Eşdeğerliği formülü"],"explanation":"Vermont, tek aks, tandem ve 80,000 lb brüt sınırlarına ek olarak, herhangi bir aks grubunda taşınan ağırlığı aralığa (L) ve aks sayısına (N) göre sınırlamak için Federal Köprü Formülü'nü (Köprü Formülü B), W = 500[LN/(N-1) + 12N + 36], uygular. Kaynak: 23 V.S.A. ch. 13 / FHWA kapsamında uygulanan federal Köprü Formülü."},"13":{"q":"Vermont'ta kullanılan Federal Köprü Formülü'nde, ardışık iki aks, merkezleri arasındaki mesafe ne kadar olduğunda (ayrı tek akslar yerine) 'tandem' olarak değerlendirilir?","options":["40 inçten fazla ancak 96 inçten fazla değil","96 inçten fazla ancak 120 inçten fazla değil","40 inçten fazla değil","48 inçten fazla ancak 108 inçten fazla değil"],"explanation":"Vermont'ta uygulanan federal tanımlar uyarınca, tandem aks, merkezleri arasındaki mesafe 40 inçten fazla ancak 96 inçten fazla olmayan iki veya daha fazla ardışık akstır; merkezleri 40 inç veya daha az aralıklı akslar tek aks olarak değerlendirilir. Kaynak: 23 V.S.A. ch. 13 kapsamında uygulanan Federal Köprü Formülü tanımları / FHWA."},"14":{"q":"Bir Vermont ticari araç sürücüsü genel olarak DMV'den ne zaman aşırı boyut veya aşırı ağırlık izni almaya ihtiyaç duyar?","options":["Yalnızca başka bir eyalete geçerken","Araç veya yük, yasal genişlik, yükseklik, uzunluk veya ağırlık sınırlarını aştığında","Yalnızca brüt ağırlık 100,000 poundu aştığında","Yalnızca gece veya kış koşullarında"],"explanation":"Bir araç veya yük, yasal sınırları aştığında (genişlik 8'6\"ten fazla, yükseklik 13'6\"tan fazla, tek araç 46 fitten fazla, kombinasyon 75 fitten fazla veya geçerli ağırlık sınırları) bir Vermont DMV aşırı boyut/aşırı ağırlık izni gereklidir. Kaynak: 23 V.S.A. ch. 13 ve Vermont DMV Aşırı Ağırlık/Aşırı Boyut İzin Kuralları (Code Vt. R. 14-050-019)."},"15":{"q":"Hangi Vermont kurumu, eyalet karayollarında ve Eyaletlerarası sistemde seyahat için aşırı boyut ve aşırı ağırlık izinleri verir?","options":["Vermont Doğal Kaynaklar Kurumu (Vermont Agency of Natural Resources)","Federal Motorlu Taşıyıcı Güvenliği İdaresi (Federal Motor Carrier Safety Administration)","Vermont Motorlu Taşıtlar Dairesi (Vermont Department of Motor Vehicles, Commercial Vehicle Operations)","İlçe şerif departmanı"],"explanation":"Vermont DMV, Komiser'in yetkisi kapsamında, Commercial Vehicle Operations birimi (ve çevrimiçi VT Haul Pass sistemi) aracılığıyla eyalet karayolları ve Eyaletlerarası sistem için aşırı boyut ve aşırı ağırlık izinleri verir. Kaynak: Vermont DMV CVO Aşırı Ağırlık/Aşırı Boyut İzin Kuralları; 23 V.S.A. § 1400."},"16":{"q":"Bir nakliye şirketinin, yıl boyunca aynı güzergahlarda tekrar tekrar büyük boyutlu ve bölünemez yükleri taşıması gerekiyor. Bu ihtiyaca en uygun Vermont izin türü hangisidir?","options":["Tek seferlik izin","Acil durum izni","Toptan (yıllık) izin","Yalnızca kayıt izni"],"explanation":"Vermont DMV, bölünemez yüklerin tekrarlanan hareketleri için toptan (yıllık) izinler verirken, tek seferlik izinler sınırlı bir zaman dilimi (yaklaşık yedi iş günü) içinde tek bir hareketi kapsar. Kaynak: Vermont DMV Aşırı Ağırlık/Aşırı Boyut İzin Kuralları (Code Vt. R. 14-050-019)."},"17":{"q":"Bir belediyenin yetki alanındaki karayolları ve köprülerde (Sınıf 1 kasaba karayolları hariç) yasal sınırların üzerindeki ağırlık için, bir Vermont aşırı ağırlık izni başvurusu kime yapılmalıdır?","options":["Vermont DMV Komiseri'ne","Belediyenin ilgili yasama organına (örneğin, selectboard)","Federal Karayolu İdaresi'ne (Federal Highway Administration)","Vermont Eyalet Polisi'ne (Vermont State Police)"],"explanation":"Vermont izin kuralları uyarınca, bir belediyenin yetki alanındaki karayolları ve köprülerde (Sınıf 1 kasaba karayolları hariç) ağırlık sınırlarını aşan işletim için başvuru, ilgili belediye yasama organına yapılır. Kaynak: Code Vt. R. 14-050-019 (Aşırı Ağırlık/Aşırı Boyut Araç İzinleri)."},"18":{"q":"Vermont'un Özel Fazla Ağırlık İzni (bölünebilir yükler için yıllık bir izin), direksiyon aksında azami ne kadar ağırlığa izin verir?","options":["10,000 pound","12,000 pound","14,000 pound","20,000 pound"],"explanation":"Vermont Özel Fazla Ağırlık İzni kuralı uyarınca, aks sınırları direksiyon aksında 12,000 pound ve diğer tüm akslarda 20,000 pounddur. Kaynak: Vermont DMV Özel Fazla Ağırlık İzni; Code Vt. R. 14-050-019."},"19":{"q":"Vermont yasası, yıllık özel izin kapsamında çalışan altı veya daha fazla aksa sahip belirli kamyon kombinasyonlarının, Eyaletlerarası olmayan karayollarında hangi yükseltilmiş brüt ağırlığa ulaşmasına izin verir?","options":["85,000 pound","108,000 pound","99,000 pound","95,000 pound"],"explanation":"23 V.S.A. § 1392 uyarınca, özel yıllık izin kapsamında çalışan altı veya daha fazla yük taşıyan aksa sahip kamyonlar, Eyaletlerarası olmayan karayollarında 99,000 pound brüt ağırlığa ulaşabilir; Vermont'a özgü bu izin, federal yasayla yetkilendirilmedikçe Eyaletlerarası sisteme uygulanmaz. Kaynak: 23 V.S.A. § 1392."},"20":{"q":"Vermont'ta, aşağıdakilerden hangisini kullanmak için Sınıf A CDL gereklidir?","options":["Çekilen birim(ler)in GVWR'si 10,000 lbs'yi aştığında, GCWR'si 26,001 lbs veya daha fazla olan herhangi bir araç kombinasyonu","GVWR'si 26,001 lbs veya daha fazla olan herhangi bir tek araç","Sürücü dahil 16 veya daha fazla yolcu taşımak üzere tasarlanmış herhangi bir araç","Tehlikeli madde plakaları gösteren, herhangi bir ağırlıktaki herhangi bir araç"],"explanation":"Vermont, federal CDL sınıflandırmasını takip eder (49 CFR 383.91): Sınıf A, çekilen araç(lar)ın GVWR'si 10,000 lbs'nin üzerinde olmak kaydıyla, GCWR'si 26,001 lbs veya daha fazla olan herhangi bir araç kombinasyonudur. Kaynak: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.91."},"21":{"q":"Vermont kuralları uyarınca, bir Sınıf B CDL hangi araçları kapsar?","options":["Yalnızca 16'dan az yolcu taşıyan otobüsler","GVWR'si 26,001 lbs veya daha fazla olan herhangi bir tek araç ya da bu tür bir aracın 10,000 lbs'yi aşmayan bir birim çekmesi","Römorkun GVWR'sinin 10,000 lbs'yi aştığı herhangi bir kombinasyon","Yalnızca tehlikeli madde onayı gerektiren herhangi bir araç"],"explanation":"Vermont, federal tanımı benimser: Sınıf B, GVWR'si 26,001 lbs veya daha fazla olan herhangi bir tek araç ya da bu tür bir aracın GVWR'si 10,000 lbs'yi aşmayan başka bir aracı çekmesidir. Kaynak: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.91."},"22":{"q":"Bir araç Sınıf A veya B ağırlık tanımlarını karşılamadığında ancak (sürücü dahil) en az kaç yolcu taşımak üzere tasarlandığında veya plakalı tehlikeli madde taşıdığında bir Vermont Sınıf C CDL gereklidir?","options":["10 yolcu","12 yolcu","16 yolcu","24 yolcu"],"explanation":"Vermont'un Sınıf C'si, (Grup A veya B'yi karşılamayan) sürücü dahil 16 veya daha fazla yolcu taşımak üzere tasarlanmış ya da plakalı tehlikeli madde taşımak için kullanılan bir araca uygulanır. Kaynak: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.91."},"23":{"q":"Bir Vermont CDL sahibinin, plakalı miktarda tehlikeli madde taşıyan bir aracı kullanmak için hangi onaya (endorsement) ihtiyacı vardır?","options":["N onayı","H onayı","T onayı","X onayı"],"explanation":"H (HazMat) onayı, plakalı miktarlarda tehlikeli madde taşınmasına izin verir. (X kodu, birleşik Tank ve HazMat anlamına gelir.) Kaynak: Vermont DMV HazMat Onayları sayfası / Vermont CDL Manual (VN-111)."},"24":{"q":"Yalnızca eyalet içi (Vermont içi) ticaretle sınırlı bir Vermont CDL almak için asgari yaş nedir?","options":["16 yaşında","17 yaşında","18 yaşında","21 yaşında"],"explanation":"Vermont, bir başvuru sahibinin CDL alması ve eyalet içi ticarette ticari motorlu araç kullanması için en az 18 yaşında olmasını gerektirir. Kaynak: Vermont DMV Commercial Driver's License sayfası."},"25":{"q":"Bir Vermont CDL ile eyaletlerarası ticarette ticari motorlu araç kullanmak için asgari yaş nedir?","options":["18 yaşında","19 yaşında","20 yaşında","21 yaşında"],"explanation":"Bir sürücü, federal kuralla uyumlu olarak, eyaletlerarası ticarette ticari motorlu araç kullanmak için en az 21 yaşında olmalıdır. Kaynak: Vermont DMV Commercial Driver's License sayfası / FMCSA 49 CFR 391.11."},"26":{"q":"CDL beceri testini planlamadan önce, federal yasa (Vermont'ta uygulanan), başvuru sahibinin Ticari Öğrenci İzni'ni (CLP) en az kaç gün elinde bulundurmasını gerektirir?","options":["7 gün","14 gün","30 gün","60 gün"],"explanation":"Bir başvuru sahibi, CDL beceri testine girmeden önce CLP'yi en az 14 gün elinde bulundurmalıdır. Kaynak: Vermont DMV CLP sayfası / FMCSA 49 CFR 383.25."},"27":{"q":"Bir Vermont Ticari Öğrenci İzni'ne (CLP) başvurmak için, başvuru sahibinin önceden neye sahip olması gerekir?","options":["Geçerli bir Vermont Sınıf D (normal) sürücü belgesi","Geçerli bir motosiklet onayı","Bir federal TWIC kartı","Bir genç sürücü (junior operator) belgesi"],"explanation":"Vermont, CLP başvuru sahiplerinin geçerli bir Vermont Sınıf D sürücü belgesine sahip olmasını gerektirir. Kaynak: Vermont DMV Commercial Driver's Learner Permit sayfası."},"28":{"q":"Bir Vermont Ticari Öğrenci İzni (CLP), verildiği tarihten itibaren ne kadar süreyle geçerlidir?","options":["90 gün","6 ay","1 yıl","2 yıl"],"explanation":"Bir Vermont CLP, verildiği tarihten itibaren bir yıl (12 ay) geçerlidir. Kaynak: Vermont DMV Commercial Driver's Learner Permit sayfası / FMCSA 49 CFR 383.25."},"29":{"q":"Kamu karayollarında araç kullanırken, bir Vermont CLP sahibine şu özelliklere sahip bir kişinin eşlik etmesi gerekir:","options":["Herhangi bir geçerli Vermont sürücü belgesine sahip kişi","Kullanılan araç sınıfı için, gerekli onaylar dahil, geçerli bir CDL'ye sahip kişi","En az 25 yaşında olan kişi","Sertifikalı bir DMV sınav görevlisi"],"explanation":"Bir CLP sahibine, yanında oturan, kullanılan araç türü için uygun onaylara sahip geçerli bir CDL bulunduran bir kişi eşlik etmelidir. Kaynak: Vermont DMV CLP sayfası / FMCSA 49 CFR 383.25."},"30":{"q":"Vermont'ta dökme halde sıvı veya gaz taşıyan bir tank aracı kullanmak için hangi onay gereklidir?","options":["T onayı","P onayı","N onayı","S onayı"],"explanation":"Dökme tanklarda sıvı/gaz taşımak için N (Tank Aracı) onayı gereklidir. Kaynak: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.93."},"31":{"q":"N onayı gerektiren bir tank aracı genel olarak, bireysel anma kapasitesi 119 galonun üzerinde olan ve toplam anma kapasitesi en az kaç galon olan bir tankta sıvı veya gaz taşıyan araçtır?","options":["500 galon","1,000 galon","1,500 galon","3,000 galon"],"explanation":"N onayı, bireysel anma kapasitesi 119 galondan fazla ve toplam anma kapasitesi 1,000 galon veya daha fazla sıvı ya da gaz olan tanklara uygulanır. Kaynak: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.5."},"32":{"q":"Bir Vermont sürücüsünün ikili veya üçlü römorkları kullanmak için hangi onaya ihtiyacı vardır?","options":["T onayı","N onayı","D onayı","X onayı"],"explanation":"T onayı, ikili ve üçlü römorkların kullanımına izin verir ve yalnızca bir bilgi testini geçmeyi gerektirir. Kaynak: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.93."},"33":{"q":"Vermont'ta yolcu taşımak (örneğin bir toplu taşıma veya çartır otobüsünde) için hangi onay gereklidir?","options":["S onayı","P onayı","N onayı","H onayı"],"explanation":"P (Yolcu) onayı, CDL eşiğinin üzerinde yolcu taşımak üzere tasarlanmış bir aracı kullanmak için gereklidir; bir bilgi testi ve bir yolcu aracında bir beceri testi gerektirir. Kaynak: Vermont CDL Manual (VN-111) / FMCSA 49 CFR 383.93."},"34":{"q":"Vermont'ta öğrenci taşıyan bir okul otobüsünü kullanan bir sürücünün, P onayına ek olarak hangi ek onaya sahip olması gerekir?","options":["H onayı","T onayı","S onayı","N onayı"],"explanation":"Okul otobüsü sürücülerinin, P onayına ek olarak S (Okul Otobüsü) onayına ihtiyacı vardır. S onayı, okul otobüsü işletimi konusunda bilgi ve beceri testi gerektirir. Kaynak: Vermont DMV Okul Otobüsü sayfaları / FMCSA 49 CFR 383.93."},"35":{"q":"Bir Vermont CDL'sinde HazMat (H) onayı almak için asgari yaş nedir?","options":["18 yaşında","19 yaşında","21 yaşında","25 yaşında"],"explanation":"Tehlikeli madde taşımacılığı, eyaletlerarası düzeyde yeterlilik ve bir federal güvenlik onayı gerektirdiğinden, HazMat onayı başvuru sahibinin en az 21 yaşında olmasını gerektirir. Kaynak: Vermont DMV HazMat Onayları sayfası."},"36":{"q":"Vermont bir HazMat (H) onayı verebilmeden veya yenileyebilmeden önce, başvuru sahibinin hangi ek taramayı geçmesi gerekir?","options":["Parmak izi alınmasını içeren bir Ulaştırma Güvenliği İdaresi (TSA) geçmiş kontrolü","Bir eyalet görme uzmanı muayenesi","Bir işveren yol testi sertifikasyonu","Bir Ulusal Muhafız (National Guard) hizmet incelemesi"],"explanation":"USA PATRIOT Act uyarınca, HazMat onayı, verilmeden veya yenilenmeden önce parmak izi alınması ve geçmiş kontrolü dahil bir TSA güvenlik tehdidi değerlendirmesi gerektirir. Kaynak: Vermont DMV HazMat Onayları sayfası / 49 CFR 1572."},"37":{"q":"Vermont'ta uygulanan ELDT kuralları uyarınca, ilk kez başvuran bir Sınıf A başvuru sahibi, gerekli giriş düzeyi sürücü eğitimini nerede tamamlamalıdır?","options":["Listelenip listelenmediğine bakılmaksızın herhangi bir community college","FMCSA Eğitim Sağlayıcı Sicili'nde (Training Provider Registry, TPR) listelenen bir sağlayıcıda","Yalnızca Vermont DMV eğitim ofisinde","Sürücünün seçeceği herhangi bir işveren işletmeli programda"],"explanation":"7 Şubat 2022 tarihinden itibaren geçerli olmak üzere, ELDT (teori ve direksiyon başında), beceri testinden önce FMCSA'nın Eğitim Sağlayıcı Sicili'nde listelenen bir sağlayıcıyla tamamlanmalıdır. Kaynak: FMCSA ELDT kuralı (49 CFR Part 380) / Vermont DMV CDL Eğitim sayfaları."},"38":{"q":"ELDT (Giriş Düzeyi Sürücü Eğitimi), test öncesinde aşağıdakilerden hangisini GEREKTİRMEZ?","options":["İlk kez başvuran Sınıf A veya Sınıf B CDL başvuru sahipleri","İlk kez bir H (HazMat) onayı isteyen sürücüler","Sınıf B'den Sınıf A'ya yükseltme yapan sürücüler","Onayı zaten 7 Şubat 2022'den önce elinde bulundurmuş sürücüler"],"explanation":"ELDT geriye dönük değildir: CDL veya S/P/H onayı 7 Şubat 2022'den önce verilmiş sürücülerin ELDT'yi tamamlaması gerekmez. İlk kez Sınıf A/B, B'den A'ya yükseltmeler ve ilk kez S, P ve H onayları için geçerlidir. Kaynak: FMCSA ELDT kuralı (49 CFR Part 380)."},"39":{"q":"Bir Vermont CDL başvuru sahibinin seçmesi gereken tıbbi öz-beyan kategorilerini en iyi hangi grup tanımlar?","options":["Ticari, Özel, Tarımsal ve Rekreasyonel","İstisnasız eyaletlerarası, İstisnalı eyaletlerarası, İstisnasız eyalet içi ve İstisnalı eyalet içi","Sınıf A tıbbi, Sınıf B tıbbi, Sınıf C tıbbi ve Muaf","Federal, Eyalet, Yerel ve Kabile"],"explanation":"CDL başvuru sahipleri dört kategoriden birine öz-beyanda bulunur: istisnasız eyaletlerarası, istisnalı eyaletlerarası, istisnasız eyalet içi veya istisnalı eyalet içi. İstisnasız sürücüler geçerli bir tıbbi muayene görevlisi sertifikası bulundurmalıdır. Kaynak: Vermont DMV CDL tıbbi öz-beyan / FMCSA 49 CFR 383.71."},"40":{"q":"Vermont'ta bir ticari motorlu araç (CMV) kullanırken, sürücünün yasaklanmış alkol seviyesiyle araç kullandığı kabul edilmeden önceki azami yasal kandaki alkol konsantrasyonu (BAC) nedir?","options":["yüzde 0.04","yüzde 0.08","yüzde 0.02","yüzde 0.10"],"explanation":"Vermont yasası, sıradan araçlar için geçerli 0.08 sınırının yarısı olan yüzde 0.04 veya daha yüksek bir BAC ile CMV kullanmayı yasa dışı kılar. Kaynak: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.2."},"41":{"q":"Vermont'ta, İLK büyük suçtan (örneğin 0.04 veya daha yüksek bir BAC ile CMV kullanmak gibi) mahkum olan bir CDL sahibi, CMV kullanmaktan en az ne kadar süreyle men edilir?","options":["1 yıl","60 gün","6 ay","3 yıl"],"explanation":"İlk büyük suç, sürücüyü bir yıl süreyle CMV kullanmaktan men eder. Kaynak: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.2 (Vermont tarafından benimsenen federal standart 49 CFR 383.51)."},"42":{"q":"Vermont yasasına göre, bir ticari motorlu araç kullanan bir sürücü, alkol için kimyasal test konusunda ne yapmış sayılır?","options":["Alkol testine onay vermiş","CDL duruşması hakkından feragat etmiş","Sabit 500 dolarlık bir cezayı kabul etmiş","30 günlük bir araç haczini kabul etmiş"],"explanation":"Vermont'un örtülü onay kuralı, bir CMV kullanan herkesin alkol testine onay vermiş sayılacağını öngörür. Kaynak: Vermont CDL Manual § 1.2.2; 23 V.S.A. §§ 1202, 4116."},"43":{"q":"Bir Vermont CDL sahibi, plaka gerektiren tehlikeli maddeleri taşırken ilk büyük suçtan mahkum olursa, CMV men süresi en az ne kadara çıkarılır?","options":["3 yıl","1 yıl","18 ay","5 yıl"],"explanation":"Plakalı tehlikeli maddeleri taşırken işlenen bir ilk büyük suç, men süresini bir yıldan üç yıla çıkarır. Kaynak: 23 V.S.A. § 4116; Vermont tarafından benimsenen 49 CFR 383.51 Table 1."},"44":{"q":"Vermont'ta, bir CMV'de işlenen İKİNCİ bir büyük suç için (örneğin ayrı bir olaydan kaynaklanan ikinci bir alkolle ilgili suç) men süresi nedir?","options":["Ömür boyu men","3 yıl","10 yıl","5 yıl"],"explanation":"Ayrı olaylardan kaynaklanan iki büyük suç, ömür boyu CMV men cezasıyla sonuçlanır. Kaynak: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.2."},"45":{"q":"Gerekli kandaki alkol testine girmeyi reddeden bir Vermont CMV sürücüsü, bu reddetme nedeniyle hangi CDL sonucuyla karşılaşır?","options":["En az 1 yıllık CDL men cezası","Men cezası olmadan bir uyarı","30 günlük CDL men cezası","Yalnızca 250 dolarlık bir hukuki ceza"],"explanation":"Alkol testine girmeyi reddetmek, bir büyük suç olarak değerlendirilir ve asgari bir yıllık CMV men cezası taşır (hazmat-plakalı ise üç yıl). Kaynak: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.2."},"46":{"q":"Hala yüzde 0.04'ün ALTINDA olan ancak tespit edilebilir herhangi bir miktarda alkole sahip olduğu tespit edilen bir Vermont CMV sürücüsü ne kadar süreyle hizmet dışı bırakılır?","options":["24 saat","1 saat","72 saat","30 gün"],"explanation":"0.04'ün altında ölçülebilir herhangi bir miktarda alkole sahip bir CMV sürücüsü 24 saat süreyle hizmet dışı bırakılır. Kaynak: Vermont CDL Manual § 1.2.2; 49 CFR 392.5."},"47":{"q":"Vermont'ta, üç yıllık bir süre içinde kaç CİDDİ trafik ihlalinden mahkum olmak 60 günlük bir CMV men cezasını tetikler?","options":["2 ciddi ihlal","3 ciddi ihlal","4 ciddi ihlal","1 ciddi ihlal"],"explanation":"Üç yıl içinde iki ciddi trafik ihlali (ayrı olaylar) 60 günlük bir CMV men cezasıyla sonuçlanır. Kaynak: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.3."},"48":{"q":"Üç yıllık bir süre içinde ÜÇ ciddi trafik ihlalinden mahkum olan bir Vermont CDL sahibi, CMV kullanmaktan en az ne kadar süreyle men edilir?","options":["120 gün","60 gün","180 gün","1 yıl"],"explanation":"Üç yıl içinde üç ciddi trafik ihlali 120 günlük bir CMV men cezası taşır. Kaynak: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.3."},"49":{"q":"Vermont'un CDL kuralları uyarınca, sürücü belirlenen hız sınırını ne kadar aştığında hız yapmak CİDDİ bir trafik ihlalidir?","options":["15 mph veya daha fazla","10 mph veya daha fazla","20 mph veya daha fazla","5 mph veya daha fazla"],"explanation":"Belirlenen sınırın 15 mph veya daha fazla üzerinde aşırı hız yapmak ciddi bir trafik ihlalidir. Kaynak: Vermont CDL Manual § 1.2.3; 49 CFR 383.51 Table 2."},"50":{"q":"Aşağıdakilerden hangisi bir Vermont CDL sahibi için CİDDİ bir trafik ihlali olarak sınıflandırılır?","options":["Öndeki aracı çok yakından takip etmek","Park yasağı bölgesinde park etmek","Süresi dolmuş bir kayıt etiketi","Yanmış bir işaret lambası"],"explanation":"Çok yakından takip etmek, aşırı hız yapma, dikkatsiz araç kullanma ve uygunsuz veya düzensiz şerit değiştirmeyle birlikte listelenen ciddi trafik ihlallerinden biridir. Kaynak: Vermont CDL Manual § 1.2.3; 49 CFR 383.51 Table 2."},"51":{"q":"Vermont'ta, demiryolu-karayolu hemzemin geçit ihlalinin İLK mahkumiyeti için CMV men süresi nedir?","options":["En az 60 gün","En az 120 gün","En az 30 gün","En az 1 yıl"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali, en az 60 günlük bir men cezasıyla sonuçlanır. Kaynak: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.5."},"52":{"q":"Bir Vermont CMV sürücüsü, üç yıllık bir süre içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlali işler. Asgari men süresi şudur:","options":["1 yıl","120 gün","60 gün","6 ay"],"explanation":"Üç yıl içinde üçüncü bir demiryolu-karayolu hemzemin geçit ihlali, en az bir yıllık men cezası taşır (ilk 60 gün, ikinci 120 gün, üçüncü bir yıl). Kaynak: 23 V.S.A. § 4116; Vermont CDL Manual § 1.2.5."},"53":{"q":"Hangi eylem, bir Vermont CDL sahibini men edebilecek bir demiryolu-karayolu hemzemin geçit ihlalidir?","options":["Geçidi durmadan tamamen geçmek için yeterli alana sahip olmamak","Rayları geçmeden önce korna çalmak","10 mph'nin altında bir hızla geçmek","Rayların 50 fitten fazla öncesinde durmak"],"explanation":"Geçidi durmadan temizlemek için yeterli alana sahip olmamak, altı hemzemin geçit suçundan biridir. Kaynak: Vermont CDL Manual § 1.2.5; 49 CFR 383.51 Table 3."},"54":{"q":"Vermont'ta, bir hizmet dışı bırakma emrini (out-of-service order) ihlal etmenin İLK mahkumiyeti (hazmat veya yolcu içermeyen) için asgari CMV men cezası nedir?","options":["180 gün","90 gün","30 gün","1 yıl"],"explanation":"İlk hizmet dışı bırakma emri ihlali, sürücüyü 180 günden az olmamak üzere (bir yıla kadar) men eder. Kaynak: 23 V.S.A. § 4116; Vermont tarafından benimsenen 49 CFR 383.51 Table 4."},"55":{"q":"Bir Vermont CDL sahibi, 10 yıllık bir süre içinde İKİNCİ bir hizmet dışı bırakma emri ihlalinden mahkum olur. Men süresi şudur:","options":["2 yıl","1 yıl","180 gün","5 yıl"],"explanation":"10 yıl içinde ikinci bir hizmet dışı bırakma emri ihlali (ayrı olaylar) iki yıllık bir men cezası taşır. Kaynak: 23 V.S.A. § 4116; 49 CFR 383.51 Table 4."},"56":{"q":"10 yıllık bir süre içinde ÜÇÜNCÜ veya sonraki bir hizmet dışı bırakma emri ihlali için Vermont CMV men süresi nedir?","options":["3 yıl","2 yıl","1 yıl","Ömür boyu"],"explanation":"10 yıl içinde üçüncü veya sonraki bir hizmet dışı bırakma emri ihlali, üç yıllık bir men cezasıyla sonuçlanır. Kaynak: 23 V.S.A. § 4116; 49 CFR 383.51 Table 4."},"57":{"q":"Vermont'un CDL yasası uyarınca, bir CMV kullanırken elde taşınan bir cep telefonu kullanmak en iyi nasıl tanımlanır?","options":["Ciddi bir trafik ihlali sayılan yasaklanmış bir eylem","Görüşme bir dakikanın altındaysa izin verilir","Yalnızca eyaletlerarası karayollarında izin verilir","CDL etkisi olmayan hareketsiz bir ihlal"],"explanation":"Vermont, bir CMV kullanırken mesajlaşmayı ve elde taşınan telefon kullanımını yasaklar; bu tür mahkumiyetler men cezasına doğru ciddi trafik ihlalleri sayılır. Kaynak: 23 V.S.A. § 4125; 49 CFR 383.51 Table 2."},"58":{"q":"Vermont'ta bir CMV kullanırken mesajlaşmaya veya elde taşınan telefon kullanımına ne zaman izin verilir?","options":["Kolluk kuvvetleriyle veya acil durum hizmetleriyle iletişim kurmak gerektiğinde","Bir kırmızı trafik ışığında durulduğunda","25 mph'nin altında seyahat edilirken","Yük tehlikesiz olduğunda"],"explanation":"Mesajlaşma/elde taşınan telefon yasağının tek istisnası, kolluk görevlileriyle veya diğer acil durum hizmetleriyle iletişimdir. Kaynak: 23 V.S.A. § 4125."},"59":{"q":"İki büyük suçtan dolayı ÖMÜR BOYU men edilen bir Vermont CDL sahibi, ticari sürüş ayrıcalıklarının yeniden tanınması için yalnızca en az ne kadar süre men edildikten ve gerekli rehabilitasyonu tamamladıktan sonra başvurabilir?","options":["10 yıl","5 yıl","7 yıl","15 yıl"],"explanation":"Ömür boyu CDL men cezası, sürücü onaylı bir rehabilitasyon programını tamamlar ve yeminli beyan gerekliliklerini karşılarsa en az 10 yıl sonra azaltılabilir. Kaynak: Code of Vermont Rules 14-050-044 (Ömür Boyu Men Cezasının Azaltılması); 49 CFR 383.51."},"60":{"q":"Vermont'un Yol Ver (Move Over) yasasına göre, bir kolluk veya acil durum aracı sireni çalarak ya da sinyal lambalarını yakarak yaklaştığında, diğer her aracın sürücüsü ne yapmalıdır?","options":["Acil durum aracı farklı bir şeritte olduğu sürece normal şekilde devam etmek","Şeridin sağına çekilmek ve araç geçinceye kadar tamamen durmak","Yalnızca sola bir şerit kaymak ve hızı korumak","Belirtilen sınırın 20 mph altına yavaşlamak ve aynı şeritte devam etmek"],"explanation":"23 V.S.A. § 1050(a), siren çalarak ya da sinyal lambasını yakarak yaklaşan bir kolluk, ambulans, itfaiye veya kurtarma aracı söz konusu olduğunda diğer tüm araçların 'şeridin sağına çekilmesi ve kolluk veya acil durum aracı geçinceye kadar tamamen durması' gerektiğini şart koşar. Kaynak: 23 V.S.A. § 1050(a)."},"61":{"q":"Vermont'ta çok şeritli bir karayolunda, uyarı lambalarını yakmış DURAN bir acil durum ya da çekici aracına yaklaşan bir sürücüden Yol Ver yasası ne yapmasını ister?","options":["Koşullara bakılmaksızın hızı tam olarak 25 mph'e düşürmek","Duran araç bir çekici değil de bir polis aracıysa yalnızca o zaman durmak","Geçme işareti verilene kadar her zaman seyir şeridinde tamamen durmak","Güvenlik koşulları izin veriyorsa daha uzaktaki bir şeride geçmek; aksi halde makul, güvenli ve sağduyulu bir hıza yavaşlamak"],"explanation":"23 V.S.A. § 1050(b), duran bir acil durum aracına (ya da amber renkli lamba yakan bir çekme/onarım aracına) yaklaşan bir sürücünün dikkatle ilerlemesi ve çok şeritli bir karayolundaysa ve güvenlik izin veriyorsa duran araçtan daha uzak bir şeride geçmesi gerektiğini belirtir; şerit değiştirmek mümkün değilse sürücü 'makul, güvenli ve sağduyulu bir hıza' yavaşlamalıdır. Kaynak: 23 V.S.A. § 1050(b)."},"62":{"q":"Vermont'un duran araçlar için Yol Ver kuralı, duran bir çekme ve onarım aracına hangi renk sinyal lambasını yaktığında uygulanır?","options":["Mavi","Kırmızı ve beyaz","Yeşil","Amber"],"explanation":"23 V.S.A. § 1050(b), polis (mavi) ve ambulans/itfaiye/kurtarma (kırmızı) araçlarına ek olarak 'amber sinyal lambası yakan duran bir çekme ve onarım aracı' için de yol ver/yavaşla yükümlülüğünü genişletir. Kaynak: 23 V.S.A. § 1050(b)."},"63":{"q":"Gerektiği gibi işaretlenmiş ve donatılmış, durmuş bir Vermont okul otobüsü söz konusu olduğunda, yaklaşan ve geçen trafik ne zaman durmalıdır?","options":["Yalnızca otobüsün amber renkli ışıkları yanıp sönüyorsa","Yalnızca çocuklar yolda gözle görülür şekilde duruyorsa","Derhal ve yanıp sönen kırmızı sinyal ışıkları çalışırken durmuş halde kalarak","Otobüsün 25 feet yakınında durarak, sonra yavaşça yanından geçerek"],"explanation":"23 V.S.A. § 1075, okul çocuklarını bindirmek veya indirmek için durmuş, gerektiği gibi işaretlenmiş bir okul otobüsüyle karşılaşan ya da onu geçen bir sürücünün 'aracını derhal durdurmasını' ve 'yanıp sönen kırmızı sinyal ışıkları çalışırken' aracını durmuş halde tutmasını şart koşar. Kaynak: 23 V.S.A. § 1075."},"64":{"q":"Vermont yasasına göre, bir sürücünün karşı tarafta çocuk bindiren bir okul otobüsü için durmasının gerekmediği tek durum, otobüsün nerede olmasıdır?","options":["Bölünmüş olsun ya da olmasın herhangi bir dört şeritli yolda","Sürücünün sınırın en az 10 mph altında gittiği herhangi bir yolda","Ortasında boyalı çift sarı çizgi olan herhangi bir yolda","Otobüsün farklı bir yolda olduğu, ayrı taşıt yolları bulunan bir karayolunda"],"explanation":"23 V.S.A. § 1075, yalnızca 'ayrı taşıt yolları bulunan bir karayolunda' farklı bir yoldaki otobüsle karşılaşıldığında ya da geçildiğinde (veya yayaların geçemeyeceği kontrollü erişimli bir bindirme bölgesinde) durmaktan muaf tutar. Taşıt yolları fiziksel olarak ayrılmış olmalıdır; boyalı bir çizgi bu niteliği taşımaz. Kaynak: 23 V.S.A. § 1075."},"65":{"q":"Vermont'ta, levhalı bir tehlikeli madde aracı ya da bir otobüs bir demiryolu-karayolu geçidinde durmak zorunda kaldığında, en yakın raya göre nerede durmalıdır?","options":["En yakın raydan tam olarak 10 feet uzakta","En yakın raydan 75 feet mesafe içinde herhangi bir yerde","En yakın raya 50 feet'ten yakın ama 15 feet'ten az olmamak üzere","En yakın raya 100 feet'ten yakın ama 25 feet'ten az olmamak üzere"],"explanation":"Vermont'ta uygulanan federal CDL/FMCSA standardına (49 CFR 392.10) göre, durmak zorunda olan levhalı bir tehlikeli madde aracının ya da bir otobüsün sürücüsü, en yakın raya 50 feet'ten yakın ama 15 feet'ten az olmamak üzere durmalıdır. Kaynak: Vermont CDL El Kitabı (Demiryolu-Karayolu Geçitleri); 49 CFR 392.10."},"66":{"q":"Bir Vermont ticari aracı demiryolu raylarından geçerken, CDL el kitabı sürücüye ne YAPMAMASINI söyler?","options":["İki elini de direksiyonda tutmak","Stop etmeyi önlemek için yeterince düşük viteste geçmek","Girmeden önce her iki yöne de bakıp dinlemek","Aracın herhangi bir kısmı raylardayken vites değiştirmek"],"explanation":"Vermont CDL El Kitabı, vites değiştirmenin geçitte stop etme riski taşıması nedeniyle sürücülere raylardan geçerken asla vites değiştirmemelerini söyler. Sürücü raylara ulaşmadan önce bir vites seçmeli ve geçidi tamamen geçene kadar değiştirmemelidir. Kaynak: Vermont CDL El Kitabı (Demiryolu-Karayolu Geçitleri)."},"67":{"q":"Bir Vermont CMV sürücüsü bir demiryolu geçidini geçmeye başlamadan önce, el kitabı sürücünün karşı tarafta aracın şunu yapacak kadar yer olduğundan emin olması gerektiğini söyler:","options":["Raylar arasında en az bir aksı kalmış olmak","Yaklaşan trenleri kontrol etmek için raylarda duraklayabilmek","Ön tamponu ikinci rayda olacak şekilde durabilmek","Raylar üzerinde durmadan rayları tamamen geçebilmek"],"explanation":"Vermont CDL El Kitabı, bir sürücünün aracın üzerinde durmadan tamamen karşıya geçebileceğinden emin olmadan asla raylardan geçmeye başlamaması gerektiği konusunda uyarır. Sürücü, geçidi tamamen geçmek için karşı tarafta yer bulundurmalıdır. Kaynak: Vermont CDL El Kitabı (Demiryolu-Karayolu Geçitleri)."},"68":{"q":"Bir Vermont CMV'si düz, dümdüz iki şeritli bir yolda durmuş durumda. Üç uyarı cihazı (yansıtıcı üçgen) nereye yerleştirilir?","options":["Arkaya yaklaşık 25 feet, 75 feet ve 150 feet mesafeye","Arkaya yaklaşık 50 feet, 150 feet ve 300 feet mesafeye","Arkaya, yaklaşan trafiğe doğru yaklaşık 10 feet, 100 feet ve 200 feet mesafeye","Arkaya yaklaşık 10 feet, 50 feet ve 100 feet mesafeye"],"explanation":"Vermont'ta kullanılan FMCSA/CDL standardına göre, iki şeritli bir yolda üçgenler aracın tam arkasına yaklaşık 10 feet, arkaya yaklaşık 100 feet ve yaklaşan trafik yönünde arkaya yaklaşık 200 feet mesafeye yerleştirilir. Kaynak: Vermont CDL El Kitabı (Yolda Durma); 49 CFR 392.22."},"69":{"q":"Bir Vermont CMV'si bir tepenin, virajın ya da görüşü engelleyen başka bir nesnenin 500 feet mesafesinde durmuşsa, uyarı cihazları nasıl ayarlanmalıdır?","options":["Yeterli uyarı sağlamak için engele doğru, araçtan 100 ila 500 feet mesafeye bir cihaz yerleştirilir","Tehlike görünür olduğundan üçgen gerekmez","Her üç cihaz da aracın 10 feet mesafesi içinde tam arkasına yerleştirilir","Engelin tam 700 feet ötesine bir cihaz yerleştirilir"],"explanation":"Vermont CDL El Kitabı (49 CFR 392.22 uyarınca), durma noktası bir virajın, tepe yükseltisinin ya da görüşü engelleyen başka bir nesnenin 500 feet mesafesinde ise, sürücünün en arkadaki uyarı cihazını engele doğru hareket ettirerek araçtan 100 ila 500 feet uzakta durmasını sağlamasını yönlendirir. Kaynak: Vermont CDL El Kitabı; 49 CFR 392.22."},"70":{"q":"Aksi belirtilmedikçe, bir Vermont sınırlı erişimli (eyaletlerarası) karayolunda herhangi bir motorlu araç için yasal azami hız sınırı nedir?","options":["55 mph","65 mph","60 mph","70 mph"],"explanation":"Vermont'un sınırlı erişimli karayolu düzenlemesi azamiyi 65 mph olarak belirler: aksi belirtilmedikçe 'sınırlı erişimli karayollarında herhangi bir motorlu aracın işletilebileceği azami hız sınırı saatte altmış beş (65) mil olacaktır.' Kaynak: Code Vt. R. 14-053-004 (sınırlı erişimli tesisler); 23 V.S.A. § 1081."},"71":{"q":"Belirtilmiş bir sınır ya da sınırlı erişim tanımı yokken, Vermont'un bir karayolundaki varsayılan yasal azami hızı nedir?","options":["65 mph","50 mph","45 mph","55 mph"],"explanation":"23 V.S.A. § 1081, farklı bir sınır belirtilmedikçe ya da yasa kapsamında belirlenmedikçe karayollarında varsayılan azami 50 mph belirler. Daha yüksek sınırlar (65 mph'e kadar) yalnızca Trafik Komitesi yetkisiyle sınırlı erişimli karayollarında geçerlidir. Kaynak: 23 V.S.A. § 1081."},"72":{"q":"Vermont, karayollarında kamyonlar ve ticari araçlar için otomobillere kıyasla ayrı, daha düşük bir azami hız sınırı belirler mi?","options":["Hayır — belirtilen sınır tüm araçlar için geçerlidir; ayrı bir kamyon hız sınırı yoktur","Evet — kamyonlar eyaletlerarası yollarda 60 mph ile sınırlıdır","Evet — kamyonlar her yerde 55 mph ile sınırlıdır","Evet — kamyonlar belirtilen otomobil sınırının 10 mph altında kalmalıdır"],"explanation":"Vermont, ayrı ve daha düşük bir kamyon hız sınırı uygulamaz. Aynı azami (örneğin sınırlı erişimli karayollarında 65 mph, varsayılan 50 mph) kamyonlar ve otobüsler dahil tüm motorlu araçlar için geçerlidir. Kaynak: 23 V.S.A. § 1081; Code Vt. R. 14-053-004."},"73":{"q":"Bir Vermont sınırlı erişimli karayolunda, bir kamyon ya da otobüs eğim nedeniyle belirtilen asgari hızın altında ancak şu koşulda seyredebilir:","options":["Bunu yaparken dörtlü flaşörlerini yakarsa","Tamamen sol banketin üzerine geçerse","Kornasını sürekli olarak çalarsa","Önce bir gabari aşımı seyahat izni alırsa"],"explanation":"Vermont'un sınırlı erişim düzenlemesi, eğim bu hızı uygulanamaz kıldığında motorlu kamyonları ve otobüsleri asgari hız kuralından muaf tutar, ancak yalnızca aracın bu süre boyunca dörtlü flaşörlerini yakması koşuluyla. Kaynak: Code Vt. R. 14-053-004 (sınırlı erişimli tesisler)."},"74":{"q":"Smugglers' Notch'tan geçen Vermont Route 108, hangi araçlara kapalıdır?","options":["8 feet 6 inç'ten daha geniş herhangi bir araç","Toplam uzunluğu 40 feet'i aşan tek gövdeli araçlar ve 45 feet'i aşan çekici-römork kombinasyonları","26,000 pound GVWR üzerindeki tüm araçlar","15'ten fazla yolcu taşıyan otobüsler"],"explanation":"23 V.S.A. § 1006b, uzunluğu 40 feet'i aşan tek gövdeli motorlu araçların ve bir veya daha fazla römorkuyla toplamda 45 feet'i aşan çekici ünitelerin Vermont Route 108'in Smugglers' Notch bölümünden geçmesini yasaklar. Dar dağ geçidi bunları barındıramaz. Kaynak: 23 V.S.A. § 1006b; Vermont Ulaştırma Ajansı (vtrans.vermont.gov/notch)."},"75":{"q":"GPS'i göz ardı eden ve bir çekici-römorku Vermont Route 108'deki Smugglers' Notch'ta sıkıştıran bir kamyoncu, trafiği önemli ölçüde engellemesi durumunda 1 Temmuz 2026'da yükselmesi planlanan bir idari para cezasıyla karşılaşır; bu ceza:","options":["$2,000","$50,000","$20,000","$5,000"],"explanation":"23 V.S.A. § 1006b uyarınca taban ceza $1,000, ihlal trafiği önemli ölçüde engelliyorsa $2,000 idi; yasal düzenleme 1 Temmuz 2026 itibarıyla bunları $10,000'a ve (trafiği engelleme için) $20,000'a yükseltir. Kaynak: 23 V.S.A. § 1006b; Vermont Ulaştırma Ajansı."},"76":{"q":"Gabari aşımı izni olmadan, Vermont karayollarında yasal azami araç genişliği nedir?","options":["8 feet 0 inç","8 feet 6 inç","10 feet 0 inç","9 feet 0 inç"],"explanation":"Vermont'un izinsiz yasal azami araç genişliği 8 feet 6 inç'tir (102 inç); yasal yükseklik 13 feet 6 inç ve yasal brüt ağırlık 80,000 pound'dur. Bunların aşılması bir DMV Ticari Araç İşletmeleri gabari aşımı/aşırı yük izni gerektirir. Kaynak: Vermont DMV CVO Gabari Aşımı/Aşırı Yük İzin Kuralları (CVO-110)."},"77":{"q":"Vermont gabari aşımı/aşırı yük izinleri genellikle hangi saatlerde hareketi yetkilendirir?","options":["Gün doğumundan yarım saat önce ile gün batımından yarım saat sonrasına kadar","Yalnızca gece yarısı ile sabah 6:00 arasında","Hiçbir kısıtlama olmaksızın günde 24 saat","Yalnızca hafta sonları ve resmi tatillerde"],"explanation":"Vermont'un izin kuralları gabari aşımı/aşırı yük seyahatini gündüz saatleriyle sınırlar: gün doğumundan yarım saat önce ile gün batımından yarım saat sonrasına kadar, en büyük yükler için hafta sonları ve tatillerde ek kısıtlamalarla. Kaynak: Vermont DMV CVO Gabari Aşımı/Aşırı Yük İzin Kuralları (CVO-110)."},"78":{"q":"Bir Vermont karayolunda, trafiğin normal hızından daha yavaş giden bir kamyon nerede sürülmelidir?","options":["Geçiş yaparken ya da sola dönmeye hazırlanırken hariç, mevcut sağ şeritte ya da sağ kenara mümkün olduğunca yakın","Daha hızlı trafiğin sağa katılabilmesi için sol şeritte","Trafik açılana kadar asfalt bankette","Herhangi bir çok şeritli yolun orta şeridinde, her zaman"],"explanation":"Vermont'un sağdan gitme kuralı, trafiğin normal hızının altında seyreden bir aracın, geçiş ve sollama ya da sola dönüşe hazırlanma durumları hariç, sağ şeritte ya da sağ kaldırıma veya kenara mümkün olduğunca yakın sürülmesini şart koşar. Kaynak: 23 V.S.A. § 1038 / § 1031."},"79":{"q":"Vermont yasasına göre, kış havası sırasında belirlenmiş eyalet karayollarında lastik zinciri zorunluluğu getirebilecek olan kimdir ve bu hangi araçlar için geçerlidir?","options":["Zincirler yalnızca kasaba yollarında zorunludur, asla eyalet karayollarında değil","Yalnızca federal hükûmet zincir zorunluluğu getirebilir ve yalnızca eyaletlerarası yollarda","Eyalet yetkilileri, belirlenmiş karayolu kesimlerinde 26,000 pound GVWR ya da GCWR üzerindeki araçlar için zincir zorunluluğu getirebilir","Zincirler aralıktan marta kadar her binek otomobil için zorunludur"],"explanation":"23 V.S.A. § 1006c, Ulaştırma Sekreterine, Motorlu Taşıtlar Komiserine ya da Kamu Güvenliği Komiserine (veya görevlendirdikleri kişilere), kış havası sırasında eyalet karayollarının belirlenmiş kesimlerinde 26,000 pound GVWR ya da GCWR üzerindeki araçlar için önceden levha yerleştirilmek kaydıyla lastik zinciri zorunluluğu getirme yetkisi verir. Kaynak: 23 V.S.A. § 1006c."},"80":{"q":"Vermont'ta, Ticari Sürücü Belgelerini (CDL) hangi kurum verir ve gerekli sınavları kim yürütür?","options":["Vermont Motorlu Taşıtlar Dairesi (DMV)","Vermont Ulaştırma Ajansı (VTrans)","Federal Motorlu Taşıyıcı Güvenliği İdaresi (FMCSA)","Vermont Eyalet Polisi Ticari Araç Birimi"],"explanation":"Vermont Motorlu Taşıtlar Dairesi (DMV), eyalette CDL'leri verir ve bilgi ile beceri sınavlarını yürütür. FMCSA federal CDL standartlarını belirler ancak belgeyi vermez. Kaynak: Vermont DMV, Ticari Sürücü Belgesi (CDL) sayfası; Vermont CDL Sürücü El Kitabı (VN-111)."},"81":{"q":"Bir kişi Vermont'ta CDL beceri sınavına girmeden önce, ilk olarak hangi izni almalı ve elinde bulundurmalıdır?","options":["Ticari Öğrenci İzni (CLP)","Yalnızca normal bir Vermont öğrenci izni","Geçici bir eyaletlerarası işletme izni","Bir gabari aşımı/aşırı yük izni"],"explanation":"Vermont, başvuru sahiplerinden, beceri sınavından önce bir ticari motorlu araçta gözetim altında pratik yapmaya yetki veren bir Ticari Öğrenci İzni (CLP) almalarını ister. Kaynak: Vermont DMV, Ticari Sürücü Öğrenci İzni (CLP) sayfası; Vermont CDL Sürücü El Kitabı (VN-111)."},"82":{"q":"Vermont'ta bir Ticari Öğrenci İzni aldıktan sonra, bir sürücünün CDL beceri sınavına girmeden önce bu izni elinde bulundurması gereken asgari gün sayısı nedir?","options":["14 gün","7 gün","30 gün","60 gün"],"explanation":"Bir CLP sahibi, CDL için beceri sınavına girmeden önce CLP verildikten sonra asgari 14 gün beklemelidir. Kaynak: Vermont DMV, Ticari Sürücü Öğrenci İzni (CLP) ve Yenileme/Devir/Yükseltme sayfaları; federal 49 CFR 383.25."},"83":{"q":"Vermont CDL beceri sınavı hangi üç bölümden oluşur?","options":["Sefer öncesi muayene, temel araç kontrolü ve yol üzerinde sürüş","Yazılı bilgi sınavı, göz muayenesi ve yol üzerinde sürüş","Hava freni kontrolü, tehlikeli madde taşıma ve gece sürüşü","Sefer öncesi muayene, paralel park ve karayolu hızında sürüş sınavı"],"explanation":"Vermont'un CDL beceri sınavı, tümü geçilmesi gereken üç bölümden oluşur: sefer öncesi araç muayenesi, temel araç kontrol manevraları ve yol üzerinde sürüş sınavı. Kaynak: Vermont DMV CDL sayfaları; Vermont CDL Sürücü El Kitabı (VN-111)."},"84":{"q":"Bir sürücü, sürüş türünü ve tıbbi durumunu Vermont DMV'ye kendi beyanıyla bildirmek için hangi formu sunar?","options":["CDL Tıbbi Sertifikasyon formu (VL-033)","Yalnızca federal Tıbbi Muayene Sertifikası","Noter onaylı bir uygunluk beyannamesi","TSA tehlikeli madde geçmiş araştırması formu"],"explanation":"Vermont CDL sahipleri ve başvuru sahipleri, sürüş türlerini ve tıbbi durumlarını CDL Tıbbi Sertifikasyon formu VL-033'ü doldurup DMV'ye sunarak kendi beyanlarıyla bildirir. Kaynak: Vermont DMV, CDL Tıbbi Gereklilikler sayfası ve Form VL-033."},"85":{"q":"Vermont DMV'ye kendi beyanını sunarken, bir CDL başvuru sahibi kaç sürüş kategorisi arasından seçim yapabilir?","options":["Dört","İki","Üç","Beş"],"explanation":"Dört kendi beyan kategorisi vardır: Muafiyetsiz Eyaletlerarası (NI), Muafiyetli Eyaletlerarası (EI), Muafiyetsiz Eyalet İçi (NA) ve Muafiyetli Eyalet İçi (EA). Sürücü, Form VL-033'te birini seçer. Kaynak: Vermont DMV CDL Tıbbi Sertifikasyon (Form VL-033); 49 CFR 383.71."},"86":{"q":"Eyaletlerarası ticarette sürüş yapan ve federal fiziksel yeterlilik kurallarına (49 CFR Part 391) tabi olan bir Vermont CDL başvuru sahibi, kendi beyanını hangi kategoride yapmalıdır?","options":["Muafiyetsiz Eyaletlerarası (NI)","Muafiyetli Eyaletlerarası (EI)","Muafiyetsiz Eyalet İçi (NA)","Muafiyetli Eyalet İçi (EA)"],"explanation":"Eyaletlerarası ticarette faaliyet gösteren ve 49 CFR Part 391'e tabi olan bir sürücü, kendi beyanını Muafiyetsiz Eyaletlerarası (NI) olarak yapar ve güncel bir Tıbbi Muayene Sertifikası sunmalıdır. Kaynak: Vermont DMV Form VL-033; 49 CFR 383.71."},"87":{"q":"Vermont'ta hangi kendi beyan kategorisi, sürücünün güncel bir 'Yalnızca Vermont' Tıbbi Muayene Sertifikası sunmasını gerektirir?","options":["Muafiyetsiz Eyalet İçi (NA)","Muafiyetsiz Eyaletlerarası (NI)","Muafiyetli Eyaletlerarası (EI)","Muafiyetli Eyalet İçi (EA)"],"explanation":"Bir Muafiyetsiz Eyalet İçi (NA) sürücüsü yalnızca Vermont içinde faaliyet gösterir ve güncel bir 'Yalnızca Vermont' Tıbbi Muayene Sertifikası sunarak tıbbi standartları karşılamalıdır. Kaynak: Vermont DMV CDL Tıbbi Sertifikasyon (Form VL-033)."},"88":{"q":"Vermont'ta kabul edilen bir CDL Tıbbi Muayene Sertifikası üreten DOT fiziksel muayenesini yapmaya kim yetkilidir?","options":["FMCSA Ulusal Sertifikalı Tıbbi Muayene Uzmanları Sicili'nde kayıtlı bir tıbbi muayene uzmanı","Sürücünün seçtiği herhangi bir lisanslı hekim","Sınav merkezindeki bir Vermont DMV sınav görevlisi","Sürücünün işvereninin güvenlik görevlisi"],"explanation":"Fiziksel muayene, FMCSA Ulusal Sertifikalı Tıbbi Muayene Uzmanları Sicili'nde kayıtlı bir tıbbi muayene uzmanı tarafından yapılmalıdır. Kaynak: Vermont DMV, CDL Tıbbi Gereklilikler sayfası; 49 CFR 390.103 / Part 391."},"89":{"q":"Bir Vermont CDL sahibi için standart bir DOT Tıbbi Muayene Sertifikası en fazla ne kadar süre geçerli olabilir?","options":["2 yıla kadar","1 yıla kadar","3 yıla kadar","5 yıla kadar"],"explanation":"Standart bir Tıbbi Muayene Sertifikası 2 yıla kadar geçerlidir; ancak bir durumun izlenmesi gerekiyorsa muayene uzmanı daha kısa bir süre için de sertifika verebilir. Kaynak: Vermont DMV, CDL Tıbbi Gereklilikler sayfası; 49 CFR Part 391."},"90":{"q":"Bir Vermont CDL sahibi, DMV'de dosyada güncel bir tıbbi sertifika bulundurmazsa CDL'ye ne olabilir?","options":["CDL düşürülebilir ya da sürüş ayrıcalığı askıya alınabilir","Belgenin kendisi süresi dolmadığı sürece hiçbir şey olmaz","Sürücüye otomatik olarak Muafiyetli Eyaletlerarası statüsü verilir","Yalnızca yazılı bir uyarı postalanır ve belgeye hiçbir etkisi olmaz"],"explanation":"Güncel tıbbi belgeler dosyada bulundurulmazsa, Vermont DMV CDL'yi düşürebilir (ticari ayrıcalıkları kaldırabilir) ve/veya sürüş ayrıcalığını askıya alabilir. Kaynak: Vermont DMV, CDL Tıbbi Gereklilikler sayfası; 49 CFR 383.73."},"91":{"q":"İlk kez Sınıf A veya Sınıf B CDL'ye başvuran bir kişinin, Vermont beceri sınavına girmesine izin verilmeden önce hangi eğitimi tamamlaması gerekir?","options":["FMCSA'ya kayıtlı bir sağlayıcıdan Giriş Düzeyi Sürücü Eğitimi (ELDT)","Vermont DMV tarafından onaylanmış bir defansif sürüş kursu","DMV tarafından verilen sekiz saatlik bir sınıf içi kurs","Yalnızca işverenle kayıt altına alınan bir çıraklık"],"explanation":"İlk kez Sınıf A/B'ye başvuranlar (ve belirli onaylar), CDL beceri sınavına girmeden önce FMCSA Eğitim Sağlayıcı Sicili'ndeki bir sağlayıcıdan Giriş Düzeyi Sürücü Eğitimi (ELDT) tamamlamalıdır. Kaynak: Vermont DMV CDL sayfaları; 49 CFR Part 380 Subpart F."},"92":{"q":"İlk kez alınan bir HazMat (H) onayı için, gerekli Giriş Düzeyi Sürücü Eğitimi ne zaman tamamlanmalıdır?","options":["HazMat bilgi sınavına girmeden önce","Yalnızca yol üzerinde beceri sınavından önce","Belge verildikten sonra 30 gün içinde","Yalnızca TSA geçmiş araştırması onaylandıktan sonra"],"explanation":"HazMat onayının beceri sınavı olmadığından, ilk kez alınan bir H onayı için ELDT, başvuru sahibi HazMat bilgi sınavına girmeden önce tamamlanmalıdır. Kaynak: Vermont DMV CDL sayfaları; 49 CFR Part 380 Subpart F."},"93":{"q":"Sınıf ya da onay ne olursa olsun her Vermont CDL başvuru sahibinin geçmesi gereken bilgi sınavı hangisidir?","options":["Genel Bilgi sınavı","Hava Frenleri sınavı","Kombinasyon Araçları sınavı","Tehlikeli Maddeler sınavı"],"explanation":"Her CDL başvuru sahibi Genel Bilgi yazılı sınavını geçmelidir; Hava Frenleri, Kombinasyon Araçları ve onay sınavları gibi ek sınavlar yalnızca araca ya da onaya ilgili olduğu ölçüde geçerlidir. Kaynak: Vermont CDL Sürücü El Kitabı (VN-111); Vermont DMV CDL sayfaları."},"94":{"q":"Bir Vermont CDL bilgi (yazılı) sınavını geçmek için gereken asgari puan nedir?","options":["Yüzde 80","Yüzde 70","Yüzde 75","Yüzde 90"],"explanation":"Vermont CDL bilgi sınavları, soruların en az yüzde 80'inin doğru yanıtlanması şeklinde geçer not gerektirir. Kaynak: Vermont CDL Sürücü El Kitabı (VN-111); Vermont DMV CDL sınav bilgileri."},"95":{"q":"Bir Vermont CDL hangi yöntemle yenilenmelidir?","options":["Bir Vermont DMV ofisinde şahsen","Yalnızca DMV web sitesi üzerinden çevrimiçi","Yalnızca yenileme bildirimini kullanarak posta yoluyla","Sürücünün hiçbir işlem yapmasına gerek kalmadan otomatik olarak"],"explanation":"Bir CDL, bir Vermont DMV müşteri hizmetleri ofisinde şahsen yenilenmelidir; sürücü imzalı yenileme bildirimini ve ücreti getirir. Kaynak: Vermont DMV, Yenileme, Devir ve Yükseltme sayfası."},"96":{"q":"Bir Vermont CDL, her seferinde kaç yıllığına yenilenebilir?","options":["İki ya da dört yıl","Bir ya da iki yıl","Beş yıl","Sekiz yıl"],"explanation":"Vermont CDL yenilemeleri iki yıllık ya da dört yıllık bir döngüyle verilir; mevcut belgede kalan tam yıllar yenileme ücretine mahsup edilir. Kaynak: Vermont DMV, Yenileme, Devir ve Yükseltme sayfası."},"97":{"q":"Başka bir eyaletten geçerli bir CDL'ye sahip olup Vermont'a taşınan bir kişi, yerleşim kurduktan sonra ne kadar süre içinde bunu bir Vermont CDL'sine devretmelidir?","options":["30 gün","10 gün","60 gün","90 gün"],"explanation":"Eyalet ve federal yasa uyarınca, eyalet dışı bir CDL'ye sahip bir kişi, Vermont yerleşimi kurduktan sonra 30 gün içinde bunu bir Vermont CDL'sine devretmelidir. Kaynak: Vermont DMV, Yenileme, Devir ve Yükseltme sayfası; 49 CFR 383.71."},"98":{"q":"Mevcut bir Vermont CDL'sini daha yüksek bir sınıfa yükseltirken, sürücü bir izinle ilgili ne yapmalıdır?","options":["Bir Ticari Öğrenci İzni almalı ve bunu en az 14 gün elinde bulundurmalıdır","Hiçbir şey; mevcut CDL, yükseltme sınavına girmek için yeterlidir","Yalnızca normal bir sürücü öğrenci izni almalıdır","Yeni izni asgari 90 gün elinde bulundurmalıdır"],"explanation":"Daha yüksek bir CDL sınıfına yükseltmek için, sürücü bir Ticari Öğrenci İzni almalı, bunu en az 14 gün elinde bulundurmalı ve uygun bilgi ile beceri sınavlarını geçmelidir. Kaynak: Vermont DMV, Yenileme, Devir ve Yükseltme sayfası."},"99":{"q":"Vermont DMV, CDL başvuru sahiplerine yayımlanan belge ve sınav ücretlerini neden değişebilir olarak değerlendirmelerini önerir?","options":["Ücret tutarları, revize edilebilen yasa ve DMV cetvelleriyle belirlenir; bu nedenle güncel ilan edilen ücret her zaman teyit edilmelidir","Vermont CDL hizmetleri için hiçbir ücret almaz, dolayısıyla ilan edilen herhangi bir tutar bir hatadır","Ücretler her başvuru sahibi için gişede ayrı ayrı pazarlık edilir","CDL ücretlerini Vermont değil yalnızca federal hükûmet belirleyebilir ya da değiştirebilir"],"explanation":"CDL ve sınav ücretleri, güncellenebilen Vermont yasası ve DMV ücret cetvelleriyle belirlenir; bu nedenle başvuru sahipleri sabit bir tutara güvenmek yerine güncel tutarı DMV ile teyit etmelidir. Kaynak: Vermont DMV ücret bilgileri; 23 V.S.A. (motorlu taşıt ücreti yasaları)."}},"es":{"0":{"q":"¿Cuál es el ancho máximo legal de un vehículo en las carreteras de Vermont antes de que se requiera un permiso por sobreancho?","options":["8 pies (96 pulgadas)","8 pies 6 pulgadas (102 pulgadas)","9 pies (108 pulgadas)","8 pies 4 pulgadas (100 pulgadas)"],"explanation":"Conforme a 23 V.S.A. § 1431, el ancho máximo de un vehículo en Vermont es de 8 pies 6 pulgadas (102 pulgadas), sin contar los dispositivos de seguridad como los espejos que sobresalen hasta 3 pulgadas por lado. Cualquier cosa más ancha requiere un permiso por sobredimensión del DMV. Fuente: 23 V.S.A. § 1431."},"1":{"q":"¿Cuál es la altura máxima legal de un vehículo en las carreteras de Vermont sin un permiso?","options":["13 pies","14 pies","13 pies 6 pulgadas","12 pies 6 pulgadas"],"explanation":"23 V.S.A. § 1431 establece la altura máxima del vehículo en 13 pies 6 pulgadas. Las cargas que excedan esto requieren un permiso por sobredimensión del Vermont DMV. Fuente: 23 V.S.A. § 1431."},"2":{"q":"En Vermont, ¿cuál es la longitud total máxima de un vehículo automotor individual (sin remolque ni semirremolque acoplado) sin un permiso especial?","options":["40 pies","53 pies","46 pies","48 pies"],"explanation":"Conforme a 23 V.S.A. § 1432, ningún vehículo automotor sin remolque ni semirremolque acoplado que tenga más de 46 pies de longitud total puede circular por una carretera de Vermont salvo con permiso especial. Fuente: 23 V.S.A. § 1432."},"3":{"q":"¿Cuál es la longitud total máxima de una combinación de vehículos (camión con remolque o semirremolque) en una carretera general de Vermont sin un permiso por sobrelongitud?","options":["65 pies","75 pies","70 pies","80 pies"],"explanation":"Conforme a 23 V.S.A. § 1432, las combinaciones de vehículos que no excedan los 75 pies de longitud total pueden circular por las carreteras de Vermont sin un permiso; las combinaciones más largas requieren un permiso por sobrelongitud. Fuente: 23 V.S.A. § 1432."},"4":{"q":"En las carreteras Interestatales y de la Red Nacional designada de Vermont, ¿cuál es la longitud máxima de semirremolque permitida en una combinación de tractor-semirremolque?","options":["48 pies","53 pies","45 pies","57 pies"],"explanation":"En el sistema Interestatal y en las carreteras designadas que califican, Vermont aplica los límites federales de longitud por componente en lugar del tope de longitud total: el semirremolque en una combinación de tractor-semirremolque puede tener hasta 53 pies. Fuente: 23 V.S.A. § 1432."},"5":{"q":"Para una combinación de tractor-semirremolque-remolque (remolque doble) en la red de carreteras designada de Vermont, ¿cuál es la longitud máxima de cada remolque o semirremolque?","options":["28 pies cada uno","30 pies cada uno","27 pies cada uno","33 pies cada uno"],"explanation":"En la Interestatal y la red designada, las combinaciones de remolque doble se rigen por los límites federales por componente: cada remolque o semirremolque puede tener hasta 28 pies. Fuente: 23 V.S.A. § 1432 (en concordancia con los estándares federales STAA)."},"6":{"q":"¿Cuál es el peso bruto vehicular máximo en las carreteras de Vermont para un vehículo comercial estándar sin un permiso especial?","options":["73,280 libras","80,000 libras","90,000 libras","84,000 libras"],"explanation":"Conforme a 23 V.S.A. § 1392, el peso bruto vehicular máximo es de 80,000 libras. Las cargas más pesadas requieren un permiso por sobrepeso del DMV o una categoría de permiso especial establecida por ley. Fuente: 23 V.S.A. § 1392."},"7":{"q":"En el Sistema de Carreteras Interestatales federales en Vermont, ¿cuál es el peso máximo por eje simple, sin tolerancia permitida?","options":["22,400 libras","18,000 libras","20,000 libras","21,000 libras"],"explanation":"Conforme a 23 V.S.A. § 1391, en la Interestatal (Sistema Nacional de Carreteras Interestatales y de Defensa Eisenhower) el límite por eje simple es de 20,000 libras sin tolerancia permitida, igualando la ley federal. Fuente: 23 V.S.A. § 1391."},"8":{"q":"En el Sistema de Carreteras Interestatales en Vermont, ¿cuál es el peso máximo por eje tándem, sin tolerancia permitida?","options":["36,000 libras","34,000 libras","32,000 libras","38,000 libras"],"explanation":"Conforme a 23 V.S.A. § 1391, en el sistema Interestatal el límite por eje tándem es de 34,000 libras sin tolerancia permitida, en concordancia con los estándares federales de peso. Fuente: 23 V.S.A. § 1391."},"9":{"q":"En las carreteras no Interestatales (estatales y municipales) de Vermont, ¿cuál es el peso máximo por eje simple antes de aplicar la tolerancia del 10 por ciento?","options":["20,000 libras","24,000 libras","22,400 libras","21,500 libras"],"explanation":"Conforme a 23 V.S.A. § 1391, en las carreteras no Interestatales de Vermont el límite por eje simple es de 22,400 libras, con una tolerancia del 10 por ciento permitida. Fuente: 23 V.S.A. § 1391."},"10":{"q":"En las carreteras no Interestatales de Vermont, ¿cuál es el peso máximo por eje tándem antes de aplicar la tolerancia del 10 por ciento?","options":["34,000 libras","36,000 libras","32,000 libras","40,000 libras"],"explanation":"Conforme a 23 V.S.A. § 1391, en las carreteras no Interestatales de Vermont el límite por eje tándem es de 36,000 libras, con una tolerancia del 10 por ciento permitida (una diferencia clave específica del estado respecto al límite Interestatal de 34,000 libras). Fuente: 23 V.S.A. § 1391."},"11":{"q":"Una diferencia clave entre las reglas de peso por eje no Interestatales e Interestatales de Vermont es la tolerancia. ¿Qué tolerancia se aplica a los límites por eje simple y tándem en las carreteras no Interestatales de Vermont?","options":["No se permite ninguna tolerancia","Se permite una tolerancia del 5 por ciento","Se permite una tolerancia del 10 por ciento","Se permite una tolerancia del 15 por ciento"],"explanation":"Conforme a 23 V.S.A. § 1391, los límites no Interestatales por eje simple (22,400 lb) y por eje tándem (36,000 lb) tienen una tolerancia del 10 por ciento, mientras que los límites Interestatales (20,000 lb / 34,000 lb) no permiten ninguna tolerancia. Fuente: 23 V.S.A. § 1391."},"12":{"q":"¿Qué fórmula utiliza Vermont, en concordancia con la ley federal, para determinar el peso bruto máximo permitido para un grupo de ejes según su espaciamiento y número?","options":["La Fórmula Federal de Puentes (Fórmula B)","La fórmula de Calificación de Peso Bruto Combinado","El Índice de Espaciamiento de Tándem","La fórmula de Equivalencia de Carga por Eje"],"explanation":"Vermont aplica la Fórmula Federal de Puentes (Fórmula de Puentes B), W = 500[LN/(N-1) + 12N + 36], para limitar el peso que soporta cualquier grupo de ejes según el espaciamiento (L) y el número de ejes (N), además de los límites por eje simple, tándem y bruto de 80,000 lb. Fuente: Fórmula Federal de Puentes según se aplica conforme a 23 V.S.A. ch. 13 / FHWA."},"13":{"q":"En la Fórmula Federal de Puentes utilizada en Vermont, dos ejes consecutivos se tratan como un 'tándem' (en lugar de ejes simples separados) cuando sus centros están separados ¿a qué distancia?","options":["Más de 40 pulgadas pero no más de 96 pulgadas","Más de 96 pulgadas pero no más de 120 pulgadas","No más de 40 pulgadas","Más de 48 pulgadas pero no más de 108 pulgadas"],"explanation":"Conforme a las definiciones federales aplicadas en Vermont, un eje tándem son dos o más ejes consecutivos cuyos centros están separados más de 40 pulgadas pero no más de 96 pulgadas; los ejes separados 40 pulgadas o menos se tratan como un eje simple. Fuente: definiciones de la Fórmula Federal de Puentes / FHWA, aplicadas conforme a 23 V.S.A. ch. 13."},"14":{"q":"¿Cuándo necesita generalmente un operador de vehículos comerciales de Vermont un permiso por sobredimensión o sobrepeso del DMV?","options":["Solo al cruzar a otro estado","Cuando el vehículo o la carga exceden los límites legales de ancho, altura, longitud o peso","Solo cuando el peso bruto excede las 100,000 libras","Solo de noche o en condiciones invernales"],"explanation":"Se requiere un permiso por sobredimensión/sobrepeso del Vermont DMV siempre que un vehículo o carga exceda los límites legales (ancho mayor a 8'6\", altura mayor a 13'6\", vehículo individual mayor a 46 pies, combinación mayor a 75 pies, o los límites de peso aplicables). Fuente: 23 V.S.A. ch. 13 y las Reglas de Permisos por Sobrepeso/Sobredimensión del Vermont DMV (Code Vt. R. 14-050-019)."},"15":{"q":"¿Qué agencia de Vermont emite los permisos por sobredimensión y sobrepeso para circular por las carreteras estatales y el sistema Interestatal?","options":["La Agencia de Recursos Naturales de Vermont","La Administración Federal de Seguridad de Autotransportes (FMCSA)","El Departamento de Vehículos Motorizados de Vermont (Operaciones de Vehículos Comerciales)","El departamento del sheriff del condado"],"explanation":"El Vermont DMV, a través de su unidad de Operaciones de Vehículos Comerciales (y el sistema en línea VT Haul Pass), emite los permisos por sobredimensión y sobrepeso para las carreteras estatales y el sistema Interestatal bajo la autoridad del Comisionado. Fuente: Reglas de Permisos por Sobrepeso/Sobredimensión del CVO del Vermont DMV; 23 V.S.A. § 1400."},"16":{"q":"Una empresa de transporte necesita mover cargas indivisibles de gran tamaño repetidamente por las mismas rutas durante todo el año. ¿Qué tipo de permiso de Vermont se ajusta mejor a esta necesidad?","options":["Un permiso de viaje único","Un permiso de emergencia","Un permiso general (anual)","Un permiso solo de registro"],"explanation":"El Vermont DMV emite permisos generales (anuales) para movimientos recurrentes de cargas indivisibles, mientras que los permisos de viaje único cubren un solo movimiento dentro de un período limitado (aproximadamente siete días hábiles). Fuente: Reglas de Permisos por Sobrepeso/Sobredimensión del Vermont DMV (Code Vt. R. 14-050-019)."},"17":{"q":"Para el peso que exceda los límites legales en carreteras y puentes bajo la jurisdicción de un municipio (que no sean carreteras municipales de Clase 1), ¿a quién debe presentarse una solicitud de permiso por sobrepeso de Vermont?","options":["Al Comisionado del Vermont DMV","Al cuerpo legislativo correspondiente del municipio (por ejemplo, el selectboard)","A la Administración Federal de Carreteras","A la Policía Estatal de Vermont"],"explanation":"Conforme a las reglas de permisos de Vermont, para circular excediendo los límites de peso en carreteras y puentes bajo la jurisdicción de un municipio (salvo las carreteras municipales de Clase 1), la solicitud se presenta ante el cuerpo legislativo municipal correspondiente. Fuente: Code Vt. R. 14-050-019 (Permisos para Vehículos con Sobrepeso/Sobredimensión)."},"18":{"q":"El Permiso Especial de Exceso de Peso de Vermont (un permiso anual para cargas divisibles) permite ¿qué peso máximo en el eje de dirección?","options":["10,000 libras","12,000 libras","14,000 libras","20,000 libras"],"explanation":"Conforme a la regla del Permiso Especial de Exceso de Peso de Vermont, los límites por eje son de 12,000 libras en el eje de dirección y 20,000 libras en todos los demás ejes. Fuente: Permiso Especial de Exceso de Peso del Vermont DMV; Code Vt. R. 14-050-019."},"19":{"q":"La ley de Vermont permite que ciertas combinaciones de camiones de seis o más ejes que operan bajo un permiso especial anual alcancen ¿qué peso bruto elevado en carreteras no Interestatales?","options":["85,000 libras","108,000 libras","99,000 libras","95,000 libras"],"explanation":"Conforme a 23 V.S.A. § 1392, los camiones con seis o más ejes portantes de carga que operan bajo un permiso especial anual pueden alcanzar 99,000 libras de peso bruto en carreteras no Interestatales; esta autorización específica de Vermont no se aplica al sistema Interestatal a menos que lo permita la ley federal. Fuente: 23 V.S.A. § 1392."},"20":{"q":"En Vermont, ¿se requiere una CDL Clase A para operar cuál de las siguientes opciones?","options":["Cualquier combinación de vehículos con un GCWR de 26,001 lbs o más, donde la unidad o unidades remolcadas excedan los 10,000 lbs de GVWR","Cualquier vehículo individual con un GVWR de 26,001 lbs o más","Cualquier vehículo diseñado para transportar 16 o más pasajeros incluyendo al conductor","Cualquier vehículo de cualquier peso que muestre carteles de materiales peligrosos"],"explanation":"Vermont sigue la clasificación federal de CDL (49 CFR 383.91): la Clase A es cualquier combinación de vehículos con un GCWR de 26,001 lbs o más, siempre que el vehículo o vehículos remolcados tengan un GVWR superior a 10,000 lbs. Fuente: Manual CDL de Vermont (VN-111) / FMCSA 49 CFR 383.91."},"21":{"q":"Conforme a las reglas de Vermont, ¿qué vehículos cubre una CDL Clase B?","options":["Solo autobuses que transportan menos de 16 pasajeros","Cualquier vehículo individual con un GVWR de 26,001 lbs o más, o dicho vehículo remolcando una unidad que no exceda los 10,000 lbs","Cualquier combinación donde el remolque exceda los 10,000 lbs de GVWR","Cualquier vehículo que requiera únicamente un endoso de materiales peligrosos"],"explanation":"Vermont adopta la definición federal: la Clase B es cualquier vehículo individual con un GVWR de 26,001 lbs o más, o dicho vehículo remolcando otro vehículo que no exceda los 10,000 lbs de GVWR. Fuente: Manual CDL de Vermont (VN-111) / FMCSA 49 CFR 383.91."},"22":{"q":"Se requiere una CDL Clase C de Vermont cuando un vehículo no cumple con las definiciones de peso de Clase A o B pero está diseñado para transportar al menos ¿cuántos pasajeros (incluyendo al conductor), o transporta materiales peligrosos con carteles?","options":["10 pasajeros","12 pasajeros","16 pasajeros","24 pasajeros"],"explanation":"La Clase C de Vermont se aplica a un vehículo (que no cumple con el Grupo A o B) diseñado para transportar 16 o más pasajeros incluyendo al conductor, o que se utiliza para transportar materiales peligrosos con carteles. Fuente: Manual CDL de Vermont (VN-111) / FMCSA 49 CFR 383.91."},"23":{"q":"¿Qué endoso necesita un titular de una CDL de Vermont para conducir un vehículo que transporta cantidades con cartel de materiales peligrosos?","options":["Endoso N","Endoso H","Endoso T","Endoso X"],"explanation":"El endoso H (HazMat) autoriza el transporte de materiales peligrosos en cantidades que requieren cartel. (El código X significa Tanque y HazMat combinados.) Fuente: página de Endosos HazMat del Vermont DMV / Manual CDL de Vermont (VN-111)."},"24":{"q":"¿Cuál es la edad mínima para obtener una CDL de Vermont restringida únicamente al comercio intraestatal (dentro de Vermont)?","options":["16 años","17 años","18 años","21 años"],"explanation":"Vermont exige que un solicitante tenga al menos 18 años para obtener una CDL y operar un vehículo motorizado comercial en el comercio intraestatal. Fuente: página de Licencia de Conducir Comercial del Vermont DMV."},"25":{"q":"¿Cuál es la edad mínima para operar un vehículo motorizado comercial en el comercio interestatal con una CDL de Vermont?","options":["18 años","19 años","20 años","21 años"],"explanation":"Un conductor debe tener al menos 21 años para operar un vehículo motorizado comercial en el comercio interestatal, en concordancia con la regla federal. Fuente: página de Licencia de Conducir Comercial del Vermont DMV / FMCSA 49 CFR 391.11."},"26":{"q":"Antes de programar el examen de habilidades de la CDL, la ley federal (aplicada en Vermont) exige que el solicitante mantenga el Permiso de Aprendiz Comercial (CLP) durante un mínimo de ¿cuántos días?","options":["7 días","14 días","30 días","60 días"],"explanation":"Un solicitante debe mantener el CLP durante al menos 14 días antes de tomar el examen de habilidades de la CDL. Fuente: página del CLP del Vermont DMV / FMCSA 49 CFR 383.25."},"27":{"q":"Para solicitar un Permiso de Aprendiz Comercial (CLP) de Vermont, un solicitante ya debe tener ¿qué?","options":["Una licencia de conducir Clase D (regular) de Vermont válida","Un endoso de motocicleta válido","Una tarjeta TWIC federal","Una licencia de operador juvenil"],"explanation":"Vermont exige que los solicitantes del CLP tengan una licencia de operador Clase D de Vermont válida. Fuente: página del Permiso de Aprendiz de Conductor Comercial del Vermont DMV."},"28":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Vermont a partir de su fecha de emisión?","options":["90 días","6 meses","1 año","2 años"],"explanation":"Un CLP de Vermont es válido por un año (12 meses) a partir de la fecha de emisión. Fuente: página del Permiso de Aprendiz de Conductor Comercial del Vermont DMV / FMCSA 49 CFR 383.25."},"29":{"q":"Mientras conduce en carreteras públicas, el titular de un CLP de Vermont debe estar acompañado por una persona que:","options":["Tenga cualquier licencia de conducir de Vermont válida","Tenga una CDL válida para la clase de vehículo que se conduce, incluyendo los endosos requeridos","Tenga al menos 25 años","Sea un examinador certificado del DMV"],"explanation":"El titular de un CLP debe estar acompañado, sentado a su lado, por una persona que tenga una CDL válida para el tipo de vehículo que se conduce, con los endosos correspondientes. Fuente: página del CLP del Vermont DMV / FMCSA 49 CFR 383.25."},"30":{"q":"¿Qué endoso se requiere para operar un vehículo cisterna que transporta líquidos o gases a granel en Vermont?","options":["Endoso T","Endoso P","Endoso N","Endoso S"],"explanation":"El endoso N (Vehículo Cisterna) se requiere para transportar líquidos/gases a granel en tanques. Fuente: Manual CDL de Vermont (VN-111) / FMCSA 49 CFR 383.93."},"31":{"q":"Un vehículo cisterna que requiere el endoso N es generalmente uno que transporta líquido o gas en un tanque con una capacidad nominal individual superior a 119 galones y una capacidad nominal agregada de al menos ¿cuántos galones?","options":["500 galones","1,000 galones","1,500 galones","3,000 galones"],"explanation":"El endoso N se aplica a tanques con una capacidad nominal individual superior a 119 galones y una capacidad nominal agregada de 1,000 galones o más de líquido o gas. Fuente: Manual CDL de Vermont (VN-111) / FMCSA 49 CFR 383.5."},"32":{"q":"¿Qué endoso necesita un conductor de Vermont para operar remolques dobles o triples?","options":["Endoso T","Endoso N","Endoso D","Endoso X"],"explanation":"El endoso T autoriza la operación de remolques dobles y triples y requiere aprobar únicamente un examen de conocimientos. Fuente: Manual CDL de Vermont (VN-111) / FMCSA 49 CFR 383.93."},"33":{"q":"Para transportar pasajeros (por ejemplo, en un autobús de transporte público o de alquiler) en Vermont, ¿qué endoso se requiere?","options":["Endoso S","Endoso P","Endoso N","Endoso H"],"explanation":"El endoso P (Pasajeros) se requiere para operar un vehículo diseñado para transportar pasajeros por encima del umbral de la CDL; requiere un examen de conocimientos y un examen de habilidades en un vehículo de pasajeros. Fuente: Manual CDL de Vermont (VN-111) / FMCSA 49 CFR 383.93."},"34":{"q":"En Vermont, un conductor que opera un autobús escolar que transporta estudiantes debe tener el endoso P más ¿qué endoso adicional?","options":["Endoso H","Endoso T","Endoso S","Endoso N"],"explanation":"Los conductores de autobús escolar necesitan el endoso S (Autobús Escolar) además del endoso P. El endoso S requiere exámenes de conocimientos y de habilidades sobre las operaciones de autobús escolar. Fuente: páginas de Autobús Escolar del Vermont DMV / FMCSA 49 CFR 383.93."},"35":{"q":"¿Cuál es la edad mínima para obtener un endoso HazMat (H) en una CDL de Vermont?","options":["18 años","19 años","21 años","25 años"],"explanation":"Dado que el transporte de materiales peligrosos requiere una calificación de nivel interestatal y una autorización de seguridad federal, el endoso HazMat exige que el solicitante tenga al menos 21 años. Fuente: página de Endosos HazMat del Vermont DMV."},"36":{"q":"Antes de que Vermont pueda emitir o renovar un endoso HazMat (H), el solicitante debe aprobar ¿qué evaluación adicional?","options":["Una verificación de antecedentes de la Administración de Seguridad en el Transporte (TSA) con toma de huellas dactilares","Un examen de especialista en visión del estado","Una certificación de examen de manejo del empleador","Una revisión de servicio de la Guardia Nacional"],"explanation":"Conforme a la Ley USA PATRIOT, el endoso HazMat requiere una evaluación de amenazas a la seguridad de la TSA, que incluye la toma de huellas dactilares y una verificación de antecedentes, antes de su emisión o renovación. Fuente: página de Endosos HazMat del Vermont DMV / 49 CFR 1572."},"37":{"q":"Conforme a las reglas ELDT aplicadas en Vermont, ¿dónde debe un solicitante de Clase A por primera vez completar la capacitación requerida para conductores de nivel inicial?","options":["Cualquier colegio comunitario, sin importar si está registrado","Un proveedor que figure en el Registro de Proveedores de Capacitación (TPR) de la FMCSA","Solo en la oficina de capacitación del Vermont DMV","Cualquier programa administrado por un empleador a elección del conductor"],"explanation":"A partir del 7 de febrero de 2022, la ELDT (teórica y práctica al volante) debe completarse con un proveedor que figure en el Registro de Proveedores de Capacitación de la FMCSA antes del examen de habilidades. Fuente: regla ELDT de la FMCSA (49 CFR Part 380) / páginas de Capacitación CDL del Vermont DMV."},"38":{"q":"¿Cuál de estos NO requiere la ELDT (Capacitación para Conductores de Nivel Inicial) antes del examen?","options":["Solicitantes de CDL Clase A o Clase B por primera vez","Conductores que buscan un endoso H (HazMat) por primera vez","Conductores que ascienden de Clase B a Clase A","Conductores que ya tenían el endoso antes del 7 de febrero de 2022"],"explanation":"La ELDT no es retroactiva: los conductores a quienes se les emitió la CDL o el endoso S/P/H antes del 7 de febrero de 2022 no están obligados a completar la ELDT. Sí se aplica a los solicitantes de Clase A/B por primera vez, ascensos de B a A, y endosos S, P y H por primera vez. Fuente: regla ELDT de la FMCSA (49 CFR Part 380)."},"39":{"q":"¿Qué conjunto describe mejor las categorías de autocertificación médica entre las que debe elegir un solicitante de CDL de Vermont?","options":["Comercial, Privada, Agrícola y Recreativa","Interestatal no exenta, Interestatal exenta, Intraestatal no exenta e Intraestatal exenta","Médica Clase A, Médica Clase B, Médica Clase C y Exenta","Federal, Estatal, Local y Tribal"],"explanation":"Los solicitantes de CDL se autocertifican en una de cuatro categorías: interestatal no exenta, interestatal exenta, intraestatal no exenta o intraestatal exenta. Los conductores no exentos deben mantener un certificado válido de examinador médico. Fuente: autocertificación médica de CDL del Vermont DMV / FMCSA 49 CFR 383.71."},"40":{"q":"Al operar un vehículo motorizado comercial (CMV) en Vermont, ¿cuál es la concentración máxima legal de alcohol en sangre (BAC) antes de que se considere que el conductor opera con un nivel de alcohol prohibido?","options":["0.04 por ciento","0.08 por ciento","0.02 por ciento","0.10 por ciento"],"explanation":"La ley de Vermont prohíbe operar un CMV con un BAC de 0.04 por ciento o más, la mitad del límite de 0.08 para vehículos comunes. Fuente: 23 V.S.A. § 4116; Manual CDL de Vermont § 1.2.2."},"41":{"q":"En Vermont, un titular de una CDL que es condenado por una PRIMERA infracción grave (como conducir un CMV con un BAC de 0.04 o más) queda descalificado para operar un CMV durante al menos ¿cuánto tiempo?","options":["1 año","60 días","6 meses","3 años"],"explanation":"Una primera infracción grave descalifica al conductor para operar un CMV durante un año. Fuente: 23 V.S.A. § 4116; Manual CDL de Vermont § 1.2.2 (estándar federal 49 CFR 383.51 adoptado por Vermont)."},"42":{"q":"Conforme a la ley de Vermont, al operar un vehículo motorizado comercial, ¿qué se considera que ha hecho un conductor respecto a las pruebas químicas para detectar alcohol?","options":["Dado su consentimiento para pruebas de alcohol","Renunciado al derecho a una audiencia de CDL","Aceptado una multa fija de $500","Aceptado la incautación del vehículo por 30 días"],"explanation":"La regla de consentimiento implícito de Vermont establece que cualquier persona que opere un CMV se considera que ha dado su consentimiento para las pruebas de alcohol. Fuente: Manual CDL de Vermont § 1.2.2; 23 V.S.A. §§ 1202, 4116."},"43":{"q":"Si un titular de una CDL de Vermont es condenado por una primera infracción grave mientras transporta materiales peligrosos que requieren carteles, el período de descalificación del CMV se incrementa a al menos ¿cuánto tiempo?","options":["3 años","1 año","18 meses","5 años"],"explanation":"Una primera infracción grave cometida mientras se transportan materiales peligrosos con cartel eleva la descalificación de uno a tres años. Fuente: 23 V.S.A. § 4116; 49 CFR 383.51 Tabla 1 según adoptada por Vermont."},"44":{"q":"En Vermont, ¿cuál es el período de descalificación por una SEGUNDA infracción grave cometida en un CMV (por ejemplo, una segunda infracción relacionada con el alcohol en un incidente distinto)?","options":["Descalificación de por vida","3 años","10 años","5 años"],"explanation":"Dos infracciones graves que surjan de incidentes distintos resultan en una descalificación de por vida del CMV. Fuente: 23 V.S.A. § 4116; Manual CDL de Vermont § 1.2.2."},"45":{"q":"Un conductor de CMV de Vermont que se niega a someterse a las pruebas requeridas de alcohol en sangre, ¿qué consecuencia para la CDL enfrenta por esa negativa?","options":["Al menos una descalificación de la CDL de 1 año","Una advertencia sin descalificación","Una descalificación de la CDL de 30 días","Solo una multa civil de $250"],"explanation":"Negarse a someterse a las pruebas de alcohol se trata como una infracción grave, conllevando una descalificación mínima del CMV de un año (tres años si transporta materiales peligrosos con cartel). Fuente: 23 V.S.A. § 4116; Manual CDL de Vermont § 1.2.2."},"46":{"q":"¿Por cuánto tiempo se pone fuera de servicio a un conductor de CMV de Vermont si se determina que tiene cualquier cantidad detectable de alcohol que aún esté POR DEBAJO del 0.04 por ciento?","options":["24 horas","1 hora","72 horas","30 días"],"explanation":"Un conductor de CMV con cualquier cantidad medible de alcohol por debajo de 0.04 se pone fuera de servicio por 24 horas. Fuente: Manual CDL de Vermont § 1.2.2; 49 CFR 392.5."},"47":{"q":"En Vermont, ser condenado por cuántas infracciones de tránsito GRAVES dentro de un período de tres años desencadena una descalificación del CMV de 60 días?","options":["2 infracciones graves","3 infracciones graves","4 infracciones graves","1 infracción grave"],"explanation":"Dos infracciones de tránsito graves dentro de tres años (incidentes distintos) resultan en una descalificación del CMV de 60 días. Fuente: 23 V.S.A. § 4116; Manual CDL de Vermont § 1.2.3."},"48":{"q":"Un titular de una CDL de Vermont condenado por TRES infracciones de tránsito graves dentro de un período de tres años queda descalificado para operar un CMV durante al menos ¿cuánto tiempo?","options":["120 días","60 días","180 días","1 año"],"explanation":"Tres infracciones de tránsito graves dentro de tres años conllevan una descalificación del CMV de 120 días. Fuente: 23 V.S.A. § 4116; Manual CDL de Vermont § 1.2.3."},"49":{"q":"Conforme a las reglas de CDL de Vermont, el exceso de velocidad es una infracción de tránsito GRAVE cuando el conductor supera el límite establecido por ¿cuánto?","options":["15 mph o más","10 mph o más","20 mph o más","5 mph o más"],"explanation":"El exceso de velocidad de 15 mph o más por encima del límite establecido es una infracción de tránsito grave. Fuente: Manual CDL de Vermont § 1.2.3; 49 CFR 383.51 Tabla 2."},"50":{"q":"¿Cuál de las siguientes se clasifica como una infracción de tránsito GRAVE para un titular de una CDL de Vermont?","options":["Seguir demasiado de cerca al vehículo de adelante","Estacionarse en una zona de no estacionar","Una calcomanía de registro vencida","Una luz de posición quemada"],"explanation":"Seguir demasiado de cerca es una de las infracciones de tránsito graves enumeradas, junto con el exceso de velocidad, la conducción temeraria y los cambios de carril indebidos o erráticos. Fuente: Manual CDL de Vermont § 1.2.3; 49 CFR 383.51 Tabla 2."},"51":{"q":"En Vermont, ¿cuál es el período de descalificación del CMV por una PRIMERA condena de una infracción en un cruce a nivel entre ferrocarril y carretera?","options":["Al menos 60 días","Al menos 120 días","Al menos 30 días","Al menos 1 año"],"explanation":"Una primera infracción en un cruce a nivel entre ferrocarril y carretera resulta en al menos una descalificación de 60 días. Fuente: 23 V.S.A. § 4116; Manual CDL de Vermont § 1.2.5."},"52":{"q":"Un conductor de CMV de Vermont comete una TERCERA infracción en un cruce a nivel entre ferrocarril y carretera dentro de un período de tres años. La descalificación mínima es:","options":["1 año","120 días","60 días","6 meses"],"explanation":"Una tercera infracción en un cruce a nivel entre ferrocarril y carretera dentro de tres años conlleva al menos una descalificación de un año (60 días la primera, 120 días la segunda, un año la tercera). Fuente: 23 V.S.A. § 4116; Manual CDL de Vermont § 1.2.5."},"53":{"q":"¿Qué acción es una infracción en un cruce a nivel entre ferrocarril y carretera que puede descalificar a un titular de una CDL de Vermont?","options":["No tener suficiente espacio para conducir completamente a través del cruce sin detenerse","Tocar la bocina antes de cruzar las vías","Cruzar a una velocidad inferior a 10 mph","Detenerse a más de 50 pies antes de las vías"],"explanation":"No tener suficiente espacio para despejar el cruce sin detenerse es una de las seis infracciones de cruce a nivel. Fuente: Manual CDL de Vermont § 1.2.5; 49 CFR 383.51 Tabla 3."},"54":{"q":"En Vermont, ¿cuál es la descalificación mínima del CMV por una PRIMERA condena por violar una orden de fuera de servicio (que no involucre materiales peligrosos ni pasajeros)?","options":["180 días","90 días","30 días","1 año"],"explanation":"Una primera violación de una orden de fuera de servicio descalifica al conductor por no menos de 180 días (hasta un año). Fuente: 23 V.S.A. § 4116; 49 CFR 383.51 Tabla 4 según adoptada por Vermont."},"55":{"q":"Un titular de una CDL de Vermont es condenado por una SEGUNDA violación de una orden de fuera de servicio dentro de un período de 10 años. El período de descalificación es:","options":["2 años","1 año","180 días","5 años"],"explanation":"Una segunda violación de una orden de fuera de servicio en 10 años (incidentes distintos) conlleva una descalificación de dos años. Fuente: 23 V.S.A. § 4116; 49 CFR 383.51 Tabla 4."},"56":{"q":"¿Cuál es el período de descalificación del CMV en Vermont por una TERCERA o subsiguiente violación de una orden de fuera de servicio dentro de un período de 10 años?","options":["3 años","2 años","1 año","De por vida"],"explanation":"Una tercera o subsiguiente violación de una orden de fuera de servicio en 10 años resulta en una descalificación de tres años. Fuente: 23 V.S.A. § 4116; 49 CFR 383.51 Tabla 4."},"57":{"q":"Conforme a la ley de CDL de Vermont, usar un teléfono móvil de mano mientras se conduce un CMV se describe mejor como:","options":["Un acto prohibido que cuenta como una infracción de tránsito grave","Permitido si la llamada dura menos de un minuto","Permitido solo en carreteras interestatales","Una infracción sin movimiento sin impacto en la CDL"],"explanation":"Vermont prohíbe enviar mensajes de texto y usar el teléfono de mano mientras se conduce un CMV; tales condenas cuentan como infracciones de tránsito graves para efectos de la descalificación. Fuente: 23 V.S.A. § 4125; 49 CFR 383.51 Tabla 2."},"58":{"q":"¿Cuándo se permite enviar mensajes de texto o usar el teléfono de mano mientras se opera un CMV en Vermont?","options":["Cuando sea necesario para contactar a las fuerzas del orden o a los servicios de emergencia","Cuando se está detenido en un semáforo en rojo","Cuando se viaja a menos de 25 mph","Cuando la carga no es peligrosa"],"explanation":"La única excepción a la prohibición de mensajes de texto/teléfono de mano es la comunicación con funcionarios de las fuerzas del orden u otros servicios de emergencia. Fuente: 23 V.S.A. § 4125."},"59":{"q":"Un titular de una CDL de Vermont descalificado DE POR VIDA por dos infracciones graves puede solicitar que se le restablezcan los privilegios de conducción comercial solo después de haber estado descalificado durante al menos ¿cuánto tiempo, y tras completar cualquier rehabilitación requerida?","options":["10 años","5 años","7 años","15 años"],"explanation":"Una descalificación de la CDL de por vida puede reducirse después de al menos 10 años si el conductor completa un programa de rehabilitación aprobado y cumple con los requisitos de declaración jurada. Fuente: Code of Vermont Rules 14-050-044 (Reducción de la Descalificación de por Vida); 49 CFR 383.51."},"60":{"q":"Según la ley \"Move Over\" (Cámbiate de Carril) de Vermont, cuando un vehículo policial o de emergencia se aproxima con la sirena sonando o las luces de señalización encendidas, ¿qué debe hacer el conductor de cualquier otro vehículo?","options":["Continuar normalmente siempre que el vehículo de emergencia esté en un carril diferente","Orillarse a la derecha del carril de circulación y detenerse por completo hasta que el vehículo haya pasado","Moverse solo un carril hacia la izquierda y mantener la velocidad","Reducir a 20 mph por debajo del límite indicado y continuar en el mismo carril"],"explanation":"23 V.S.A. § 1050(a) exige que, ante la aproximación de un vehículo de las fuerzas del orden, ambulancia, bomberos o rescate que haga sonar una sirena o muestre su luz de señalización, todos los demás vehículos \"deben orillarse a la derecha del carril de circulación y detenerse por completo hasta que el vehículo policial o de emergencia haya pasado\". Fuente: 23 V.S.A. § 1050(a)."},"61":{"q":"En una carretera de Vermont de varios carriles, ¿qué exige la ley \"Move Over\" a un conductor que se aproxima a un vehículo de emergencia o de remolque DETENIDO que tiene encendidas sus luces de advertencia?","options":["Reducir la velocidad a exactamente 25 mph sin importar las condiciones","Detenerse solo si el vehículo detenido es una patrulla policial, no una grúa","Detenerse siempre por completo en el carril de circulación hasta que se le indique avanzar","Cambiarse a un carril más alejado si las condiciones de seguridad lo permiten; de lo contrario, reducir a una velocidad razonable, segura y prudente"],"explanation":"23 V.S.A. § 1050(b) indica que un conductor que se aproxima a un vehículo de emergencia detenido (o a un vehículo de remolque/reparación que muestre una luz ámbar) debe proceder con precaución y, si está en una carretera de varios carriles y la seguridad lo permite, cambiarse a un carril más alejado del vehículo detenido; si no es posible cambiar de carril, el conductor debe reducir a una \"velocidad razonable, segura y prudente\". Fuente: 23 V.S.A. § 1050(b)."},"62":{"q":"La regla \"Move Over\" de Vermont para vehículos detenidos aplica a un vehículo de remolque y reparación detenido cuando muestra una luz de señalización de qué color?","options":["Azul","Rojo y blanco","Verde","Ámbar"],"explanation":"23 V.S.A. § 1050(b) extiende el deber de cambiarse de carril o reducir la velocidad a un \"vehículo de remolque y reparación detenido que muestre una luz de señalización ámbar\", además de los vehículos policiales (azul) y de ambulancia/bomberos/rescate (rojo). Fuente: 23 V.S.A. § 1050(b)."},"63":{"q":"Cuando un autobús escolar de Vermont está detenido, debidamente identificado y equipado según lo exigido, ¿cuándo debe detenerse el tránsito que se aproxima y el que lo rebasa?","options":["Solo si las luces ámbar del autobús están parpadeando","Solo cuando hay niños visiblemente parados en la calzada","De inmediato, y permanecer detenido mientras las luces rojas intermitentes estén en funcionamiento","A menos de 25 pies del autobús, y luego pasar lentamente junto a él"],"explanation":"23 V.S.A. § 1075 exige que un conductor, al encontrarse con un autobús escolar debidamente identificado y detenido para recoger o dejar a escolares, o al rebasarlo, \"detenga su vehículo de inmediato\" y lo mantenga detenido \"mientras las luces rojas intermitentes estén en funcionamiento\". Fuente: 23 V.S.A. § 1075."},"64":{"q":"Según la ley de Vermont, la única situación en la que un conductor NO necesita detenerse ante un autobús escolar que recoge niños en el lado opuesto es cuando el autobús está en:","options":["Cualquier carretera de cuatro carriles, con o sin divisor","Cualquier carretera donde el conductor circule al menos 10 mph por debajo del límite","Cualquier carretera con una doble línea amarilla central pintada","Una carretera con calzadas separadas, estando el autobús en una calzada diferente"],"explanation":"23 V.S.A. § 1075 exime de detenerse únicamente \"en una carretera con calzadas separadas\" cuando se encuentra con un autobús o lo rebasa en una calzada diferente (o en una zona de carga de acceso controlado donde los peatones no puedan cruzar). Las calzadas deben estar físicamente separadas; una línea pintada no califica. Fuente: 23 V.S.A. § 1075."},"65":{"q":"En Vermont, cuando un vehículo con placas de materiales peligrosos o un autobús debe detenerse en un cruce de ferrocarril, ¿dónde debe detenerse con respecto al riel más cercano?","options":["Exactamente a 10 pies del riel más cercano","En cualquier punto dentro de los 75 pies del riel más cercano","A menos de 50 pies pero no menos de 15 pies del riel más cercano","A menos de 100 pies pero no menos de 25 pies del riel más cercano"],"explanation":"Siguiendo el estándar federal CDL/FMCSA aplicado en Vermont (49 CFR 392.10), el conductor de un vehículo con placas de materiales peligrosos o de un autobús obligado a detenerse debe hacerlo a menos de 50 pies pero no menos de 15 pies del riel más cercano. Fuente: Manual CDL de Vermont (Cruces de Ferrocarril); 49 CFR 392.10."},"66":{"q":"Mientras un vehículo comercial de Vermont cruza las vías del ferrocarril, ¿qué le indica el manual CDL al conductor que NO debe hacer?","options":["Mantener ambas manos en el volante","Cruzar en una marcha lo suficientemente baja para evitar que se apague el motor","Mirar y escuchar en ambas direcciones antes de entrar","Cambiar de marcha mientras cualquier parte del vehículo esté sobre las vías"],"explanation":"El Manual CDL de Vermont indica a los conductores que nunca cambien de marcha mientras cruzan las vías, porque hacerlo arriesga que el motor se apague sobre el cruce. El conductor debe seleccionar una marcha antes de llegar a las vías y no cambiarla hasta haberlas despejado. Fuente: Manual CDL de Vermont (Cruces de Ferrocarril)."},"67":{"q":"Antes de que un conductor de vehículo comercial (CMV) de Vermont comience a cruzar un paso a nivel de ferrocarril, el manual indica que el conductor debe asegurarse de que haya suficiente espacio del otro lado para que el vehículo:","options":["Tenga al menos un eje entre los rieles","Pueda detenerse sobre las vías para verificar si vienen trenes","Pueda detenerse con su defensa delantera sobre el segundo riel","Pueda despejar por completo las vías sin detenerse sobre ellas"],"explanation":"El Manual CDL de Vermont advierte que un conductor nunca debe comenzar a cruzar las vías sin estar seguro de que el vehículo pueda pasar por completo sin detenerse. El conductor debe tener espacio del otro lado para despejar el cruce por completo. Fuente: Manual CDL de Vermont (Cruces de Ferrocarril)."},"68":{"q":"Un CMV de Vermont está detenido en una carretera recta, plana y de dos carriles. ¿Dónde se colocan los tres dispositivos de advertencia (triángulos reflectantes)?","options":["Aproximadamente a 25 pies, 75 pies y 150 pies hacia atrás","Aproximadamente a 50 pies, 150 pies y 300 pies hacia atrás","Aproximadamente a 10 pies, 100 pies y 200 pies hacia atrás en dirección al tránsito que se aproxima","Aproximadamente a 10 pies, 50 pies y 100 pies hacia atrás"],"explanation":"Siguiendo el estándar FMCSA/CDL utilizado en Vermont, en una carretera de dos carriles los triángulos se colocan aproximadamente a 10 pies directamente detrás del vehículo, aproximadamente a 100 pies hacia atrás y aproximadamente a 200 pies hacia atrás en dirección al tránsito que se aproxima. Fuente: Manual CDL de Vermont (Detenerse en la Carretera); 49 CFR 392.22."},"69":{"q":"Si un CMV de Vermont está detenido a menos de 500 pies de una colina, curva u otra obstrucción visual, ¿cómo deben ajustarse los dispositivos de advertencia?","options":["Colocar un dispositivo en dirección a la obstrucción, de 100 a 500 pies del vehículo, para dar una advertencia amplia","No se requieren triángulos porque el peligro es visible","Colocar los tres dispositivos directamente detrás del vehículo a menos de 10 pies","Colocar un dispositivo exactamente a 700 pies más allá de la obstrucción"],"explanation":"El Manual CDL de Vermont (conforme a 49 CFR 392.22) indica que si la detención ocurre a menos de 500 pies de una curva, cima de colina u otra obstrucción visual, el conductor desplaza el dispositivo de advertencia trasero en dirección a la obstrucción de modo que quede de 100 a 500 pies del vehículo. Fuente: Manual CDL de Vermont; 49 CFR 392.22."},"70":{"q":"¿Cuál es el límite máximo de velocidad legal para cualquier vehículo motorizado en una carretera de acceso limitado (interestatal) de Vermont, salvo que se indique lo contrario?","options":["55 mph","65 mph","60 mph","70 mph"],"explanation":"La normativa de carreteras de acceso limitado de Vermont fija el máximo en 65 mph: \"El límite máximo de velocidad al que puede operarse cualquier vehículo motorizado en carreteras de acceso limitado será de sesenta y cinco (65) millas por hora\", salvo que se indique lo contrario. Fuente: Code Vt. R. 14-053-004 (instalaciones de acceso limitado); 23 V.S.A. § 1081."},"71":{"q":"En ausencia de un límite indicado o de una designación de acceso limitado, ¿cuál es la velocidad máxima estatutaria por defecto en una carretera de Vermont?","options":["65 mph","50 mph","45 mph","55 mph"],"explanation":"23 V.S.A. § 1081 establece un máximo por defecto de 50 mph en las carreteras, salvo que se indique o se fije un límite diferente conforme al estatuto. Los límites más altos (hasta 65 mph) aplican únicamente en carreteras de acceso limitado por autoridad del Comité de Tránsito. Fuente: 23 V.S.A. § 1081."},"72":{"q":"¿Establece Vermont un límite máximo de velocidad separado y más bajo para camiones y vehículos comerciales que para los automóviles en sus carreteras?","options":["No: el límite indicado aplica a todos los vehículos; no hay un límite de velocidad separado para camiones","Sí: los camiones están limitados a 60 mph en las interestatales","Sí: los camiones están limitados a 55 mph en todas partes","Sí: los camiones deben circular 10 mph por debajo del límite indicado para automóviles"],"explanation":"Vermont no impone un límite de velocidad separado y más bajo para camiones. El mismo máximo (por ejemplo, 65 mph en carreteras de acceso limitado, 50 mph por defecto) aplica a todos los vehículos motorizados, incluidos camiones y autobuses. Fuente: 23 V.S.A. § 1081; Code Vt. R. 14-053-004."},"73":{"q":"En una carretera de acceso limitado de Vermont, un camión o autobús puede circular por debajo de la velocidad mínima indicada debido a la pendiente únicamente si:","options":["Muestra sus intermitentes de cuatro direcciones mientras lo hace","Se mueve por completo al acotamiento izquierdo","Hace sonar su claxon de forma continua","Primero obtiene un permiso de circulación para carga sobredimensionada"],"explanation":"La normativa de acceso limitado de Vermont exime a los camiones y autobuses de la regla de velocidad mínima cuando la pendiente hace impracticable esa velocidad, pero solo si el vehículo muestra los intermitentes de cuatro direcciones durante ese tiempo. Fuente: Code Vt. R. 14-053-004 (instalaciones de acceso limitado)."},"74":{"q":"La Ruta 108 de Vermont, que atraviesa Smugglers' Notch, está cerrada a ¿cuáles vehículos?","options":["Cualquier vehículo de más de 8 pies 6 pulgadas de ancho","Vehículos de chasis único de más de 40 pies y combinaciones de tractocamión y remolque de más de 45 pies de longitud total","Todos los vehículos de más de 26,000 libras de GVWR","Autobuses que transporten más de 15 pasajeros"],"explanation":"23 V.S.A. § 1006b prohíbe que los vehículos motorizados de chasis único de más de 40 pies de longitud, y las unidades tractoras con uno o más remolques que excedan los 45 pies en total, circulen por el tramo de Smugglers' Notch de la Ruta 108 de Vermont. El estrecho paso de montaña no puede acomodarlos. Fuente: 23 V.S.A. § 1006b; Vermont Agency of Transportation (vtrans.vermont.gov/notch)."},"75":{"q":"Un camionero que ignora el GPS y deja atascado un tractocamión con remolque en Smugglers' Notch, en la Ruta 108 de Vermont, enfrenta una sanción civil que, por bloquear sustancialmente el tránsito, está programada para aumentar el 1 de julio de 2026 a:","options":["$2,000","$50,000","$20,000","$5,000"],"explanation":"Conforme a 23 V.S.A. § 1006b, la multa base era de $1,000, o $2,000 si la infracción impide sustancialmente el tránsito; la legislación las eleva a $10,000 y $20,000 (por bloqueo del tránsito) a partir del 1 de julio de 2026. Fuente: 23 V.S.A. § 1006b; Vermont Agency of Transportation."},"76":{"q":"Sin un permiso para carga sobredimensionada, ¿cuál es el ancho máximo legal de un vehículo en las carreteras de Vermont?","options":["8 pies 0 pulgadas","8 pies 6 pulgadas","10 pies 0 pulgadas","9 pies 0 pulgadas"],"explanation":"El ancho máximo legal de un vehículo en Vermont sin permiso es de 8 pies 6 pulgadas (102 pulgadas); la altura legal es de 13 pies 6 pulgadas y el peso bruto legal es de 80,000 libras. Exceder estos límites requiere un permiso de carga sobredimensionada o sobrepeso de Operaciones de Vehículos Comerciales del DMV. Fuente: Reglas de Permisos de Carga Sobredimensionada/Sobrepeso del CVO del Vermont DMV (CVO-110)."},"77":{"q":"Los permisos de carga sobredimensionada/sobrepeso de Vermont generalmente autorizan el movimiento únicamente durante qué horario?","options":["Desde media hora antes del amanecer hasta media hora después del atardecer","Solo entre la medianoche y las 6:00 a.m.","Las 24 horas del día sin restricción","Solo los fines de semana y días feriados oficiales"],"explanation":"Las reglas de permisos de Vermont limitan el desplazamiento de cargas sobredimensionadas o con sobrepeso a las horas de luz natural: desde media hora antes del amanecer hasta media hora después del atardecer, con restricciones adicionales para las cargas más grandes durante los fines de semana y días feriados. Fuente: Reglas de Permisos de Carga Sobredimensionada/Sobrepeso del CVO del Vermont DMV (CVO-110)."},"78":{"q":"En una carretera de Vermont, ¿por dónde debe circular un camión que va más lento que la velocidad normal del tránsito?","options":["Por el carril derecho disponible, o lo más cerca posible del borde derecho, salvo al rebasar o al prepararse para girar a la izquierda","Por el carril izquierdo para que el tránsito más rápido pueda incorporarse a la derecha","Por el acotamiento pavimentado hasta que se despeje el tránsito","Por el carril central de cualquier carretera de varios carriles en todo momento"],"explanation":"La regla de mantenerse a la derecha de Vermont exige que un vehículo que circula por debajo de la velocidad normal del tránsito sea conducido por el carril derecho, o lo más cerca posible de la guarnición o el borde derecho, salvo al alcanzar y rebasar o al prepararse para un giro a la izquierda. Fuente: 23 V.S.A. § 1038 / § 1031."},"79":{"q":"Según la ley de Vermont, ¿quién puede exigir cadenas para neumáticos en determinadas carreteras estatales durante el clima invernal, y para cuáles vehículos?","options":["Las cadenas se exigen solo en caminos municipales, nunca en carreteras estatales","Solo el gobierno federal puede exigir cadenas, y únicamente en las interestatales","Las autoridades estatales pueden exigir cadenas para vehículos de más de 26,000 libras de GVWR o GCWR en tramos designados de carretera","Las cadenas son obligatorias para todo automóvil de pasajeros de diciembre a marzo"],"explanation":"23 V.S.A. § 1006c autoriza al Secretario de Transporte, al Comisionado de Vehículos Motorizados o al Comisionado de Seguridad Pública (o a sus designados) a exigir cadenas para neumáticos en tramos determinados de las carreteras estatales durante el clima invernal para vehículos de más de 26,000 libras de GVWR o GCWR, con señalización anticipada. Fuente: 23 V.S.A. § 1006c."},"80":{"q":"En Vermont, ¿qué agencia emite las Licencias de Conducir Comerciales (CDL) y administra los exámenes requeridos?","options":["El Departamento de Vehículos Motorizados de Vermont (DMV)","La Agencia de Transporte de Vermont (VTrans)","La Administración Federal de Seguridad de Autotransportes (FMCSA)","La Unidad de Vehículos Comerciales de la Policía Estatal de Vermont"],"explanation":"El Departamento de Vehículos Motorizados de Vermont (DMV) emite las CDL y administra los exámenes de conocimientos y de habilidades en el estado. La FMCSA fija los estándares federales de CDL pero no emite la licencia. Fuente: Vermont DMV, página de la Licencia de Conducir Comercial (CDL); Manual del Conductor CDL de Vermont (VN-111)."},"81":{"q":"Antes de que una persona pueda presentar el examen de habilidades de la CDL en Vermont, ¿qué permiso debe obtener y poseer primero?","options":["Un Permiso de Aprendizaje Comercial (CLP)","Solo un permiso de aprendizaje regular de Vermont","Un permiso temporal de operación interestatal","Un permiso de carga sobredimensionada/sobrepeso"],"explanation":"Vermont exige que los solicitantes obtengan un Permiso de Aprendizaje Comercial (CLP), que autoriza la práctica supervisada en un vehículo motorizado comercial antes del examen de habilidades. Fuente: Vermont DMV, página del Permiso de Aprendizaje de Conductor Comercial (CLP); Manual del Conductor CDL de Vermont (VN-111)."},"82":{"q":"Después de recibir un Permiso de Aprendizaje Comercial en Vermont, ¿cuál es el número mínimo de días que un conductor debe poseerlo antes de presentar el examen de habilidades de la CDL?","options":["14 días","7 días","30 días","60 días"],"explanation":"El titular de un CLP debe esperar un mínimo de 14 días después de la emisión del CLP antes de presentar el examen de habilidades para la CDL. Fuente: Vermont DMV, páginas del Permiso de Aprendizaje de Conductor Comercial (CLP) y de Renovaciones/Transferencias/Actualizaciones; 49 CFR 383.25 federal."},"83":{"q":"El examen de habilidades de la CDL de Vermont consta de ¿cuáles tres partes?","options":["Inspección previaje, control básico del vehículo y conducción en carretera","Examen escrito de conocimientos, examen de la vista y conducción en carretera","Verificación de frenos de aire, manejo de materiales peligrosos y conducción nocturna","Inspección previaje, estacionamiento en paralelo y una prueba a velocidad de carretera"],"explanation":"El examen de habilidades de la CDL de Vermont tiene tres partes, todas las cuales deben aprobarse: la inspección previaje del vehículo, las maniobras de control básico del vehículo y el examen de conducción en carretera. Fuente: páginas de CDL del Vermont DMV; Manual del Conductor CDL de Vermont (VN-111)."},"84":{"q":"¿Qué formulario presenta un conductor para autocertificar su tipo de conducción y su estado médico ante el Vermont DMV?","options":["El formulario de Certificación Médica de la CDL (VL-033)","Únicamente el Certificado federal del Examinador Médico","Una declaración jurada de aptitud certificada ante notario","El formulario de antecedentes de materiales peligrosos de la TSA"],"explanation":"Los titulares y solicitantes de CDL de Vermont autocertifican su tipo de conducción y estado médico completando y presentando el formulario de Certificación Médica de la CDL, VL-033, ante el DMV. Fuente: Vermont DMV, página de Requisitos Médicos de la CDL y Formulario VL-033."},"85":{"q":"Al autocertificarse ante el Vermont DMV, ¿entre cuántas categorías de conducción puede elegir un solicitante de CDL?","options":["Cuatro","Dos","Tres","Cinco"],"explanation":"Hay cuatro categorías de autocertificación: Interestatal No Exceptuado (NI), Interestatal Exceptuado (EI), Intraestatal No Exceptuado (NA) e Intraestatal Exceptuado (EA). El conductor selecciona una en el Formulario VL-033. Fuente: Certificación Médica de la CDL del Vermont DMV (Formulario VL-033); 49 CFR 383.71."},"86":{"q":"Un solicitante de CDL de Vermont que conduce en el comercio interestatal y está sujeto a las reglas federales de calificación física (49 CFR Parte 391) debe autocertificarse en ¿cuál categoría?","options":["Interestatal No Exceptuado (NI)","Interestatal Exceptuado (EI)","Intraestatal No Exceptuado (NA)","Intraestatal Exceptuado (EA)"],"explanation":"Un conductor que opera en el comercio interestatal y está sujeto a 49 CFR Parte 391 se autocertifica como Interestatal No Exceptuado (NI) y debe presentar un Certificado del Examinador Médico vigente. Fuente: Vermont DMV Formulario VL-033; 49 CFR 383.71."},"87":{"q":"¿Cuál categoría de autocertificación en Vermont exige que el conductor presente un Certificado del Examinador Médico vigente \"Vermont Only\" (solo para Vermont)?","options":["Intraestatal No Exceptuado (NA)","Interestatal No Exceptuado (NI)","Interestatal Exceptuado (EI)","Intraestatal Exceptuado (EA)"],"explanation":"Un conductor Intraestatal No Exceptuado (NA) opera únicamente dentro de Vermont y debe cumplir con los estándares médicos presentando un Certificado del Examinador Médico vigente \"Vermont Only\". Fuente: Certificación Médica de la CDL del Vermont DMV (Formulario VL-033)."},"88":{"q":"¿Quién está autorizado para realizar el examen físico del DOT que produce un Certificado del Examinador Médico de la CDL aceptado en Vermont?","options":["Un examinador médico inscrito en el Registro Nacional de Examinadores Médicos Certificados de la FMCSA","Cualquier médico con licencia elegido por el conductor","Un examinador del Vermont DMV en el sitio de examen","El oficial de seguridad del empleador del conductor"],"explanation":"El examen físico debe ser realizado por un examinador médico inscrito en el Registro Nacional de Examinadores Médicos Certificados de la FMCSA. Fuente: Vermont DMV, página de Requisitos Médicos de la CDL; 49 CFR 390.103 / Parte 391."},"89":{"q":"¿Cuál es el período máximo de validez de un Certificado del Examinador Médico del DOT estándar para un titular de CDL de Vermont?","options":["Hasta 2 años","Hasta 1 año","Hasta 3 años","Hasta 5 años"],"explanation":"Un Certificado del Examinador Médico estándar es válido hasta por 2 años, aunque un examinador puede emitir uno por un período más corto si una condición requiere monitoreo. Fuente: Vermont DMV, página de Requisitos Médicos de la CDL; 49 CFR Parte 391."},"90":{"q":"¿Qué puede ocurrir con una CDL de Vermont si el titular no mantiene un certificado médico vigente registrado ante el DMV?","options":["La CDL puede degradarse o suspenderse el privilegio de conducir","Nada, siempre que la licencia en sí no haya expirado","Al conductor se le asigna automáticamente el estatus de Interestatal Exceptuado","Solo se envía por correo una advertencia escrita sin efecto sobre la licencia"],"explanation":"Si no se mantiene registrada la documentación médica vigente, el Vermont DMV puede degradar la CDL (retirar los privilegios comerciales) o suspender el privilegio de conducir. Fuente: Vermont DMV, página de Requisitos Médicos de la CDL; 49 CFR 383.73."},"91":{"q":"¿Cuál capacitación debe completar un solicitante de CDL Clase A o Clase B por primera vez antes de que se le permita presentar el examen de habilidades de Vermont?","options":["Capacitación de Conductor de Nivel Inicial (ELDT) de un proveedor registrado en la FMCSA","Un curso de conducción defensiva aprobado por el Vermont DMV","Un curso teórico de ocho horas impartido por el DMV","Un aprendizaje registrado únicamente con el empleador"],"explanation":"Los solicitantes de Clase A/B por primera vez (y ciertos endosos) deben completar la Capacitación de Conductor de Nivel Inicial (ELDT) de un proveedor inscrito en el Registro de Proveedores de Capacitación de la FMCSA antes de presentar el examen de habilidades de la CDL. Fuente: páginas de CDL del Vermont DMV; 49 CFR Parte 380 Subparte F."},"92":{"q":"Para un endoso de Materiales Peligrosos (HazMat) (H) por primera vez, ¿cuándo debe completarse la Capacitación de Conductor de Nivel Inicial requerida?","options":["Antes de presentar el examen de conocimientos de HazMat","Únicamente antes del examen de habilidades en carretera","Dentro de los 30 días posteriores a la emisión de la licencia","Solo después de que se apruebe la verificación de antecedentes de la TSA"],"explanation":"Dado que el endoso de HazMat no tiene examen de habilidades, la ELDT para un endoso H por primera vez debe completarse antes de que el solicitante presente el examen de conocimientos de HazMat. Fuente: páginas de CDL del Vermont DMV; 49 CFR Parte 380 Subparte F."},"93":{"q":"¿Cuál examen de conocimientos debe aprobar todo solicitante de CDL de Vermont, sin importar la clase o el endoso?","options":["El examen de Conocimientos Generales","El examen de Frenos de Aire","El examen de Vehículos Combinados","El examen de Materiales Peligrosos"],"explanation":"Todo solicitante de CDL debe aprobar el examen escrito de Conocimientos Generales; los exámenes adicionales como Frenos de Aire, Vehículos Combinados y los exámenes de endoso aplican únicamente según corresponda al vehículo o al endoso. Fuente: Manual del Conductor CDL de Vermont (VN-111); páginas de CDL del Vermont DMV."},"94":{"q":"¿Cuál es la calificación mínima requerida para aprobar un examen de conocimientos (escrito) de la CDL de Vermont?","options":["80 por ciento","70 por ciento","75 por ciento","90 por ciento"],"explanation":"Los exámenes de conocimientos de la CDL de Vermont requieren una calificación aprobatoria de al menos el 80 por ciento de las preguntas respondidas correctamente. Fuente: Manual del Conductor CDL de Vermont (VN-111); información de exámenes de CDL del Vermont DMV."},"95":{"q":"¿Mediante cuál método debe renovarse una CDL de Vermont?","options":["En persona en una oficina del Vermont DMV","Únicamente en línea a través del sitio web del DMV","Por correo, usando solo el aviso de renovación","Automáticamente, sin acción alguna por parte del conductor"],"explanation":"Una CDL debe renovarse en persona en una oficina de atención al cliente del Vermont DMV; el conductor lleva el aviso de renovación firmado y la tarifa. Fuente: Vermont DMV, página de Renovaciones, Transferencias y Actualizaciones."},"96":{"q":"¿Por cuántos años puede renovarse una CDL de Vermont a la vez?","options":["Dos o cuatro años","Uno o dos años","Cinco años","Ocho años"],"explanation":"Las renovaciones de la CDL de Vermont se emiten en un ciclo de dos o cuatro años, acreditándose cualquier año completo restante de la credencial actual a la tarifa de renovación. Fuente: Vermont DMV, página de Renovaciones, Transferencias y Actualizaciones."},"97":{"q":"Una persona que posee una CDL válida de otro estado y se muda a Vermont debe transferirla a una CDL de Vermont dentro de ¿cuánto tiempo después de establecer la residencia?","options":["30 días","10 días","60 días","90 días"],"explanation":"Conforme a la ley estatal y federal, una persona que posee una CDL de otro estado debe transferirla a una CDL de Vermont dentro de los 30 días posteriores a establecer su residencia en Vermont. Fuente: Vermont DMV, página de Renovaciones, Transferencias y Actualizaciones; 49 CFR 383.71."},"98":{"q":"Al actualizar una CDL de Vermont existente a una clase superior, ¿qué debe hacer el conductor respecto a un permiso?","options":["Obtener un Permiso de Aprendizaje Comercial y poseerlo durante al menos 14 días","Nada; la CDL existente es suficiente para examinarse por la actualización","Obtener únicamente un permiso de aprendizaje de operador regular","Poseer el nuevo permiso durante un mínimo de 90 días"],"explanation":"Para actualizar a una clase de CDL superior, el conductor debe obtener un Permiso de Aprendizaje Comercial, poseerlo durante al menos 14 días y aprobar los exámenes de conocimientos y de habilidades correspondientes. Fuente: Vermont DMV, página de Renovaciones, Transferencias y Actualizaciones."},"99":{"q":"¿Por qué el Vermont DMV aconseja a los solicitantes de CDL tratar las tarifas publicadas de licencia y de exámenes como sujetas a cambio?","options":["Los montos de las tarifas se fijan por estatuto y por las tablas del DMV, que pueden revisarse, por lo que siempre debe confirmarse la tarifa vigente publicada","Vermont no cobra tarifas por los servicios de CDL, así que cualquier monto publicado es un error","Las tarifas se negocian individualmente en el mostrador para cada solicitante","Solo el gobierno federal, no Vermont, puede fijar o cambiar las tarifas de CDL"],"explanation":"Las tarifas de CDL y de exámenes se establecen por estatuto de Vermont y por las tablas de tarifas del DMV, que pueden actualizarse, por lo que los solicitantes deben confirmar el monto vigente con el DMV en lugar de basarse en una cifra fija. Fuente: información de tarifas del Vermont DMV; 23 V.S.A. (estatutos de tarifas de vehículos motorizados)."}},"hi":{"0":{"q":"वर्मोंट के राजमार्गों पर ओवर-विड्थ परमिट की आवश्यकता होने से पहले वाहन की अधिकतम कानूनी चौड़ाई कितनी होती है?","options":["8 फीट (96 इंच)","8 फीट 6 इंच (102 इंच)","9 फीट (108 इंच)","8 फीट 4 इंच (100 इंच)"],"explanation":"23 V.S.A. § 1431 के तहत, वर्मोंट में वाहन की अधिकतम चौड़ाई 8 फीट 6 इंच (102 इंच) है, जिसमें सुरक्षा उपकरण जैसे शीशे (मिरर) शामिल नहीं हैं जो प्रत्येक तरफ 3 इंच तक बाहर निकलते हैं। इससे अधिक चौड़ी किसी भी चीज़ के लिए DMV ओवर-डाइमेंशन परमिट की आवश्यकता होती है। स्रोत: 23 V.S.A. § 1431."},"1":{"q":"वर्मोंट के राजमार्गों पर बिना परमिट के वाहन की अधिकतम कानूनी ऊँचाई कितनी होती है?","options":["13 फीट","14 फीट","13 फीट 6 इंच","12 फीट 6 इंच"],"explanation":"23 V.S.A. § 1431 वाहन की अधिकतम ऊँचाई 13 फीट 6 इंच निर्धारित करता है। इससे अधिक भार वाले लोड के लिए वर्मोंट DMV से ओवर-डाइमेंशन परमिट की आवश्यकता होती है। स्रोत: 23 V.S.A. § 1431."},"2":{"q":"वर्मोंट में, बिना विशेष अनुमति के एकल मोटर वाहन (जिसमें कोई ट्रेलर या सेमीट्रेलर जुड़ा न हो) की अधिकतम कुल लंबाई कितनी होती है?","options":["40 फीट","53 फीट","46 फीट","48 फीट"],"explanation":"23 V.S.A. § 1432 के तहत, बिना ट्रेलर या सेमीट्रेलर जुड़े ऐसे किसी मोटर वाहन को जिसकी कुल लंबाई 46 फीट से अधिक हो, विशेष अनुमति के बिना वर्मोंट के राजमार्ग पर नहीं चलाया जा सकता। स्रोत: 23 V.S.A. § 1432."},"3":{"q":"वर्मोंट के किसी सामान्य राजमार्ग पर ओवर-लेंथ परमिट के बिना वाहनों के संयोजन (ट्रेलर या सेमीट्रेलर सहित ट्रक) की अधिकतम कुल लंबाई कितनी होती है?","options":["65 फीट","75 फीट","70 फीट","80 फीट"],"explanation":"23 V.S.A. § 1432 के तहत, 75 फीट कुल लंबाई से अधिक न होने वाले वाहनों के संयोजन परमिट के बिना वर्मोंट के राजमार्गों पर चल सकते हैं; इससे लंबे संयोजनों के लिए ओवर-लेंथ परमिट की आवश्यकता होती है। स्रोत: 23 V.S.A. § 1432."},"4":{"q":"वर्मोंट के इंटरस्टेट और नामित नेशनल नेटवर्क राजमार्गों पर, ट्रैक्टर-सेमीट्रेलर संयोजन में अनुमत सेमीट्रेलर की अधिकतम लंबाई कितनी होती है?","options":["48 फीट","53 फीट","45 फीट","57 फीट"],"explanation":"इंटरस्टेट प्रणाली और योग्य नामित राजमार्गों पर, वर्मोंट कुल-लंबाई की सीमा के बजाय संघीय कंपोनेंट-लंबाई सीमाएँ लागू करता है: ट्रैक्टर-सेमीट्रेलर संयोजन में सेमीट्रेलर 53 फीट तक हो सकता है। स्रोत: 23 V.S.A. § 1432."},"5":{"q":"वर्मोंट के नामित राजमार्ग नेटवर्क पर ट्रैक्टर-सेमीट्रेलर-ट्रेलर (ट्विन-ट्रेलर) संयोजन के लिए, प्रत्येक ट्रेलर या सेमीट्रेलर की अधिकतम लंबाई कितनी होती है?","options":["प्रत्येक 28 फीट","प्रत्येक 30 फीट","प्रत्येक 27 फीट","प्रत्येक 33 फीट"],"explanation":"इंटरस्टेट और नामित नेटवर्क पर, ट्विन-ट्रेलर संयोजन संघीय कंपोनेंट सीमाओं द्वारा शासित होते हैं: प्रत्येक ट्रेलर या सेमीट्रेलर 28 फीट तक हो सकता है। स्रोत: 23 V.S.A. § 1432 (संघीय STAA मानकों के अनुरूप)।"},"6":{"q":"वर्मोंट के राजमार्गों पर किसी मानक वाणिज्यिक वाहन के लिए बिना विशेष परमिट के अधिकतम सकल वाहन भार कितना होता है?","options":["73,280 pounds","80,000 pounds","90,000 pounds","84,000 pounds"],"explanation":"23 V.S.A. § 1392 के तहत, अधिकतम सकल वाहन भार 80,000 pounds है। इससे भारी लोड के लिए DMV ओवरवेट परमिट या किसी वैधानिक विशेष-परमिट श्रेणी की आवश्यकता होती है। स्रोत: 23 V.S.A. § 1392."},"7":{"q":"वर्मोंट में संघीय इंटरस्टेट हाईवे प्रणाली पर, बिना किसी सहनशीलता (टॉलरेंस) की अनुमति के अधिकतम सिंगल-एक्सल भार कितना होता है?","options":["22,400 pounds","18,000 pounds","20,000 pounds","21,000 pounds"],"explanation":"23 V.S.A. § 1391 के तहत, इंटरस्टेट (आइज़नहावर नेशनल सिस्टम ऑफ इंटरस्टेट एंड डिफेंस हाईवेज़) पर सिंगल-एक्सल सीमा 20,000 pounds है जिसमें कोई सहनशीलता की अनुमति नहीं है, जो संघीय कानून से मेल खाती है। स्रोत: 23 V.S.A. § 1391."},"8":{"q":"वर्मोंट में इंटरस्टेट हाईवे प्रणाली पर, बिना किसी सहनशीलता (टॉलरेंस) की अनुमति के अधिकतम टैंडम-एक्सल भार कितना होता है?","options":["36,000 pounds","34,000 pounds","32,000 pounds","38,000 pounds"],"explanation":"23 V.S.A. § 1391 के तहत, इंटरस्टेट प्रणाली पर टैंडम-एक्सल सीमा 34,000 pounds है जिसमें कोई सहनशीलता की अनुमति नहीं है, जो संघीय भार मानकों के अनुरूप है। स्रोत: 23 V.S.A. § 1391."},"9":{"q":"वर्मोंट के गैर-इंटरस्टेट (राज्य और टाउन) राजमार्गों पर, 10 प्रतिशत सहनशीलता लागू करने से पहले अधिकतम सिंगल-एक्सल भार कितना होता है?","options":["20,000 pounds","24,000 pounds","22,400 pounds","21,500 pounds"],"explanation":"23 V.S.A. § 1391 के तहत, गैर-इंटरस्टेट वर्मोंट राजमार्गों पर सिंगल-एक्सल सीमा 22,400 pounds है, जिसमें 10 प्रतिशत सहनशीलता की अनुमति है। स्रोत: 23 V.S.A. § 1391."},"10":{"q":"वर्मोंट के गैर-इंटरस्टेट राजमार्गों पर, 10 प्रतिशत सहनशीलता लागू करने से पहले अधिकतम टैंडम-एक्सल भार कितना होता है?","options":["34,000 pounds","36,000 pounds","32,000 pounds","40,000 pounds"],"explanation":"23 V.S.A. § 1391 के तहत, गैर-इंटरस्टेट वर्मोंट राजमार्गों पर टैंडम-एक्सल सीमा 36,000 pounds है, जिसमें 10 प्रतिशत सहनशीलता की अनुमति है (इंटरस्टेट की 34,000-pound सीमा से एक प्रमुख राज्य-विशिष्ट अंतर)। स्रोत: 23 V.S.A. § 1391."},"11":{"q":"वर्मोंट के गैर-इंटरस्टेट और इंटरस्टेट एक्सल-भार नियमों के बीच एक प्रमुख अंतर सहनशीलता (टॉलरेंस) है। गैर-इंटरस्टेट वर्मोंट राजमार्गों पर सिंगल- और टैंडम-एक्सल सीमाओं पर कौन-सी सहनशीलता लागू होती है?","options":["कोई सहनशीलता की अनुमति नहीं है","5 प्रतिशत सहनशीलता की अनुमति है","10 प्रतिशत सहनशीलता की अनुमति है","15 प्रतिशत सहनशीलता की अनुमति है"],"explanation":"23 V.S.A. § 1391 के तहत, गैर-इंटरस्टेट सिंगल-एक्सल (22,400 lb) और टैंडम-एक्सल (36,000 lb) सीमाओं पर 10 प्रतिशत सहनशीलता होती है, जबकि इंटरस्टेट सीमाएँ (20,000 lb / 34,000 lb) कोई सहनशीलता की अनुमति नहीं देतीं। स्रोत: 23 V.S.A. § 1391."},"12":{"q":"वर्मोंट किस सूत्र का उपयोग करता है, जो संघीय कानून के अनुरूप है, एक्सल के समूह के लिए उनके अंतराल और संख्या के आधार पर अधिकतम अनुमेय सकल भार निर्धारित करने के लिए?","options":["फेडरल ब्रिज फॉर्मूला (Formula B)","ग्रॉस कॉम्बिनेशन वेट रेटिंग सूत्र","टैंडम स्पेसिंग इंडेक्स","एक्सल लोड इक्विवेलेंसी सूत्र"],"explanation":"वर्मोंट फेडरल ब्रिज फॉर्मूला (Bridge Formula B), W = 500[LN/(N-1) + 12N + 36], लागू करता है ताकि किसी भी एक्सल समूह पर ढोए जाने वाले भार को अंतराल (L) और एक्सल की संख्या (N) के आधार पर सीमित किया जा सके, सिंगल, टैंडम, और 80,000-lb सकल सीमाओं के अतिरिक्त। स्रोत: 23 V.S.A. ch. 13 / FHWA के तहत लागू संघीय ब्रिज फॉर्मूला।"},"13":{"q":"वर्मोंट में उपयोग किए जाने वाले फेडरल ब्रिज फॉर्मूला में, दो लगातार एक्सल को 'टैंडम' (अलग-अलग सिंगल एक्सल के बजाय) कब माना जाता है, जब उनके केंद्र कितनी दूरी पर हों?","options":["40 इंच से अधिक लेकिन 96 इंच से अधिक नहीं","96 इंच से अधिक लेकिन 120 इंच से अधिक नहीं","40 इंच से अधिक नहीं","48 इंच से अधिक लेकिन 108 इंच से अधिक नहीं"],"explanation":"वर्मोंट में लागू संघीय परिभाषाओं के तहत, टैंडम एक्सल दो या अधिक लगातार एक्सल होते हैं जिनके केंद्र 40 इंच से अधिक लेकिन 96 इंच से अधिक नहीं होते; 40 इंच या उससे कम दूरी पर स्थित एक्सल को एकल एक्सल माना जाता है। स्रोत: फेडरल ब्रिज फॉर्मूला परिभाषाएँ / FHWA, 23 V.S.A. ch. 13 के तहत लागू।"},"14":{"q":"वर्मोंट के किसी वाणिज्यिक वाहन ऑपरेटर को आमतौर पर DMV से ओवर-डाइमेंशन या ओवरवेट परमिट की आवश्यकता कब होती है?","options":["केवल जब किसी अन्य राज्य में प्रवेश करते समय","जब वाहन या लोड वैधानिक चौड़ाई, ऊँचाई, लंबाई, या भार सीमाओं से अधिक हो","केवल जब सकल भार 100,000 pounds से अधिक हो","केवल रात में या सर्दियों की परिस्थितियों में"],"explanation":"वर्मोंट DMV ओवर-डाइमेंशन/ओवरवेट परमिट की आवश्यकता तब होती है जब कोई वाहन या लोड वैधानिक सीमाओं से अधिक हो (चौड़ाई 8'6\" से अधिक, ऊँचाई 13'6\" से अधिक, एकल वाहन 46 ft से अधिक, संयोजन 75 ft से अधिक, या लागू भार सीमाएँ)। स्रोत: 23 V.S.A. ch. 13 और वर्मोंट DMV ओवरवेट/ओवरडाइमेंशन परमिट नियम (Code Vt. R. 14-050-019)."},"15":{"q":"कौन-सी वर्मोंट एजेंसी राज्य राजमार्गों और इंटरस्टेट प्रणाली पर यात्रा के लिए ओवर-डाइमेंशन और ओवरवेट परमिट जारी करती है?","options":["वर्मोंट एजेंसी ऑफ नेचुरल रिसोर्सेज़","फेडरल मोटर कैरियर सेफ्टी एडमिनिस्ट्रेशन","वर्मोंट डिपार्टमेंट ऑफ मोटर व्हीकल्स (कमर्शियल व्हीकल ऑपरेशंस)","काउंटी शेरिफ का विभाग"],"explanation":"वर्मोंट DMV, अपनी कमर्शियल व्हीकल ऑपरेशंस यूनिट के माध्यम से (और ऑनलाइन VT Haul Pass प्रणाली), आयुक्त (कमिश्नर) के अधिकार के तहत राज्य राजमार्गों और इंटरस्टेट प्रणाली के लिए ओवर-डाइमेंशन और ओवरवेट परमिट जारी करता है। स्रोत: वर्मोंट DMV CVO ओवरवेट/ओवरडाइमेंशन परमिट नियम; 23 V.S.A. § 1400."},"16":{"q":"एक ट्रकिंग कंपनी को पूरे वर्ष में बार-बार एक ही मार्गों पर ओवरसाइज़ अविभाज्य (नॉनडिविज़िबल) लोड ले जाने की आवश्यकता है। कौन-सा वर्मोंट परमिट प्रकार इस ज़रूरत के लिए सबसे उपयुक्त है?","options":["एक सिंगल-ट्रिप परमिट","एक आपातकालीन परमिट","एक ब्लैंकेट (वार्षिक) परमिट","एक रजिस्ट्रेशन-केवल परमिट"],"explanation":"वर्मोंट DMV अविभाज्य लोड के बार-बार आवागमन के लिए ब्लैंकेट (वार्षिक) परमिट जारी करता है, जबकि सिंगल-ट्रिप परमिट एक सीमित अवधि (लगभग सात कार्यदिवस) के भीतर एक आवागमन को कवर करते हैं। स्रोत: वर्मोंट DMV ओवरवेट/ओवरडाइमेंशन परमिट नियम (Code Vt. R. 14-050-019)."},"17":{"q":"किसी नगरपालिका के अधिकार क्षेत्र के अंतर्गत राजमार्गों और पुलों पर वैधानिक सीमाओं से अधिक भार के लिए (Class 1 टाउन राजमार्गों के अलावा), वर्मोंट ओवरवेट परमिट आवेदन किसे किया जाना चाहिए?","options":["वर्मोंट DMV आयुक्त (कमिश्नर) को","नगरपालिका के उपयुक्त विधायी निकाय को (जैसे, सेलेक्टबोर्ड)","फेडरल हाईवे एडमिनिस्ट्रेशन को","वर्मोंट स्टेट पुलिस को"],"explanation":"वर्मोंट परमिट नियमों के तहत, किसी नगरपालिका के अधिकार क्षेत्र के अंतर्गत राजमार्गों और पुलों पर भार सीमाओं से अधिक संचालन के लिए (Class 1 टाउन राजमार्गों को छोड़कर), आवेदन उपयुक्त नगरपालिका विधायी निकाय को किया जाता है। स्रोत: Code Vt. R. 14-050-019 (ओवरवेट/ओवरडाइमेंशन व्हीकल परमिट)."},"18":{"q":"वर्मोंट का स्पेशल एक्सेस वेट परमिट (विभाज्य लोड के लिए एक वार्षिक परमिट) स्टीयरिंग एक्सल पर अधिकतम कितने भार की अनुमति देता है?","options":["10,000 pounds","12,000 pounds","14,000 pounds","20,000 pounds"],"explanation":"वर्मोंट स्पेशल एक्सेस वेट परमिट नियम के तहत, एक्सल सीमाएँ स्टीयरिंग एक्सल पर 12,000 pounds और अन्य सभी एक्सल पर 20,000 pounds हैं। स्रोत: वर्मोंट DMV स्पेशल एक्सेस वेट परमिट; Code Vt. R. 14-050-019."},"19":{"q":"वर्मोंट कानून कुछ छह-या-अधिक-एक्सल वाले ट्रक संयोजनों को एक वार्षिक विशेष परमिट के तहत संचालित करने पर गैर-इंटरस्टेट राजमार्गों पर कितने बढ़े हुए सकल भार तक पहुँचने की अनुमति देता है?","options":["85,000 pounds","108,000 pounds","99,000 pounds","95,000 pounds"],"explanation":"23 V.S.A. § 1392 के तहत, छह या अधिक भार-वहन करने वाले एक्सल वाले ट्रक जो एक विशेष वार्षिक परमिट के तहत संचालित होते हैं, गैर-इंटरस्टेट राजमार्गों पर 99,000 pounds सकल भार तक पहुँच सकते हैं; यह वर्मोंट-विशिष्ट छूट इंटरस्टेट प्रणाली पर लागू नहीं होती जब तक कि संघीय कानून द्वारा अधिकृत न हो। स्रोत: 23 V.S.A. § 1392."},"20":{"q":"वर्मोंट में, निम्नलिखित में से किसका संचालन करने के लिए Class A CDL की आवश्यकता होती है?","options":["वाहनों का कोई भी संयोजन जिसका GCWR 26,001 lbs या अधिक हो, जहाँ खींची जाने वाली इकाई(याँ) 10,000 lbs GVWR से अधिक हों","कोई भी एकल वाहन जिसका GVWR 26,001 lbs या अधिक हो","कोई भी वाहन जो चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया हो","किसी भी भार का कोई भी वाहन जो खतरनाक सामग्री के प्लेकार्ड प्रदर्शित करता हो"],"explanation":"वर्मोंट संघीय CDL वर्गीकरण (49 CFR 383.91) का पालन करता है: Class A वाहनों का कोई भी संयोजन है जिसका GCWR 26,001 lbs या अधिक हो, बशर्ते खींचे जाने वाले वाहन(नों) का GVWR 10,000 lbs से अधिक हो। स्रोत: वर्मोंट CDL मैनुअल (VN-111) / FMCSA 49 CFR 383.91."},"21":{"q":"वर्मोंट के नियमों के तहत, Class B CDL किन वाहनों को कवर करता है?","options":["केवल 16 से कम यात्रियों को ले जाने वाली बसें","कोई भी एकल वाहन जिसका GVWR 26,001 lbs या अधिक हो, या ऐसा वाहन जो 10,000 lbs से अधिक न होने वाली इकाई को खींच रहा हो","कोई भी संयोजन जहाँ ट्रेलर 10,000 lbs GVWR से अधिक हो","कोई भी वाहन जिसके लिए केवल खतरनाक सामग्री समर्थन (एंडोर्समेंट) की आवश्यकता हो"],"explanation":"वर्मोंट संघीय परिभाषा को अपनाता है: Class B कोई भी एकल वाहन है जिसका GVWR 26,001 lbs या अधिक हो, या ऐसा वाहन जो 10,000 lbs GVWR से अधिक न होने वाले किसी अन्य वाहन को खींच रहा हो। स्रोत: वर्मोंट CDL मैनुअल (VN-111) / FMCSA 49 CFR 383.91."},"22":{"q":"वर्मोंट Class C CDL की आवश्यकता तब होती है जब कोई वाहन Class A या B भार परिभाषाओं को पूरा नहीं करता, लेकिन कम से कम कितने यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किया गया हो, या प्लेकार्ड वाली खतरनाक सामग्री ले जाता हो?","options":["10 यात्री","12 यात्री","16 यात्री","24 यात्री"],"explanation":"वर्मोंट का Class C ऐसे वाहन पर लागू होता है (जो Group A या B को पूरा नहीं करता) जो चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया हो, या प्लेकार्ड वाली खतरनाक सामग्री ले जाने के लिए उपयोग किया जाता हो। स्रोत: वर्मोंट CDL मैनुअल (VN-111) / FMCSA 49 CFR 383.91."},"23":{"q":"किसी वाहन को प्लेकार्ड वाली मात्रा में खतरनाक सामग्री ले जाते हुए चलाने के लिए वर्मोंट CDL धारक को किस समर्थन (एंडोर्समेंट) की आवश्यकता होती है?","options":["N एंडोर्समेंट","H एंडोर्समेंट","T एंडोर्समेंट","X एंडोर्समेंट"],"explanation":"H (HazMat) एंडोर्समेंट प्लेकार्ड वाली मात्रा में खतरनाक सामग्री के परिवहन को अधिकृत करता है। (X कोड का अर्थ संयुक्त Tank और HazMat है।) स्रोत: वर्मोंट DMV HazMat एंडोर्समेंट्स पेज / वर्मोंट CDL मैनुअल (VN-111)."},"24":{"q":"केवल इंट्रास्टेट (वर्मोंट के भीतर) वाणिज्य तक सीमित वर्मोंट CDL प्राप्त करने के लिए न्यूनतम आयु कितनी है?","options":["16 वर्ष","17 वर्ष","18 वर्ष","21 वर्ष"],"explanation":"वर्मोंट के लिए आवश्यक है कि CDL प्राप्त करने और इंट्रास्टेट वाणिज्य में वाणिज्यिक मोटर वाहन संचालित करने के लिए आवेदक की आयु कम से कम 18 वर्ष हो। स्रोत: वर्मोंट DMV कमर्शियल ड्राइवर्स लाइसेंस पेज।"},"25":{"q":"वर्मोंट CDL के साथ इंटरस्टेट वाणिज्य में वाणिज्यिक मोटर वाहन संचालित करने के लिए न्यूनतम आयु कितनी है?","options":["18 वर्ष","19 वर्ष","20 वर्ष","21 वर्ष"],"explanation":"इंटरस्टेट वाणिज्य में वाणिज्यिक मोटर वाहन संचालित करने के लिए चालक की आयु कम से कम 21 वर्ष होनी चाहिए, जो संघीय नियम के अनुरूप है। स्रोत: वर्मोंट DMV कमर्शियल ड्राइवर्स लाइसेंस पेज / FMCSA 49 CFR 391.11."},"26":{"q":"CDL स्किल्स टेस्ट निर्धारित करने से पहले, संघीय कानून (वर्मोंट में लागू) के अनुसार आवेदक को कम से कम कितने दिनों तक कमर्शियल लर्नर परमिट (CLP) रखना आवश्यक है?","options":["7 days","14 days","30 days","60 days"],"explanation":"आवेदक को CDL स्किल्स टेस्ट देने से पहले कम से कम 14 days तक CLP रखना आवश्यक है। स्रोत: वर्मोंट DMV CLP पेज / FMCSA 49 CFR 383.25."},"27":{"q":"वर्मोंट कमर्शियल लर्नर परमिट (CLP) के लिए आवेदन करने हेतु, आवेदक के पास पहले से क्या होना आवश्यक है?","options":["एक वैध वर्मोंट Class D (नियमित) ड्राइवर्स लाइसेंस","एक वैध मोटरसाइकिल एंडोर्समेंट","एक संघीय TWIC कार्ड","एक जूनियर ऑपरेटर लाइसेंस"],"explanation":"वर्मोंट के लिए आवश्यक है कि CLP आवेदकों के पास एक वैध वर्मोंट Class D ऑपरेटर्स लाइसेंस हो। स्रोत: वर्मोंट DMV कमर्शियल ड्राइवर्स लर्नर परमिट पेज।"},"28":{"q":"वर्मोंट कमर्शियल लर्नर परमिट (CLP) जारी होने की तारीख से कितने समय तक वैध रहता है?","options":["90 days","6 months","1 year","2 years"],"explanation":"वर्मोंट CLP जारी होने की तारीख से एक वर्ष (12 महीने) तक वैध रहता है। स्रोत: वर्मोंट DMV कमर्शियल ड्राइवर्स लर्नर परमिट पेज / FMCSA 49 CFR 383.25."},"29":{"q":"सार्वजनिक राजमार्गों पर वाहन चलाते समय, वर्मोंट CLP के धारक के साथ ऐसा व्यक्ति होना आवश्यक है जो:","options":["कोई भी वैध वर्मोंट ड्राइवर्स लाइसेंस रखता हो","चलाए जा रहे वाहन की श्रेणी के लिए वैध CDL रखता हो, जिसमें आवश्यक एंडोर्समेंट शामिल हों","कम से कम 25 वर्ष का हो","एक प्रमाणित DMV परीक्षक हो"],"explanation":"CLP धारक के साथ, उनके बगल में बैठा हुआ, ऐसा व्यक्ति होना आवश्यक है जो चलाए जा रहे वाहन के प्रकार के लिए वैध CDL रखता हो, और जिसके पास उपयुक्त एंडोर्समेंट हों। स्रोत: वर्मोंट DMV CLP पेज / FMCSA 49 CFR 383.25."},"30":{"q":"वर्मोंट में तरल पदार्थ या गैसों को थोक में ले जाने वाले टैंक वाहन को संचालित करने के लिए कौन-सा एंडोर्समेंट आवश्यक है?","options":["T एंडोर्समेंट","P एंडोर्समेंट","N एंडोर्समेंट","S एंडोर्समेंट"],"explanation":"थोक टैंकों में तरल पदार्थ/गैसें ले जाने के लिए N (Tank Vehicle) एंडोर्समेंट आवश्यक है। स्रोत: वर्मोंट CDL मैनुअल (VN-111) / FMCSA 49 CFR 383.93."},"31":{"q":"N एंडोर्समेंट की आवश्यकता वाला टैंक वाहन आमतौर पर वह होता है जो किसी टैंक में तरल या गैस ले जाता है, जिसकी व्यक्तिगत रेटेड क्षमता 119 गैलन से अधिक हो और कुल (एग्रीगेट) रेटेड क्षमता कम से कम कितने गैलन हो?","options":["500 gallons","1,000 gallons","1,500 gallons","3,000 gallons"],"explanation":"N एंडोर्समेंट उन टैंकों पर लागू होता है जिनकी व्यक्तिगत रेटेड क्षमता 119 गैलन से अधिक हो और तरल या गैस की कुल (एग्रीगेट) रेटेड क्षमता 1,000 gallons या अधिक हो। स्रोत: वर्मोंट CDL मैनुअल (VN-111) / FMCSA 49 CFR 383.5."},"32":{"q":"डबल या ट्रिपल ट्रेलर संचालित करने के लिए वर्मोंट के चालक को किस एंडोर्समेंट की आवश्यकता होती है?","options":["T एंडोर्समेंट","N एंडोर्समेंट","D एंडोर्समेंट","X एंडोर्समेंट"],"explanation":"T एंडोर्समेंट डबल और ट्रिपल ट्रेलर के संचालन को अधिकृत करता है और इसके लिए केवल एक ज्ञान परीक्षा (नॉलेज टेस्ट) पास करना आवश्यक है। स्रोत: वर्मोंट CDL मैनुअल (VN-111) / FMCSA 49 CFR 383.93."},"33":{"q":"वर्मोंट में यात्रियों को ले जाने के लिए (जैसे ट्रांज़िट या चार्टर बस पर), किस एंडोर्समेंट की आवश्यकता होती है?","options":["S एंडोर्समेंट","P एंडोर्समेंट","N एंडोर्समेंट","H एंडोर्समेंट"],"explanation":"CDL सीमा से ऊपर यात्रियों को ले जाने के लिए डिज़ाइन किए गए वाहन को संचालित करने के लिए P (Passenger) एंडोर्समेंट आवश्यक है; इसके लिए एक ज्ञान परीक्षा और एक यात्री वाहन में स्किल्स टेस्ट की आवश्यकता होती है। स्रोत: वर्मोंट CDL मैनुअल (VN-111) / FMCSA 49 CFR 383.93."},"34":{"q":"वर्मोंट में, छात्रों को ले जाने वाली स्कूल बस संचालित करने वाले चालक के पास P एंडोर्समेंट के साथ-साथ कौन-सा अतिरिक्त एंडोर्समेंट होना आवश्यक है?","options":["H एंडोर्समेंट","T एंडोर्समेंट","S एंडोर्समेंट","N एंडोर्समेंट"],"explanation":"स्कूल बस चालकों को P एंडोर्समेंट के अतिरिक्त S (School Bus) एंडोर्समेंट की आवश्यकता होती है। S एंडोर्समेंट के लिए स्कूल बस संचालन पर ज्ञान और स्किल्स परीक्षण आवश्यक है। स्रोत: वर्मोंट DMV स्कूल बस पेज / FMCSA 49 CFR 383.93."},"35":{"q":"वर्मोंट CDL पर HazMat (H) एंडोर्समेंट प्राप्त करने के लिए न्यूनतम आयु कितनी है?","options":["18 वर्ष","19 वर्ष","21 वर्ष","25 वर्ष"],"explanation":"क्योंकि खतरनाक सामग्री परिवहन के लिए इंटरस्टेट-स्तर की योग्यता और एक संघीय सुरक्षा मंजूरी की आवश्यकता होती है, HazMat एंडोर्समेंट के लिए आवेदक की आयु कम से कम 21 वर्ष होना आवश्यक है। स्रोत: वर्मोंट DMV HazMat एंडोर्समेंट्स पेज।"},"36":{"q":"वर्मोंट द्वारा HazMat (H) एंडोर्समेंट जारी या नवीनीकृत करने से पहले, आवेदक को कौन-सी अतिरिक्त जाँच पास करनी होती है?","options":["फिंगरप्रिंटिंग के साथ एक ट्रांसपोर्टेशन सिक्योरिटी एडमिनिस्ट्रेशन (TSA) पृष्ठभूमि जाँच","एक राज्य दृष्टि विशेषज्ञ परीक्षा","एक नियोक्ता रोड-टेस्ट प्रमाणन","एक नेशनल गार्ड सेवा समीक्षा"],"explanation":"USA PATRIOT Act के तहत, HazMat एंडोर्समेंट के लिए जारी करने या नवीनीकरण से पहले एक TSA सुरक्षा खतरा मूल्यांकन की आवश्यकता होती है, जिसमें फिंगरप्रिंटिंग और एक पृष्ठभूमि जाँच शामिल है। स्रोत: वर्मोंट DMV HazMat एंडोर्समेंट्स पेज / 49 CFR 1572."},"37":{"q":"वर्मोंट में लागू ELDT नियमों के तहत, पहली बार Class A आवेदक को आवश्यक एंट्री-लेवल ड्राइवर प्रशिक्षण कहाँ पूरा करना होता है?","options":["कोई भी कम्युनिटी कॉलेज, सूचीबद्ध हो या न हो","FMCSA ट्रेनिंग प्रोवाइडर रजिस्ट्री (TPR) पर सूचीबद्ध एक प्रदाता","केवल वर्मोंट DMV प्रशिक्षण कार्यालय","चालक की पसंद का कोई भी नियोक्ता-संचालित कार्यक्रम"],"explanation":"7 फरवरी, 2022 से प्रभावी, ELDT (सिद्धांत और बिहाइंड-द-व्हील) स्किल्स टेस्ट से पहले FMCSA की ट्रेनिंग प्रोवाइडर रजिस्ट्री पर सूचीबद्ध प्रदाता के साथ पूरा किया जाना चाहिए। स्रोत: FMCSA ELDT नियम (49 CFR Part 380) / वर्मोंट DMV CDL प्रशिक्षण पेज।"},"38":{"q":"इनमें से किसके लिए ELDT (Entry-Level Driver Training) परीक्षण से पहले आवश्यक नहीं है?","options":["पहली बार Class A या Class B CDL आवेदक","पहली बार H (HazMat) एंडोर्समेंट चाहने वाले चालक","Class B से Class A में अपग्रेड करने वाले चालक","वे चालक जो 7 फरवरी, 2022 से पहले ही एंडोर्समेंट रखते थे"],"explanation":"ELDT पूर्वव्यापी (रेट्रोएक्टिव) नहीं है: जिन चालकों को 7 फरवरी, 2022 से पहले CDL या S/P/H एंडोर्समेंट जारी किया गया था, उन्हें ELDT पूरा करने की आवश्यकता नहीं है। यह पहली बार Class A/B, B-से-A अपग्रेड, और पहली बार S, P, और H एंडोर्समेंट पर लागू होता है। स्रोत: FMCSA ELDT नियम (49 CFR Part 380)."},"39":{"q":"कौन-सा समूह उन चिकित्सा स्व-प्रमाणन श्रेणियों का सबसे अच्छा वर्णन करता है जिनमें से वर्मोंट CDL आवेदक को चुनना होता है?","options":["कमर्शियल, प्राइवेट, एग्रीकल्चरल, और रिक्रिएशनल","नॉन-एक्सेप्टेड इंटरस्टेट, एक्सेप्टेड इंटरस्टेट, नॉन-एक्सेप्टेड इंट्रास्टेट, और एक्सेप्टेड इंट्रास्टेट","Class A मेडिकल, Class B मेडिकल, Class C मेडिकल, और एक्ज़ेम्प्ट","फेडरल, स्टेट, लोकल, और ट्राइबल"],"explanation":"CDL आवेदक चार श्रेणियों में से एक के लिए स्व-प्रमाणन करते हैं: नॉन-एक्सेप्टेड इंटरस्टेट, एक्सेप्टेड इंटरस्टेट, नॉन-एक्सेप्टेड इंट्रास्टेट, या एक्सेप्टेड इंट्रास्टेट। नॉन-एक्सेप्टेड चालकों को एक वैध मेडिकल एग्ज़ामिनर्स सर्टिफिकेट बनाए रखना आवश्यक है। स्रोत: वर्मोंट DMV CDL मेडिकल स्व-प्रमाणन / FMCSA 49 CFR 383.71."},"40":{"q":"वर्मोंट में किसी वाणिज्यिक मोटर वाहन (CMV) को संचालित करते समय, चालक को निषिद्ध शराब स्तर पर संचालन करते हुए माने जाने से पहले अधिकतम कानूनी रक्त अल्कोहल सांद्रता (BAC) कितनी होती है?","options":["0.04 प्रतिशत","0.08 प्रतिशत","0.02 प्रतिशत","0.10 प्रतिशत"],"explanation":"वर्मोंट कानून किसी CMV को 0.04 प्रतिशत या अधिक BAC के साथ संचालित करना अवैध बनाता है, जो साधारण वाहनों के लिए 0.08 सीमा का आधा है। स्रोत: 23 V.S.A. § 4116; वर्मोंट CDL मैनुअल § 1.2.2."},"41":{"q":"वर्मोंट में, एक CDL धारक जिसे पहले प्रमुख अपराध (जैसे किसी CMV को 0.04 या अधिक BAC के साथ चलाना) के लिए दोषी ठहराया जाता है, उसे कम से कम कितने समय के लिए CMV संचालित करने से अयोग्य घोषित किया जाता है?","options":["1 year","60 days","6 months","3 years"],"explanation":"पहला प्रमुख अपराध चालक को एक वर्ष के लिए CMV संचालित करने से अयोग्य घोषित करता है। स्रोत: 23 V.S.A. § 4116; वर्मोंट CDL मैनुअल § 1.2.2 (वर्मोंट द्वारा अपनाया गया संघीय मानक 49 CFR 383.51)."},"42":{"q":"वर्मोंट कानून के तहत, किसी वाणिज्यिक मोटर वाहन को संचालित करने से चालक को शराब के लिए रासायनिक परीक्षण के संबंध में क्या किया हुआ माना जाता है?","options":["शराब परीक्षण के लिए सहमति दी हुई","CDL सुनवाई के अधिकार का त्याग किया हुआ","एक निश्चित $500 जुर्माने पर सहमति दी हुई","एक 30-दिन की वाहन ज़ब्ती स्वीकार की हुई"],"explanation":"वर्मोंट का निहित-सहमति (इम्प्लाइड-कॉन्सेंट) नियम यह प्रावधान करता है कि जो कोई भी CMV संचालित करता है, उसे शराब परीक्षण के लिए सहमति दी हुई माना जाता है। स्रोत: वर्मोंट CDL मैनुअल § 1.2.2; 23 V.S.A. §§ 1202, 4116."},"43":{"q":"यदि किसी वर्मोंट CDL धारक को प्लेकार्ड वाली खतरनाक सामग्री ले जाते समय पहले प्रमुख अपराध के लिए दोषी ठहराया जाता है, तो CMV अयोग्यता अवधि बढ़ाकर कम से कम कितनी कर दी जाती है?","options":["3 years","1 year","18 months","5 years"],"explanation":"प्लेकार्ड वाली खतरनाक सामग्री ले जाते समय किया गया पहला प्रमुख अपराध अयोग्यता को एक वर्ष से बढ़ाकर तीन वर्ष कर देता है। स्रोत: 23 V.S.A. § 4116; वर्मोंट द्वारा अपनाई गई 49 CFR 383.51 Table 1."},"44":{"q":"वर्मोंट में, किसी CMV में किए गए दूसरे प्रमुख अपराध के लिए अयोग्यता अवधि क्या है (उदाहरण के लिए, एक अलग घटना से दूसरा शराब-संबंधी अपराध)?","options":["आजीवन अयोग्यता","3 years","10 years","5 years"],"explanation":"अलग-अलग घटनाओं से उत्पन्न दो प्रमुख अपराधों के परिणामस्वरूप आजीवन CMV अयोग्यता होती है। स्रोत: 23 V.S.A. § 4116; वर्मोंट CDL मैनुअल § 1.2.2."},"45":{"q":"एक वर्मोंट CMV चालक जो आवश्यक रक्त अल्कोहल परीक्षण कराने से इनकार करता है, उस इनकार के लिए किस CDL परिणाम का सामना करता है?","options":["कम से कम 1 साल की CDL अयोग्यता","बिना किसी अयोग्यता के एक चेतावनी","एक 30-दिन की CDL अयोग्यता","केवल एक $250 नागरिक जुर्माना"],"explanation":"शराब परीक्षण कराने से इनकार करना एक प्रमुख अपराध माना जाता है, जिसमें न्यूनतम एक-वर्ष की CMV अयोग्यता होती है (हैज़मैट-प्लेकार्ड होने पर तीन वर्ष)। स्रोत: 23 V.S.A. § 4116; वर्मोंट CDL मैनुअल § 1.2.2."},"46":{"q":"किसी वर्मोंट CMV चालक को कितने समय के लिए आउट-ऑफ-सर्विस रखा जाता है यदि उसमें शराब की कोई भी पता लगाने योग्य मात्रा पाई जाती है जो अभी भी 0.04 प्रतिशत से कम है?","options":["24 hours","1 hour","72 hours","30 days"],"explanation":"0.04 से कम कोई भी मापने योग्य शराब वाले CMV चालक को 24 घंटे के लिए आउट-ऑफ-सर्विस रखा जाता है। स्रोत: वर्मोंट CDL मैनुअल § 1.2.2; 49 CFR 392.5."},"47":{"q":"वर्मोंट में, तीन-वर्ष की अवधि के भीतर कितने गंभीर यातायात उल्लंघनों के लिए दोषी ठहराया जाना 60-दिन की CMV अयोग्यता को ट्रिगर करता है?","options":["2 गंभीर उल्लंघन","3 गंभीर उल्लंघन","4 गंभीर उल्लंघन","1 गंभीर उल्लंघन"],"explanation":"तीन वर्षों के भीतर दो गंभीर यातायात उल्लंघन (अलग-अलग घटनाएँ) 60-दिन की CMV अयोग्यता का परिणाम देते हैं। स्रोत: 23 V.S.A. § 4116; वर्मोंट CDL मैनुअल § 1.2.3."},"48":{"q":"एक वर्मोंट CDL धारक जिसे तीन-वर्ष की अवधि के भीतर तीन गंभीर यातायात उल्लंघनों के लिए दोषी ठहराया जाता है, उसे कम से कम कितने समय के लिए CMV संचालित करने से अयोग्य घोषित किया जाता है?","options":["120 days","60 days","180 days","1 year"],"explanation":"तीन वर्षों के भीतर तीन गंभीर यातायात उल्लंघन 120-दिन की CMV अयोग्यता वहन करते हैं। स्रोत: 23 V.S.A. § 4116; वर्मोंट CDL मैनुअल § 1.2.3."},"49":{"q":"वर्मोंट के CDL नियमों के तहत, तेज़ गति (स्पीडिंग) एक गंभीर यातायात उल्लंघन तब होता है जब चालक निर्धारित सीमा को कितना पार कर जाता है?","options":["15 mph या अधिक","10 mph या अधिक","20 mph या अधिक","5 mph या अधिक"],"explanation":"निर्धारित सीमा से 15 mph या अधिक की अत्यधिक तेज़ गति एक गंभीर यातायात उल्लंघन है। स्रोत: वर्मोंट CDL मैनुअल § 1.2.3; 49 CFR 383.51 Table 2."},"50":{"q":"निम्नलिखित में से किसे वर्मोंट CDL धारक के लिए एक गंभीर यातायात उल्लंघन के रूप में वर्गीकृत किया गया है?","options":["आगे के वाहन का बहुत करीब से पीछा करना","नो-पार्किंग ज़ोन में पार्किंग करना","एक समाप्त रजिस्ट्रेशन स्टिकर","एक जला हुआ मार्कर लैंप"],"explanation":"बहुत करीब से पीछा करना सूचीबद्ध गंभीर यातायात उल्लंघनों में से एक है, साथ ही अत्यधिक तेज़ गति, लापरवाह ड्राइविंग, और अनुचित या अनियमित लेन परिवर्तन भी हैं। स्रोत: वर्मोंट CDL मैनुअल § 1.2.3; 49 CFR 383.51 Table 2."},"51":{"q":"वर्मोंट में, रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन की पहली दोषसिद्धि के लिए CMV अयोग्यता अवधि क्या है?","options":["कम से कम 60 days","कम से कम 120 days","कम से कम 30 days","कम से कम 1 year"],"explanation":"पहला रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन कम से कम 60-दिन की अयोग्यता का परिणाम देता है। स्रोत: 23 V.S.A. § 4116; वर्मोंट CDL मैनुअल § 1.2.5."},"52":{"q":"एक वर्मोंट CMV चालक तीन-वर्ष की अवधि के भीतर तीसरा रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन करता है। न्यूनतम अयोग्यता है:","options":["1 year","120 days","60 days","6 months"],"explanation":"तीन वर्षों के भीतर तीसरा रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन कम से कम एक-वर्ष की अयोग्यता वहन करता है (पहला 60 days, दूसरा 120 days, तीसरा एक वर्ष)। स्रोत: 23 V.S.A. § 4116; वर्मोंट CDL मैनुअल § 1.2.5."},"53":{"q":"कौन-सी कार्रवाई एक रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन है जो किसी वर्मोंट CDL धारक को अयोग्य घोषित कर सकती है?","options":["रुके बिना क्रॉसिंग को पूरी तरह से पार करने के लिए पर्याप्त जगह न होना","पटरियों को पार करने से पहले हॉर्न बजाना","10 mph से कम गति पर पार करना","पटरियों से 50 फीट से अधिक पहले रुकना"],"explanation":"रुके बिना क्रॉसिंग पार करने के लिए पर्याप्त जगह न होना छह ग्रेड-क्रॉसिंग अपराधों में से एक है। स्रोत: वर्मोंट CDL मैनुअल § 1.2.5; 49 CFR 383.51 Table 3."},"54":{"q":"वर्मोंट में, आउट-ऑफ-सर्विस ऑर्डर के उल्लंघन की पहली दोषसिद्धि के लिए न्यूनतम CMV अयोग्यता क्या है (हैज़मैट या यात्रियों से जुड़ी न हो)?","options":["180 days","90 days","30 days","1 year"],"explanation":"पहला आउट-ऑफ-सर्विस ऑर्डर उल्लंघन चालक को 180 days से कम नहीं (एक वर्ष तक) के लिए अयोग्य घोषित करता है। स्रोत: 23 V.S.A. § 4116; वर्मोंट द्वारा अपनाई गई 49 CFR 383.51 Table 4."},"55":{"q":"एक वर्मोंट CDL धारक को 10-वर्ष की अवधि के भीतर दूसरे आउट-ऑफ-सर्विस ऑर्डर उल्लंघन के लिए दोषी ठहराया जाता है। अयोग्यता अवधि है:","options":["2 years","1 year","180 days","5 years"],"explanation":"10 वर्षों में दूसरा आउट-ऑफ-सर्विस ऑर्डर उल्लंघन (अलग-अलग घटनाएँ) दो-वर्ष की अयोग्यता वहन करता है। स्रोत: 23 V.S.A. § 4116; 49 CFR 383.51 Table 4."},"56":{"q":"10-वर्ष की अवधि के भीतर तीसरे या बाद के आउट-ऑफ-सर्विस ऑर्डर उल्लंघन के लिए वर्मोंट CMV अयोग्यता अवधि क्या है?","options":["3 years","2 years","1 year","आजीवन"],"explanation":"10 वर्षों में तीसरा या बाद का आउट-ऑफ-सर्विस ऑर्डर उल्लंघन तीन-वर्ष की अयोग्यता का परिणाम देता है। स्रोत: 23 V.S.A. § 4116; 49 CFR 383.51 Table 4."},"57":{"q":"वर्मोंट के CDL कानून के तहत, किसी CMV को चलाते समय हैंड-हेल्ड मोबाइल टेलीफोन का उपयोग करना सबसे अच्छी तरह से किस रूप में वर्णित किया जाता है?","options":["एक निषिद्ध कार्य जो एक गंभीर यातायात उल्लंघन के रूप में गिना जाता है","अनुमत यदि कॉल एक मिनट से कम हो","केवल इंटरस्टेट राजमार्गों पर अनुमत","एक गैर-गतिशील उल्लंघन जिसका CDL पर कोई प्रभाव नहीं"],"explanation":"वर्मोंट किसी CMV को चलाते समय टेक्स्टिंग और हैंड-हेल्ड फोन उपयोग को प्रतिबंधित करता है; ऐसी दोषसिद्धियाँ अयोग्यता की ओर गंभीर यातायात उल्लंघनों के रूप में गिनी जाती हैं। स्रोत: 23 V.S.A. § 4125; 49 CFR 383.51 Table 2."},"58":{"q":"वर्मोंट में किसी CMV को संचालित करते समय टेक्स्टिंग या हैंड-हेल्ड फोन उपयोग की अनुमति कब है?","options":["जब कानून प्रवर्तन या आपातकालीन सेवाओं से संपर्क करना आवश्यक हो","जब किसी लाल ट्रैफिक लाइट पर रुके हों","जब 25 mph से कम गति पर चल रहे हों","जब लोड गैर-खतरनाक हो"],"explanation":"टेक्स्टिंग/हैंड-हेल्ड फोन प्रतिबंध का एकमात्र अपवाद कानून प्रवर्तन अधिकारियों या अन्य आपातकालीन सेवाओं के साथ संचार है। स्रोत: 23 V.S.A. § 4125."},"59":{"q":"दो प्रमुख अपराधों के लिए आजीवन अयोग्य घोषित किया गया एक वर्मोंट CDL धारक वाणिज्यिक ड्राइविंग विशेषाधिकारों को बहाल कराने के लिए केवल कम से कम कितने समय तक अयोग्य रहने के बाद, और कोई भी आवश्यक पुनर्वास पूरा करने के बाद आवेदन कर सकता है?","options":["10 years","5 years","7 years","15 years"],"explanation":"एक आजीवन CDL अयोग्यता को कम से कम 10 वर्षों के बाद कम किया जा सकता है यदि चालक एक स्वीकृत पुनर्वास कार्यक्रम पूरा करता है और शपथपत्र (एफिडेविट) आवश्यकताओं को पूरा करता है। स्रोत: Code of Vermont Rules 14-050-044 (Reduction of Life Disqualification); 49 CFR 383.51."},"60":{"q":"Vermont के Move Over कानून के तहत, जब कोई कानून प्रवर्तन या आपातकालीन वाहन अपना सायरन बजाते हुए या सिग्नल लैंप प्रदर्शित करते हुए आता है, तो हर दूसरे वाहन के चालक को क्या करना चाहिए?","options":["जब तक आपातकालीन वाहन किसी अलग लेन में है, सामान्य रूप से चलते रहें","यातायात की लेन के दाईं ओर हट जाएं और जब तक वह गुजर न जाए, पूरी तरह रुक जाएं","केवल एक लेन बाईं ओर जाएं और गति बनाए रखें","घोषित सीमा से 20 mph नीचे गति कम करें और उसी लेन में चलते रहें"],"explanation":"23 V.S.A. § 1050(a) के अनुसार, जब कोई कानून प्रवर्तन, एम्बुलेंस, अग्निशमन, या बचाव वाहन सायरन बजाते हुए या अपना सिग्नल लैंप प्रदर्शित करते हुए आता है, तो अन्य सभी वाहनों को 'यातायात की लेन के दाईं ओर हट जाना चाहिए और जब तक कानून प्रवर्तन या आपातकालीन वाहन गुजर न जाए तब तक पूरी तरह रुक जाना चाहिए।' स्रोत: 23 V.S.A. § 1050(a)।"},"61":{"q":"Vermont के एक बहु-लेन राजमार्ग पर, Move Over कानून एक ऐसे चालक से क्या अपेक्षा करता है जो एक स्थिर (STATIONARY) आपातकालीन या टोइंग वाहन के पास आ रहा है जो अपने चेतावनी लैंप प्रदर्शित कर रहा है?","options":["परिस्थितियों की परवाह किए बिना गति को ठीक 25 mph तक कम करें","रुकें केवल तभी जब स्थिर वाहन एक पुलिस क्रूज़र हो, टो ट्रक नहीं","जब तक आगे बढ़ने का संकेत न मिले, हमेशा यात्रा लेन में पूरी तरह रुक जाएं","यदि सुरक्षा परिस्थितियां अनुमति दें तो दूर वाली लेन में लेन बदलें; अन्यथा एक उचित, सुरक्षित और विवेकपूर्ण गति तक धीमा करें"],"explanation":"23 V.S.A. § 1050(b) कहता है कि एक स्थिर आपातकालीन वाहन (या एम्बर लैंप प्रदर्शित करने वाला टोइंग/मरम्मत वाहन) के पास आने वाले चालक को सावधानी से आगे बढ़ना चाहिए और, यदि बहु-लेन राजमार्ग पर है और सुरक्षा अनुमति देती है, तो स्थिर वाहन से दूर वाली लेन में बदल जाना चाहिए; यदि लेन बदलना संभव नहीं है, तो चालक को एक 'उचित, सुरक्षित और विवेकपूर्ण गति' तक धीमा करना चाहिए। स्रोत: 23 V.S.A. § 1050(b)।"},"62":{"q":"Vermont का स्थिर Move Over नियम एक रुके हुए टोइंग और मरम्मत वाहन पर तब लागू होता है जब वह किस रंग का सिग्नल लैंप प्रदर्शित कर रहा हो?","options":["नीला","लाल और सफेद","हरा","एम्बर"],"explanation":"23 V.S.A. § 1050(b) पुलिस (नीला) और एम्बुलेंस/अग्निशमन/बचाव (लाल) वाहनों के अतिरिक्त, 'एम्बर सिग्नल लैंप प्रदर्शित करने वाले स्थिर टोइंग और मरम्मत वाहन' तक move-over/slow-down कर्तव्य को विस्तारित करता है। स्रोत: 23 V.S.A. § 1050(b)।"},"63":{"q":"एक रुके हुए Vermont स्कूल बस पर जो आवश्यकतानुसार चिह्नित और सुसज्जित है, पास आने वाले और आगे निकलने वाले यातायात को कब रुकना चाहिए?","options":["केवल तभी जब बस की एम्बर लाइटें चमक रही हों","केवल तभी जब बच्चे सड़क पर स्पष्ट रूप से खड़े दिख रहे हों","तुरंत, और जब तक चमकती लाल सिग्नल लाइटें चालू हैं तब तक रुके रहें","बस के 25 फीट के भीतर, फिर धीरे-धीरे उसके पास से गुजरें"],"explanation":"23 V.S.A. § 1075 के अनुसार, स्कूली बच्चों को चढ़ाने या उतारने के लिए रुकी हुई एक उचित रूप से चिह्नित स्कूल बस से मिलने या उसे आगे निकलने पर, चालक को 'अपना वाहन तुरंत रोकना' चाहिए और 'जब तक चमकती लाल सिग्नल लाइटें चालू हैं' तब तक उसे स्थिर रखना चाहिए। स्रोत: 23 V.S.A. § 1075।"},"64":{"q":"Vermont कानून के तहत, एकमात्र स्थिति जिसमें चालक को विपरीत दिशा में बच्चों को चढ़ाने वाली स्कूल बस के लिए रुकने की आवश्यकता नहीं है, वह तब है जब बस इस पर हो:","options":["कोई भी चार-लेन सड़क, विभाजक के साथ या बिना","कोई भी सड़क जहां चालक सीमा से कम से कम 10 mph नीचे जा रहा हो","रंगे हुए डबल-पीली केंद्र रेखा वाली कोई भी सड़क","अलग-अलग सड़क-मार्गों वाला एक राजमार्ग, जिसमें बस एक अलग सड़क-मार्ग पर हो"],"explanation":"23 V.S.A. § 1075 केवल 'अलग-अलग सड़क-मार्गों वाले राजमार्ग पर' एक अलग सड़क-मार्ग पर बस से मिलने या उसे आगे निकलने पर (या नियंत्रित-पहुंच लोडिंग ज़ोन पर जहां पैदल यात्री पार नहीं कर सकते) रुकने से छूट देता है। सड़क-मार्गों को भौतिक रूप से अलग होना चाहिए; एक रंगी हुई रेखा योग्य नहीं है। स्रोत: 23 V.S.A. § 1075।"},"65":{"q":"Vermont में, जब एक प्लेकार्ड लगा हुआ खतरनाक-सामग्री वाहन या एक बस को रेलमार्ग-राजमार्ग क्रॉसिंग पर रुकना होता है, तो उसे निकटतम रेल के सापेक्ष कहां रुकना चाहिए?","options":["निकटतम रेल से ठीक 10 फीट","निकटतम रेल के 75 फीट के भीतर कहीं भी","निकटतम रेल के 50 फीट के भीतर लेकिन 15 फीट से कम नहीं","निकटतम रेल के 100 फीट के भीतर लेकिन 25 फीट से कम नहीं"],"explanation":"Vermont में लागू संघीय CDL/FMCSA मानक (49 CFR 392.10) के अनुसार, प्लेकार्ड लगे हुए hazmat वाहन या रुकने के लिए आवश्यक बस के चालक को निकटतम रेल के 50 फीट के भीतर लेकिन 15 फीट से कम नहीं रुकना चाहिए। स्रोत: Vermont CDL Manual (Railroad-Highway Crossings); 49 CFR 392.10।"},"66":{"q":"जब एक Vermont वाणिज्यिक वाहन रेलमार्ग पटरियों को पार कर रहा हो, तो CDL मैनुअल चालक को क्या न करने का निर्देश देता है?","options":["दोनों हाथ स्टीयरिंग व्हील पर रखना","रुक जाने से बचने के लिए पर्याप्त नीचे के गियर में पार करना","प्रवेश करने से पहले दोनों दिशाओं में देखना और सुनना","जब वाहन का कोई भी हिस्सा पटरियों पर हो तब गियर बदलना"],"explanation":"Vermont CDL Manual चालकों को पटरियों को पार करते समय कभी भी गियर न बदलने का निर्देश देता है, क्योंकि गियर बदलने से क्रॉसिंग पर रुक जाने का जोखिम होता है। चालक को पटरियों तक पहुंचने से पहले एक गियर चुनना चाहिए और साफ निकलने तक उसे नहीं बदलना चाहिए। स्रोत: Vermont CDL Manual (Railroad-Highway Crossings)।"},"67":{"q":"इससे पहले कि एक Vermont CMV चालक रेलमार्ग क्रॉसिंग को पार करना शुरू करे, मैनुअल कहता है कि चालक को यह सुनिश्चित करना चाहिए कि दूर वाली ओर पर्याप्त जगह हो ताकि वाहन:","options":["रेल के बीच कम से कम एक एक्सल शेष रहे","आने वाली ट्रेनों की जांच के लिए पटरियों पर रुक सके","अपने सामने के बंपर के साथ दूसरी रेल पर रुक सके","बिना उन पर रुके पटरियों को पूरी तरह से साफ कर सके"],"explanation":"Vermont CDL Manual चेतावनी देता है कि चालक को कभी भी पटरियों को पार करना शुरू नहीं करना चाहिए जब तक यह सुनिश्चित न हो जाए कि वाहन बिना रुके पूरी तरह से पार हो सकता है। चालक के पास दूर वाली ओर क्रॉसिंग को पूरी तरह साफ करने के लिए जगह होनी चाहिए। स्रोत: Vermont CDL Manual (Railroad-Highway Crossings)।"},"68":{"q":"एक Vermont CMV एक समतल, सीधी दो-लेन सड़क पर रुका हुआ है। तीन चेतावनी उपकरण (परावर्तक त्रिकोण) कहां रखे जाते हैं?","options":["पीछे की ओर लगभग 25 फीट, 75 फीट, और 150 फीट","पीछे की ओर लगभग 50 फीट, 150 फीट, और 300 फीट","आने वाले यातायात की ओर पीछे लगभग 10 फीट, 100 फीट, और 200 फीट","पीछे की ओर लगभग 10 फीट, 50 फीट, और 100 फीट"],"explanation":"Vermont में प्रयुक्त FMCSA/CDL मानक के अनुसार, एक दो-लेन सड़क पर त्रिकोण वाहन के लगभग 10 फीट सीधे पीछे, पीछे की ओर लगभग 100 फीट, और आने वाले यातायात की दिशा में पीछे की ओर लगभग 200 फीट रखे जाते हैं। स्रोत: Vermont CDL Manual (Stopping on the Road); 49 CFR 392.22।"},"69":{"q":"यदि एक Vermont CMV किसी पहाड़ी, मोड़, या दृश्य में अन्य बाधा के 500 फीट के भीतर रुका हुआ है, तो चेतावनी उपकरणों को कैसे समायोजित किया जाना चाहिए?","options":["पर्याप्त चेतावनी देने के लिए वाहन से 100 से 500 फीट बाधा की ओर एक उपकरण रखें","कोई त्रिकोण आवश्यक नहीं है क्योंकि खतरा दृश्यमान है","सभी तीन उपकरण वाहन के सीधे पीछे 10 फीट के भीतर रखें","बाधा से ठीक 700 फीट आगे एक उपकरण रखें"],"explanation":"Vermont CDL Manual (49 CFR 392.22 के अनुसार) निर्देश देता है कि यदि कोई स्टॉप किसी मोड़, पहाड़ी की चोटी, या अन्य दृश्य बाधा के 500 फीट के भीतर है, तो चालक सबसे पीछे वाले चेतावनी उपकरण को बाधा की ओर ले जाता है ताकि वह वाहन से 100 से 500 फीट पर खड़ा रहे। स्रोत: Vermont CDL Manual; 49 CFR 392.22।"},"70":{"q":"जब तक अन्यथा घोषित न हो, Vermont के सीमित-पहुंच (अंतरराज्यीय) राजमार्ग पर किसी भी मोटर वाहन के लिए अधिकतम कानूनी गति सीमा क्या है?","options":["55 mph","65 mph","60 mph","70 mph"],"explanation":"Vermont का सीमित-पहुंच राजमार्ग विनियमन अधिकतम 65 mph निर्धारित करता है: 'सीमित-पहुंच राजमार्गों पर किसी भी मोटर वाहन को चलाने की अधिकतम गति सीमा पैंसठ (65) मील प्रति घंटा होगी,' जब तक अन्यथा घोषित न हो। स्रोत: Code Vt. R. 14-053-004 (limited-access facilities); 23 V.S.A. § 1081।"},"71":{"q":"किसी घोषित सीमा या सीमित-पहुंच पदनाम के अभाव में, राजमार्ग पर Vermont की डिफ़ॉल्ट वैधानिक अधिकतम गति क्या है?","options":["65 mph","50 mph","45 mph","55 mph"],"explanation":"23 V.S.A. § 1081 राजमार्गों पर 50 mph की एक डिफ़ॉल्ट अधिकतम स्थापित करता है, जब तक कि कोई अलग सीमा घोषित न हो या क़ानून के तहत निर्धारित न हो। उच्च सीमाएं (65 mph तक) केवल Traffic Committee के अधिकार से सीमित-पहुंच राजमार्गों पर लागू होती हैं। स्रोत: 23 V.S.A. § 1081।"},"72":{"q":"क्या Vermont अपने राजमार्गों पर ट्रकों और वाणिज्यिक वाहनों के लिए कारों की तुलना में एक अलग, कम अधिकतम गति सीमा निर्धारित करता है?","options":["नहीं — घोषित सीमा सभी वाहनों पर लागू होती है; कोई अलग ट्रक गति सीमा नहीं है","हां — ट्रकों को अंतरराज्यीय मार्गों पर 60 mph तक सीमित किया गया है","हां — ट्रकों को हर जगह 55 mph तक सीमित किया गया है","हां — ट्रकों को घोषित कार सीमा से 10 mph नीचे रहना चाहिए"],"explanation":"Vermont एक अलग, कम ट्रक गति सीमा नहीं लगाता। वही अधिकतम (उदा., सीमित-पहुंच राजमार्गों पर 65 mph, डिफ़ॉल्ट 50 mph) सभी मोटर वाहनों पर लागू होती है, जिसमें ट्रक और बसें शामिल हैं। स्रोत: 23 V.S.A. § 1081; Code Vt. R. 14-053-004।"},"73":{"q":"एक Vermont सीमित-पहुंच राजमार्ग पर, एक ट्रक या बस ढलान के कारण घोषित न्यूनतम गति से नीचे केवल तभी चल सकता है यदि वह:","options":["ऐसा करते समय अपने चार-तरफा चमकते सिग्नल प्रदर्शित करे","पूरी तरह से बाएं किनारे पर चला जाए","अपना हॉर्न लगातार बजाए","पहले एक अतिविशाल यात्रा परमिट प्राप्त करे"],"explanation":"Vermont का सीमित-पहुंच विनियमन मोटर ट्रकों और बसों को न्यूनतम-गति नियम से छूट देता है जब ढलान उस गति को अव्यावहारिक बना देती है, लेकिन केवल तभी जब वाहन उस समय के दौरान चार-तरफा चमकते सिग्नल प्रदर्शित करे। स्रोत: Code Vt. R. 14-053-004 (limited-access facilities)।"},"74":{"q":"Smugglers' Notch के माध्यम से Vermont Route 108 किन वाहनों के लिए बंद है?","options":["8 फीट 6 इंच से चौड़ा कोई भी वाहन","40 फीट से अधिक के सिंगल-फ्रेम वाहन और 45 फीट से अधिक कुल लंबाई वाले ट्रैक्टर-ट्रेलर संयोजन","26,000 पाउंड GVWR से अधिक के सभी वाहन","15 से अधिक यात्रियों को ले जाने वाली बसें"],"explanation":"23 V.S.A. § 1006b 40 फीट से अधिक लंबाई के सिंगल-फ्रेम मोटर वाहनों, और एक या अधिक ट्रेलरों वाले ट्रैक्टर इकाइयों जो कुल 45 फीट से अधिक हैं, को Vermont Route 108 के Smugglers' Notch खंड से प्रतिबंधित करता है। संकरा पर्वतीय दर्रा उन्हें समायोजित नहीं कर सकता। स्रोत: 23 V.S.A. § 1006b; Vermont Agency of Transportation (vtrans.vermont.gov/notch)।"},"75":{"q":"एक ट्रक चालक जो GPS की अनदेखी करता है और Vermont Route 108 पर Smugglers' Notch में एक ट्रैक्टर-ट्रेलर को फंसा देता है, उसे एक नागरिक दंड का सामना करना पड़ता है जो, यातायात को पर्याप्त रूप से अवरुद्ध करने के लिए, 1 जुलाई, 2026 को बढ़कर इतना होने वाला है:","options":["$2,000","$50,000","$20,000","$5,000"],"explanation":"23 V.S.A. § 1006b के तहत आधार जुर्माना $1,000 था, या यदि उल्लंघन यातायात को पर्याप्त रूप से बाधित करता है तो $2,000; विधान इन्हें 1 जुलाई, 2026 से प्रभावी रूप से बढ़ाकर $10,000 और $20,000 (यातायात-अवरोधन) कर देता है। स्रोत: 23 V.S.A. § 1006b; Vermont Agency of Transportation।"},"76":{"q":"अतिविशाल परमिट के बिना, Vermont राजमार्गों पर अधिकतम कानूनी वाहन चौड़ाई क्या है?","options":["8 फीट 0 इंच","8 फीट 6 इंच","10 फीट 0 इंच","9 फीट 0 इंच"],"explanation":"परमिट के बिना Vermont की कानूनी अधिकतम वाहन चौड़ाई 8 फीट 6 इंच (102 inches) है; कानूनी ऊंचाई 13 फीट 6 इंच है और कानूनी सकल वजन 80,000 पाउंड है। इनसे अधिक होने पर एक DMV Commercial Vehicle Operations अतिविशाल/अतिभार परमिट की आवश्यकता होती है। स्रोत: Vermont DMV CVO Oversize/Overweight Permit Rules (CVO-110)।"},"77":{"q":"Vermont अतिविशाल/अतिभार परमिट आम तौर पर किन घंटों के दौरान ही आवागमन को अधिकृत करते हैं?","options":["सूर्योदय से आधा घंटा पहले से सूर्यास्त के आधा घंटा बाद तक","केवल मध्यरात्रि और सुबह 6:00 बजे के बीच","बिना किसी प्रतिबंध के दिन में 24 घंटे","केवल सप्ताहांत और कानूनी छुट्टियों पर"],"explanation":"Vermont के परमिट नियम अतिविशाल/अतिभार यात्रा को दिन के उजाले के घंटों तक सीमित करते हैं: सूर्योदय से आधा घंटा पहले से सूर्यास्त के आधा घंटा बाद तक, सबसे बड़े भार पर सप्ताहांत और छुट्टियों के दौरान अतिरिक्त प्रतिबंधों के साथ। स्रोत: Vermont DMV CVO Oversize/Overweight Permit Rules (CVO-110)।"},"78":{"q":"एक Vermont सड़क-मार्ग पर, यातायात की सामान्य गति से धीमे चलने वाले ट्रक को कहां चलाया जाना चाहिए?","options":["उपलब्ध दाएं-हाथ की लेन में, या दाएं किनारे के यथासंभव निकट, सिवाय जब आगे निकल रहे हों या बाएं मुड़ने की तैयारी कर रहे हों","बाईं लेन में ताकि तेज यातायात दाईं ओर मर्ज कर सके","जब तक यातायात साफ न हो जाए तब तक पक्के किनारे पर","किसी भी बहु-लेन सड़क की केंद्र लेन में हर समय"],"explanation":"Vermont का keep-right नियम यातायात की सामान्य गति से नीचे चलने वाले वाहन को दाएं-हाथ की लेन में, या दाएं कर्ब या किनारे के यथासंभव निकट चलाने की आवश्यकता है, सिवाय जब आगे निकल रहे और पास कर रहे हों या बाएं मोड़ की तैयारी कर रहे हों। स्रोत: 23 V.S.A. § 1038 / § 1031।"},"79":{"q":"Vermont कानून के तहत, सर्दियों के मौसम के दौरान निर्दिष्ट राज्य राजमार्गों पर कौन टायर चेन की आवश्यकता कर सकता है, और किन वाहनों के लिए?","options":["चेन केवल नगर सड़कों पर आवश्यक हैं, कभी भी राज्य राजमार्गों पर नहीं","केवल संघीय सरकार चेन अनिवार्य कर सकती है, और केवल अंतरराज्यीय मार्गों पर","राज्य अधिकारी निर्दिष्ट राजमार्ग भागों पर 26,000 पाउंड GVWR या GCWR से अधिक के वाहनों के लिए चेन की आवश्यकता कर सकते हैं","दिसंबर से मार्च तक हर यात्री कार के लिए चेन अनिवार्य हैं"],"explanation":"23 V.S.A. § 1006c, Secretary of Transportation, Commissioner of Motor Vehicles, या Commissioner of Public Safety (या नामितों) को सर्दियों के मौसम के दौरान राज्य राजमार्गों के निर्दिष्ट भागों पर 26,000 पाउंड GVWR या GCWR से अधिक के वाहनों के लिए टायर चेन की आवश्यकता करने का अधिकार देता है, अग्रिम साइनेज के साथ। स्रोत: 23 V.S.A. § 1006c।"},"80":{"q":"Vermont में, कौन-सी एजेंसी वाणिज्यिक चालक लाइसेंस (CDLs) जारी करती है और आवश्यक परीक्षण आयोजित करती है?","options":["Vermont Department of Motor Vehicles (DMV)","Vermont Agency of Transportation (VTrans)","Federal Motor Carrier Safety Administration (FMCSA)","Vermont State Police Commercial Vehicle Unit"],"explanation":"Vermont Department of Motor Vehicles (DMV) राज्य में CDLs जारी करता है और ज्ञान तथा कौशल परीक्षण आयोजित करता है। FMCSA संघीय CDL मानक निर्धारित करता है लेकिन लाइसेंस जारी नहीं करता। स्रोत: Vermont DMV, Commercial Driver's License (CDL) पेज; Vermont CDL Driver Manual (VN-111)।"},"81":{"q":"इससे पहले कि कोई व्यक्ति Vermont में CDL कौशल परीक्षण दे सके, उसे पहले कौन-सा परमिट प्राप्त करना और रखना चाहिए?","options":["एक Commercial Learner's Permit (CLP)","केवल एक नियमित Vermont learner's permit","एक अस्थायी अंतरराज्यीय परिचालन परमिट","एक अतिविशाल/अतिभार लोड परमिट"],"explanation":"Vermont आवेदकों से एक Commercial Learner's Permit (CLP) प्राप्त करने की आवश्यकता रखता है, जो कौशल परीक्षण से पहले एक वाणिज्यिक मोटर वाहन में पर्यवेक्षित अभ्यास को अधिकृत करता है। स्रोत: Vermont DMV, Commercial Driver's Learner Permit (CLP) पेज; Vermont CDL Driver Manual (VN-111)।"},"82":{"q":"Vermont में Commercial Learner's Permit प्राप्त करने के बाद, चालक को CDL कौशल परीक्षण देने से पहले इसे कम से कम कितने दिनों तक रखना चाहिए?","options":["14 days","7 days","30 days","60 days"],"explanation":"एक CLP धारक को CDL के लिए कौशल परीक्षण देने से पहले CLP जारी होने के बाद कम से कम 14 days प्रतीक्षा करनी चाहिए। स्रोत: Vermont DMV, Commercial Driver's Learner Permit (CLP) और Renewals/Transfers/Upgrades पेज; संघीय 49 CFR 383.25।"},"83":{"q":"Vermont CDL कौशल परीक्षण किन तीन भागों से बना है?","options":["Pre-trip निरीक्षण, बुनियादी वाहन नियंत्रण, और ऑन-रोड ड्राइविंग","लिखित ज्ञान परीक्षण, आंखों की जांच, और ऑन-रोड ड्राइविंग","एयर ब्रेक जांच, hazmat हैंडलिंग, और रात की ड्राइविंग","Pre-trip निरीक्षण, समानांतर पार्किंग, और एक राजमार्ग-गति परीक्षण"],"explanation":"Vermont के CDL कौशल परीक्षण के तीन भाग हैं, जिन सभी को पास करना होगा: pre-trip वाहन निरीक्षण, बुनियादी वाहन नियंत्रण युक्तियां, और ऑन-रोड ड्राइविंग परीक्षण। स्रोत: Vermont DMV CDL पेज; Vermont CDL Driver Manual (VN-111)।"},"84":{"q":"Vermont DMV के साथ अपनी ड्राइविंग के प्रकार और चिकित्सा स्थिति को स्व-प्रमाणित करने के लिए चालक कौन-सा फॉर्म जमा करता है?","options":["CDL Medical Certification फॉर्म (VL-033)","केवल संघीय Medical Examiner's Certificate","फिटनेस का नोटरीकृत शपथपत्र","TSA खतरनाक सामग्री पृष्ठभूमि फॉर्म"],"explanation":"Vermont CDL धारक और आवेदक CDL Medical Certification फॉर्म, VL-033, को पूरा करके और DMV को जमा करके अपने ड्राइविंग प्रकार और चिकित्सा स्थिति को स्व-प्रमाणित करते हैं। स्रोत: Vermont DMV, CDL Medical Requirements पेज और Form VL-033।"},"85":{"q":"Vermont DMV के साथ स्व-प्रमाणन करते समय, एक CDL आवेदक कितनी ड्राइविंग श्रेणियों में से चुन सकता है?","options":["चार","दो","तीन","पांच"],"explanation":"चार स्व-प्रमाणन श्रेणियां हैं: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), और Excepted Intrastate (EA)। चालक Form VL-033 पर एक का चयन करता है। स्रोत: Vermont DMV CDL Medical Certification (Form VL-033); 49 CFR 383.71।"},"86":{"q":"एक Vermont CDL आवेदक जो अंतरराज्यीय वाणिज्य में गाड़ी चलाता है और संघीय शारीरिक योग्यता नियमों (49 CFR Part 391) के अधीन है, उसे किस श्रेणी के रूप में स्व-प्रमाणित करना चाहिए?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"एक चालक जो अंतरराज्यीय वाणिज्य में संचालन करता है और 49 CFR Part 391 के अधीन है, वह Non-Excepted Interstate (NI) के रूप में स्व-प्रमाणित करता है और उसे एक वर्तमान Medical Examiner's Certificate प्रदान करना चाहिए। स्रोत: Vermont DMV Form VL-033; 49 CFR 383.71।"},"87":{"q":"Vermont में कौन-सी स्व-प्रमाणन श्रेणी के लिए चालक को एक वर्तमान 'Vermont Only' Medical Examiner's Certificate प्रदान करने की आवश्यकता होती है?","options":["Non-Excepted Intrastate (NA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)"],"explanation":"एक Non-Excepted Intrastate (NA) चालक केवल Vermont के भीतर ही संचालन करता है और उसे एक वर्तमान 'Vermont Only' Medical Examiner's Certificate प्रदान करके चिकित्सा मानकों को पूरा करना चाहिए। स्रोत: Vermont DMV CDL Medical Certification (Form VL-033)।"},"88":{"q":"Vermont में स्वीकृत CDL Medical Examiner's Certificate उत्पन्न करने वाली DOT शारीरिक परीक्षा करने के लिए कौन अधिकृत है?","options":["FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध एक चिकित्सा परीक्षक","चालक द्वारा चुना गया कोई भी लाइसेंस प्राप्त चिकित्सक","परीक्षण स्थल पर एक Vermont DMV परीक्षक","चालक के नियोक्ता का सुरक्षा अधिकारी"],"explanation":"शारीरिक परीक्षा FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध एक चिकित्सा परीक्षक द्वारा की जानी चाहिए। स्रोत: Vermont DMV, CDL Medical Requirements पेज; 49 CFR 390.103 / Part 391।"},"89":{"q":"एक Vermont CDL धारक के लिए एक मानक DOT Medical Examiner's Certificate अधिकतम कितनी अवधि के लिए वैध हो सकता है?","options":["2 years तक","1 year तक","3 years तक","5 years तक"],"explanation":"एक मानक Medical Examiner's Certificate 2 years तक के लिए वैध है, हालांकि यदि किसी स्थिति की निगरानी की आवश्यकता हो तो एक परीक्षक छोटी अवधि के लिए जारी कर सकता है। स्रोत: Vermont DMV, CDL Medical Requirements पेज; 49 CFR Part 391।"},"90":{"q":"यदि धारक DMV के पास एक वर्तमान चिकित्सा प्रमाणपत्र फाइल पर रखने में विफल रहता है तो एक Vermont CDL के साथ क्या हो सकता है?","options":["CDL को डाउनग्रेड किया जा सकता है या ड्राइविंग विशेषाधिकार निलंबित किया जा सकता है","कुछ नहीं, जब तक कि लाइसेंस स्वयं समाप्त न हो गया हो","चालक को स्वचालित रूप से Excepted Interstate स्थिति जारी की जाती है","केवल एक लिखित चेतावनी डाक से भेजी जाती है जिसका लाइसेंस पर कोई प्रभाव नहीं होता"],"explanation":"यदि वर्तमान चिकित्सा दस्तावेज़ीकरण फाइल पर बनाए नहीं रखा जाता है, तो Vermont DMV CDL को डाउनग्रेड कर सकता है (वाणिज्यिक विशेषाधिकार हटा सकता है) और/या ड्राइविंग विशेषाधिकार निलंबित कर सकता है। स्रोत: Vermont DMV, CDL Medical Requirements पेज; 49 CFR 383.73।"},"91":{"q":"Vermont कौशल परीक्षण देने की अनुमति मिलने से पहले एक पहली बार Class A या Class B CDL आवेदक को कौन-सा प्रशिक्षण पूरा करना चाहिए?","options":["एक FMCSA-पंजीकृत प्रदाता से Entry-Level Driver Training (ELDT)","Vermont DMV द्वारा अनुमोदित एक रक्षात्मक ड्राइविंग पाठ्यक्रम","DMV द्वारा पढ़ाया जाने वाला आठ-घंटे का कक्षा पाठ्यक्रम","केवल नियोक्ता के साथ दर्ज की गई एक प्रशिक्षुता"],"explanation":"पहली बार के Class A/B आवेदकों (और कुछ एंडोर्समेंट) को CDL कौशल परीक्षण देने से पहले FMCSA Training Provider Registry पर एक प्रदाता से Entry-Level Driver Training (ELDT) पूरा करना चाहिए। स्रोत: Vermont DMV CDL पेज; 49 CFR Part 380 Subpart F।"},"92":{"q":"एक पहली बार HazMat (H) एंडोर्समेंट के लिए, आवश्यक Entry-Level Driver Training कब पूरा किया जाना चाहिए?","options":["HazMat ज्ञान परीक्षण देने से पहले","केवल ऑन-रोड कौशल परीक्षण से पहले","लाइसेंस जारी होने के 30 दिनों के भीतर","केवल TSA पृष्ठभूमि जांच अनुमोदित होने के बाद"],"explanation":"चूंकि HazMat एंडोर्समेंट का कोई कौशल परीक्षण नहीं है, इसलिए एक पहली बार के H एंडोर्समेंट के लिए ELDT आवेदक द्वारा HazMat ज्ञान परीक्षण देने से पहले पूरा किया जाना चाहिए। स्रोत: Vermont DMV CDL पेज; 49 CFR Part 380 Subpart F।"},"93":{"q":"वर्ग या एंडोर्समेंट की परवाह किए बिना हर Vermont CDL आवेदक को कौन-सा ज्ञान परीक्षण पास करना चाहिए?","options":["General Knowledge परीक्षण","Air Brakes परीक्षण","Combination Vehicles परीक्षण","Hazardous Materials परीक्षण"],"explanation":"हर CDL आवेदक को General Knowledge लिखित परीक्षण पास करना चाहिए; Air Brakes, Combination Vehicles, और एंडोर्समेंट परीक्षण जैसे अतिरिक्त परीक्षण केवल वाहन या एंडोर्समेंट के अनुसार प्रासंगिक होने पर ही लागू होते हैं। स्रोत: Vermont CDL Driver Manual (VN-111); Vermont DMV CDL पेज।"},"94":{"q":"एक Vermont CDL ज्ञान (लिखित) परीक्षण पास करने के लिए न्यूनतम कितना स्कोर आवश्यक है?","options":["80 percent","70 percent","75 percent","90 percent"],"explanation":"Vermont CDL ज्ञान परीक्षणों के लिए कम से कम 80 percent प्रश्नों के सही उत्तर के साथ एक उत्तीर्ण स्कोर आवश्यक है। स्रोत: Vermont CDL Driver Manual (VN-111); Vermont DMV CDL परीक्षण जानकारी।"},"95":{"q":"एक Vermont CDL को किस विधि का उपयोग करके नवीनीकृत किया जाना चाहिए?","options":["एक Vermont DMV कार्यालय में व्यक्तिगत रूप से","केवल DMV वेबसाइट के माध्यम से ऑनलाइन","केवल नवीनीकरण नोटिस का उपयोग करके डाक द्वारा","स्वचालित रूप से, चालक द्वारा बिना किसी कार्रवाई के"],"explanation":"एक CDL को एक Vermont DMV ग्राहक सेवा कार्यालय में व्यक्तिगत रूप से नवीनीकृत किया जाना चाहिए; चालक हस्ताक्षरित नवीनीकरण नोटिस और शुल्क लाता है। स्रोत: Vermont DMV, Renewals, Transfers & Upgrades पेज।"},"96":{"q":"एक Vermont CDL को एक बार में कितने वर्षों के लिए नवीनीकृत किया जा सकता है?","options":["दो या चार वर्ष","एक या दो वर्ष","पांच वर्ष","आठ वर्ष"],"explanation":"Vermont CDL नवीनीकरण दो-वर्षीय या चार-वर्षीय चक्र पर जारी किए जाते हैं, वर्तमान क्रेडेंशियल पर शेष किसी भी पूर्ण वर्ष को नवीनीकरण शुल्क की ओर श्रेय दिया जाता है। स्रोत: Vermont DMV, Renewals, Transfers & Upgrades पेज।"},"97":{"q":"किसी अन्य राज्य से एक वैध CDL रखने वाला व्यक्ति जो Vermont में स्थानांतरित होता है, उसे निवास स्थापित करने के बाद कितने समय के भीतर इसे एक Vermont CDL में स्थानांतरित करना चाहिए?","options":["30 days","10 days","60 days","90 days"],"explanation":"राज्य और संघीय कानून के तहत, एक राज्य-बाहरी CDL रखने वाले व्यक्ति को Vermont निवास स्थापित करने के 30 days के भीतर इसे एक Vermont CDL में स्थानांतरित करना चाहिए। स्रोत: Vermont DMV, Renewals, Transfers & Upgrades पेज; 49 CFR 383.71।"},"98":{"q":"एक मौजूदा Vermont CDL को एक उच्च वर्ग में अपग्रेड करते समय, चालक को परमिट के संबंध में क्या करना चाहिए?","options":["एक Commercial Learner's Permit प्राप्त करें और इसे कम से कम 14 दिनों तक रखें","कुछ नहीं; अपग्रेड के लिए परीक्षण देने हेतु मौजूदा CDL पर्याप्त है","केवल एक नियमित ऑपरेटर का learner permit प्राप्त करें","नए परमिट को कम से कम 90 दिनों तक रखें"],"explanation":"एक उच्च CDL वर्ग में अपग्रेड करने के लिए, चालक को एक Commercial Learner's Permit प्राप्त करना चाहिए, इसे कम से कम 14 दिनों तक रखना चाहिए, और उपयुक्त ज्ञान तथा कौशल परीक्षण पास करने चाहिए। स्रोत: Vermont DMV, Renewals, Transfers & Upgrades पेज।"},"99":{"q":"Vermont DMV CDL आवेदकों को प्रकाशित लाइसेंस और परीक्षण शुल्क को परिवर्तन के अधीन मानने की सलाह क्यों देता है?","options":["शुल्क राशि क़ानून और DMV अनुसूचियों द्वारा निर्धारित होती है जिन्हें संशोधित किया जा सकता है, इसलिए वर्तमान घोषित शुल्क की हमेशा पुष्टि की जानी चाहिए","Vermont CDL सेवाओं के लिए कोई शुल्क नहीं लेता, इसलिए कोई भी घोषित राशि एक त्रुटि है","प्रत्येक आवेदक के लिए शुल्क काउंटर पर व्यक्तिगत रूप से बातचीत किए जाते हैं","केवल संघीय सरकार, Vermont नहीं, CDL शुल्क निर्धारित या बदल सकती है"],"explanation":"CDL और परीक्षण शुल्क Vermont क़ानून और DMV शुल्क अनुसूचियों द्वारा स्थापित होते हैं जिन्हें अद्यतन किया जा सकता है, इसलिए आवेदकों को एक निश्चित आंकड़े पर भरोसा करने के बजाय DMV के साथ वर्तमान राशि की पुष्टि करनी चाहिए। स्रोत: Vermont DMV शुल्क जानकारी; 23 V.S.A. (मोटर वाहन शुल्क क़ानून)।"}},"ar":{"0":{"q":"ما هو الحد الأقصى القانوني لعرض المركبة على طرق فيرمونت السريعة قبل أن يصبح تصريح تجاوز العرض مطلوباً؟","options":["8 أقدام (96 إنشاً)","8 أقدام و6 إنشات (102 إنش)","9 أقدام (108 إنشات)","8 أقدام و4 إنشات (100 إنش)"],"explanation":"بموجب 23 V.S.A. § 1431، يبلغ الحد الأقصى لعرض المركبة في فيرمونت 8 أقدام و6 إنشات (102 إنش)، باستثناء أجهزة السلامة مثل المرايا التي تمتد حتى 3 إنشات في كل جانب. أي مركبة أعرض من ذلك تحتاج إلى تصريح تجاوز الأبعاد من DMV. المصدر: 23 V.S.A. § 1431."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة على طرق فيرمونت السريعة دون تصريح؟","options":["13 قدماً","14 قدماً","13 قدماً و6 إنشات","12 قدماً و6 إنشات"],"explanation":"يحدد 23 V.S.A. § 1431 الحد الأقصى لارتفاع المركبة بـ 13 قدماً و6 إنشات. تتطلب الأحمال التي تتجاوز ذلك تصريح تجاوز الأبعاد من Vermont DMV. المصدر: 23 V.S.A. § 1431."},"2":{"q":"في فيرمونت، ما هو الحد الأقصى للطول الإجمالي لمركبة آلية مفردة (دون مقطورة أو نصف مقطورة متصلة) دون إذن خاص؟","options":["40 قدماً","53 قدماً","46 قدماً","48 قدماً"],"explanation":"بموجب 23 V.S.A. § 1432، لا يجوز تشغيل أي مركبة آلية بدون مقطورة أو نصف مقطورة متصلة يزيد طولها الإجمالي عن 46 قدماً على طريق فيرمونت السريع إلا بإذن خاص. المصدر: 23 V.S.A. § 1432."},"3":{"q":"ما هو الحد الأقصى للطول الإجمالي لمجموعة مركبات (شاحنة مع مقطورة أو نصف مقطورة) على طريق فيرمونت السريع العام دون تصريح تجاوز الطول؟","options":["65 قدماً","75 قدماً","70 قدماً","80 قدماً"],"explanation":"بموجب 23 V.S.A. § 1432، يمكن لمجموعات المركبات التي لا يتجاوز طولها الإجمالي 75 قدماً أن تعمل على طرق فيرمونت السريعة دون تصريح؛ أما المجموعات الأطول فتتطلب تصريح تجاوز الطول. المصدر: 23 V.S.A. § 1432."},"4":{"q":"على الطرق السريعة بين الولايات والشبكة الوطنية المخصصة في فيرمونت، ما هو الحد الأقصى المسموح به لطول نصف المقطورة في مجموعة جرار-نصف مقطورة؟","options":["48 قدماً","53 قدماً","45 قدماً","57 قدماً"],"explanation":"على نظام الطرق السريعة بين الولايات والطرق المخصصة المؤهلة، تطبق فيرمونت حدود طول المكونات الفيدرالية بدلاً من سقف الطول الإجمالي: يمكن أن يصل طول نصف المقطورة في مجموعة جرار-نصف مقطورة إلى 53 قدماً. المصدر: 23 V.S.A. § 1432."},"5":{"q":"بالنسبة لمجموعة جرار-نصف مقطورة-مقطورة (مقطورة مزدوجة) على شبكة طرق فيرمونت السريعة المخصصة، ما هو الحد الأقصى لطول كل مقطورة أو نصف مقطورة؟","options":["28 قدماً لكل واحدة","30 قدماً لكل واحدة","27 قدماً لكل واحدة","33 قدماً لكل واحدة"],"explanation":"على شبكة الطرق السريعة بين الولايات والشبكة المخصصة، تخضع مجموعات المقطورات المزدوجة لحدود المكونات الفيدرالية: يمكن أن يصل طول كل مقطورة أو نصف مقطورة إلى 28 قدماً. المصدر: 23 V.S.A. § 1432 (متوافق مع معايير STAA الفيدرالية)."},"6":{"q":"ما هو الحد الأقصى للوزن الإجمالي للمركبة على طرق فيرمونت السريعة لمركبة تجارية قياسية دون تصريح خاص؟","options":["73,280 رطلاً","80,000 رطل","90,000 رطل","84,000 رطل"],"explanation":"بموجب 23 V.S.A. § 1392، يبلغ الحد الأقصى للوزن الإجمالي للمركبة 80,000 رطل. تتطلب الأحمال الأثقل تصريح زيادة الوزن من DMV أو فئة تصريح خاص قانونية. المصدر: 23 V.S.A. § 1392."},"7":{"q":"على نظام الطرق السريعة الفيدرالية بين الولايات في فيرمونت، ما هو الحد الأقصى لوزن المحور المفرد، دون السماح بأي هامش تفاوت؟","options":["22,400 رطلاً","18,000 رطل","20,000 رطل","21,000 رطل"],"explanation":"بموجب 23 V.S.A. § 1391، على الطرق السريعة بين الولايات (نظام أيزنهاور الوطني للطرق السريعة بين الولايات والدفاع) يكون حد المحور المفرد 20,000 رطل دون السماح بأي هامش تفاوت، بما يتطابق مع القانون الفيدرالي. المصدر: 23 V.S.A. § 1391."},"8":{"q":"على نظام الطرق السريعة بين الولايات في فيرمونت، ما هو الحد الأقصى لوزن المحور المزدوج (الترادفي)، دون السماح بأي هامش تفاوت؟","options":["36,000 رطل","34,000 رطل","32,000 رطل","38,000 رطل"],"explanation":"بموجب 23 V.S.A. § 1391، على نظام الطرق السريعة بين الولايات يكون حد المحور المزدوج (الترادفي) 34,000 رطل دون السماح بأي هامش تفاوت، بما يتوافق مع معايير الوزن الفيدرالية. المصدر: 23 V.S.A. § 1391."},"9":{"q":"على طرق فيرمونت السريعة غير الواقعة بين الولايات (طرق الولاية والبلدات)، ما هو الحد الأقصى لوزن المحور المفرد قبل تطبيق هامش التفاوت البالغ 10 بالمئة؟","options":["20,000 رطل","24,000 رطل","22,400 رطلاً","21,500 رطلاً"],"explanation":"بموجب 23 V.S.A. § 1391، على طرق فيرمونت السريعة غير الواقعة بين الولايات يكون حد المحور المفرد 22,400 رطل، مع السماح بهامش تفاوت 10 بالمئة. المصدر: 23 V.S.A. § 1391."},"10":{"q":"على طرق فيرمونت السريعة غير الواقعة بين الولايات، ما هو الحد الأقصى لوزن المحور المزدوج (الترادفي) قبل تطبيق هامش التفاوت البالغ 10 بالمئة؟","options":["34,000 رطل","36,000 رطل","32,000 رطل","40,000 رطل"],"explanation":"بموجب 23 V.S.A. § 1391، على طرق فيرمونت السريعة غير الواقعة بين الولايات يكون حد المحور المزدوج (الترادفي) 36,000 رطل، مع السماح بهامش تفاوت 10 بالمئة (وهو اختلاف رئيسي خاص بالولاية عن حد 34,000 رطل على الطرق بين الولايات). المصدر: 23 V.S.A. § 1391."},"11":{"q":"أحد الاختلافات الرئيسية بين قواعد وزن المحاور في فيرمونت على الطرق غير الواقعة بين الولايات وتلك الواقعة بينها هو هامش التفاوت. ما هو هامش التفاوت الذي ينطبق على حدود المحور المفرد والمزدوج على طرق فيرمونت السريعة غير الواقعة بين الولايات؟","options":["لا يُسمح بأي هامش تفاوت","يُسمح بهامش تفاوت 5 بالمئة","يُسمح بهامش تفاوت 10 بالمئة","يُسمح بهامش تفاوت 15 بالمئة"],"explanation":"بموجب 23 V.S.A. § 1391، تحمل حدود المحور المفرد (22,400 رطل) والمحور المزدوج (36,000 رطل) على الطرق غير الواقعة بين الولايات هامش تفاوت 10 بالمئة، في حين أن الحدود على الطرق بين الولايات (20,000 رطل / 34,000 رطل) لا تسمح بأي هامش تفاوت. المصدر: 23 V.S.A. § 1391."},"12":{"q":"ما هي المعادلة التي تستخدمها فيرمونت، بما يتوافق مع القانون الفيدرالي، لتحديد الحد الأقصى المسموح به للوزن الإجمالي لمجموعة من المحاور بناءً على تباعدها وعددها؟","options":["المعادلة الجسرية الفيدرالية (المعادلة B)","معادلة تصنيف الوزن الإجمالي للتركيبة","مؤشر التباعد الترادفي","معادلة تكافؤ حمل المحور"],"explanation":"تطبق فيرمونت المعادلة الجسرية الفيدرالية (المعادلة الجسرية B)، W = 500[LN/(N-1) + 12N + 36]، للحد من الوزن المحمول على أي مجموعة من المحاور بناءً على التباعد (L) وعدد المحاور (N)، بالإضافة إلى حدود المحور المفرد والمزدوج والحد الإجمالي البالغ 80,000 رطل. المصدر: المعادلة الجسرية الفيدرالية كما تطبق بموجب 23 V.S.A. ch. 13 / FHWA."},"13":{"q":"في المعادلة الجسرية الفيدرالية المستخدمة في فيرمونت، يُعامل محوران متتاليان على أنهما 'محور مزدوج' (بدلاً من محورين مفردين منفصلين) عندما يتباعد مركزاهما بأي مسافة؟","options":["أكثر من 40 إنشاً ولكن ليس أكثر من 96 إنشاً","أكثر من 96 إنشاً ولكن ليس أكثر من 120 إنشاً","ليس أكثر من 40 إنشاً","أكثر من 48 إنشاً ولكن ليس أكثر من 108 إنشات"],"explanation":"بموجب التعريفات الفيدرالية المطبقة في فيرمونت، المحور المزدوج هو محوران أو أكثر متتاليان يتباعد مركزاهما أكثر من 40 إنشاً ولكن ليس أكثر من 96 إنشاً؛ أما المحاور التي تتباعد 40 إنشاً أو أقل فتُعامل على أنها محور مفرد. المصدر: تعريفات المعادلة الجسرية الفيدرالية / FHWA، مطبقة بموجب 23 V.S.A. ch. 13."},"14":{"q":"متى يحتاج مشغل مركبة تجارية في فيرمونت عموماً إلى تصريح تجاوز الأبعاد أو زيادة الوزن من DMV؟","options":["فقط عند العبور إلى ولاية أخرى","عندما تتجاوز المركبة أو الحمل حدود العرض أو الارتفاع أو الطول أو الوزن القانونية","فقط عندما يتجاوز الوزن الإجمالي 100,000 رطل","فقط في الليل أو في ظروف الشتاء"],"explanation":"يكون تصريح تجاوز الأبعاد/زيادة الوزن من Vermont DMV مطلوباً كلما تجاوزت المركبة أو الحمل الحدود القانونية (العرض أكثر من 8'6\"، الارتفاع أكثر من 13'6\"، المركبة المفردة أكثر من 46 قدماً، المجموعة أكثر من 75 قدماً، أو حدود الوزن المطبقة). المصدر: 23 V.S.A. ch. 13 وقواعد تصاريح زيادة الوزن/تجاوز الأبعاد لـ Vermont DMV (Code Vt. R. 14-050-019)."},"15":{"q":"أي وكالة في فيرمونت تصدر تصاريح تجاوز الأبعاد وزيادة الوزن للسفر على طرق الولاية ونظام الطرق بين الولايات؟","options":["وكالة الموارد الطبيعية في فيرمونت","الإدارة الفيدرالية لسلامة الناقلين الآليين","إدارة المركبات الآلية في فيرمونت (عمليات المركبات التجارية)","قسم شرطة المقاطعة"],"explanation":"تصدر Vermont DMV، من خلال وحدة عمليات المركبات التجارية الخاصة بها (ونظام VT Haul Pass عبر الإنترنت)، تصاريح تجاوز الأبعاد وزيادة الوزن لطرق الولاية ونظام الطرق بين الولايات بموجب سلطة المفوض. المصدر: قواعد تصاريح زيادة الوزن/تجاوز الأبعاد لـ Vermont DMV CVO؛ 23 V.S.A. § 1400."},"16":{"q":"تحتاج شركة نقل بالشاحنات إلى نقل أحمال كبيرة الحجم غير قابلة للتجزئة بشكل متكرر على المسارات نفسها طوال العام. أي نوع من تصاريح فيرمونت يناسب هذه الحاجة بشكل أفضل؟","options":["تصريح رحلة واحدة","تصريح طوارئ","تصريح شامل (سنوي)","تصريح تسجيل فقط"],"explanation":"تصدر Vermont DMV تصاريح شاملة (سنوية) للتحركات المتكررة للأحمال غير القابلة للتجزئة، في حين تغطي تصاريح الرحلة الواحدة تحركاً واحداً ضمن نافذة محدودة (حوالي سبعة أيام عمل). المصدر: قواعد تصاريح زيادة الوزن/تجاوز الأبعاد لـ Vermont DMV (Code Vt. R. 14-050-019)."},"17":{"q":"بالنسبة للوزن الزائد عن الحدود القانونية على الطرق السريعة والجسور الخاضعة لاختصاص بلدية ما (بخلاف طرق البلدات من الفئة 1)، إلى من يجب تقديم طلب تصريح زيادة الوزن في فيرمونت؟","options":["مفوض Vermont DMV","الهيئة التشريعية المختصة بالبلدية (مثل مجلس المختارين)","الإدارة الفيدرالية للطرق السريعة","شرطة ولاية فيرمونت"],"explanation":"بموجب قواعد التصاريح في فيرمونت، بالنسبة للتشغيل الذي يتجاوز حدود الوزن على الطرق السريعة والجسور الخاضعة لاختصاص بلدية ما (باستثناء طرق البلدات من الفئة 1)، يُقدَّم الطلب إلى الهيئة التشريعية البلدية المختصة. المصدر: Code Vt. R. 14-050-019 (تصاريح المركبات الزائدة الوزن/المتجاوزة للأبعاد)."},"18":{"q":"تصريح الوزن الزائد الخاص في فيرمونت (تصريح سنوي للأحمال القابلة للتجزئة) يسمح بأي وزن أقصى على محور التوجيه؟","options":["10,000 رطل","12,000 رطل","14,000 رطل","20,000 رطل"],"explanation":"بموجب قاعدة تصريح الوزن الزائد الخاص في فيرمونت، تكون حدود المحاور 12,000 رطل على محور التوجيه و20,000 رطل على جميع المحاور الأخرى. المصدر: تصريح الوزن الزائد الخاص لـ Vermont DMV؛ Code Vt. R. 14-050-019."},"19":{"q":"يسمح قانون فيرمونت لبعض تركيبات الشاحنات ذات الستة محاور أو أكثر العاملة بموجب تصريح خاص سنوي بالوصول إلى أي وزن إجمالي مرتفع على الطرق السريعة غير الواقعة بين الولايات؟","options":["85,000 رطل","108,000 رطل","99,000 رطل","95,000 رطل"],"explanation":"بموجب 23 V.S.A. § 1392، يمكن للشاحنات ذات الستة محاور حاملة للحمل أو أكثر العاملة بموجب تصريح خاص سنوي أن تصل إلى وزن إجمالي 99,000 رطل على الطرق السريعة غير الواقعة بين الولايات؛ ولا ينطبق هذا السماح الخاص بفيرمونت على نظام الطرق بين الولايات ما لم يكن مصرحاً به بموجب القانون الفيدرالي. المصدر: 23 V.S.A. § 1392."},"20":{"q":"في فيرمونت، يُطلب الحصول على رخصة CDL من الفئة A لتشغيل أي مما يلي؟","options":["أي مجموعة من المركبات بتصنيف وزن إجمالي للتركيبة (GCWR) يبلغ 26,001 رطلاً أو أكثر، حيث تتجاوز الوحدة (الوحدات) المقطورة 10,000 رطل من تصنيف الوزن الإجمالي للمركبة (GVWR)","أي مركبة مفردة بتصنيف وزن إجمالي للمركبة (GVWR) يبلغ 26,001 رطلاً أو أكثر","أي مركبة مصممة لنقل 16 راكباً أو أكثر بما في ذلك السائق","أي مركبة من أي وزن تعرض لافتات المواد الخطرة"],"explanation":"تتبع فيرمونت التصنيف الفيدرالي لرخص CDL (49 CFR 383.91): الفئة A هي أي مجموعة من المركبات بتصنيف وزن إجمالي للتركيبة (GCWR) يبلغ 26,001 رطلاً أو أكثر بشرط أن يكون تصنيف الوزن الإجمالي (GVWR) للمركبة (المركبات) المقطورة أكثر من 10,000 رطل. المصدر: دليل CDL لفيرمونت (VN-111) / FMCSA 49 CFR 383.91."},"21":{"q":"بموجب قواعد فيرمونت، أي مركبات تغطيها رخصة CDL من الفئة B؟","options":["الحافلات التي تقل عن 16 راكباً فقط","أي مركبة مفردة بتصنيف وزن إجمالي للمركبة (GVWR) يبلغ 26,001 رطلاً أو أكثر، أو مثل هذه المركبة وهي تقطر وحدة لا تتجاوز 10,000 رطل","أي مجموعة تتجاوز فيها المقطورة 10,000 رطل من تصنيف الوزن الإجمالي (GVWR)","أي مركبة تتطلب فقط مصادقة المواد الخطرة"],"explanation":"تتبنى فيرمونت التعريف الفيدرالي: الفئة B هي أي مركبة مفردة بتصنيف وزن إجمالي للمركبة (GVWR) يبلغ 26,001 رطلاً أو أكثر، أو مثل هذه المركبة وهي تقطر مركبة أخرى لا تتجاوز 10,000 رطل من تصنيف الوزن الإجمالي (GVWR). المصدر: دليل CDL لفيرمونت (VN-111) / FMCSA 49 CFR 383.91."},"22":{"q":"تُطلب رخصة CDL من الفئة C في فيرمونت عندما لا تستوفي المركبة تعريفات الوزن للفئة A أو B ولكنها مصممة لنقل عدد لا يقل عن كم من الركاب (بما في ذلك السائق)، أو تحمل مواد خطرة تتطلب لافتات؟","options":["10 ركاب","12 راكباً","16 راكباً","24 راكباً"],"explanation":"تنطبق الفئة C في فيرمونت على مركبة (لا تستوفي المجموعة A أو B) مصممة لنقل 16 راكباً أو أكثر بما في ذلك السائق، أو تُستخدم لنقل مواد خطرة تتطلب لافتات. المصدر: دليل CDL لفيرمونت (VN-111) / FMCSA 49 CFR 383.91."},"23":{"q":"أي مصادقة يحتاجها حامل رخصة CDL في فيرمونت لقيادة مركبة تنقل كميات من المواد الخطرة تتطلب لافتات؟","options":["مصادقة N","مصادقة H","مصادقة T","مصادقة X"],"explanation":"تخوّل مصادقة H (HazMat) نقل المواد الخطرة بكميات تتطلب لافتات. (يعني الرمز X الدمج بين الصهريج والمواد الخطرة HazMat.) المصدر: صفحة مصادقات HazMat لـ Vermont DMV / دليل CDL لفيرمونت (VN-111)."},"24":{"q":"ما هو الحد الأدنى للسن للحصول على رخصة CDL في فيرمونت مقيدة بالتجارة داخل الولاية (ضمن فيرمونت) فقط؟","options":["16 عاماً","17 عاماً","18 عاماً","21 عاماً"],"explanation":"تشترط فيرمونت أن يكون المتقدم في سن 18 على الأقل للحصول على رخصة CDL وتشغيل مركبة آلية تجارية في التجارة داخل الولاية. المصدر: صفحة رخصة القيادة التجارية لـ Vermont DMV."},"25":{"q":"ما هو الحد الأدنى للسن لتشغيل مركبة آلية تجارية في التجارة بين الولايات برخصة CDL من فيرمونت؟","options":["18 عاماً","19 عاماً","20 عاماً","21 عاماً"],"explanation":"يجب أن يكون السائق في سن 21 على الأقل لتشغيل مركبة آلية تجارية في التجارة بين الولايات، بما يتوافق مع القاعدة الفيدرالية. المصدر: صفحة رخصة القيادة التجارية لـ Vermont DMV / FMCSA 49 CFR 391.11."},"26":{"q":"قبل تحديد موعد اختبار مهارات CDL، يشترط القانون الفيدرالي (المطبق في فيرمونت) أن يحمل المتقدم تصريح المتعلم التجاري (CLP) لمدة لا تقل عن كم يوماً؟","options":["7 أيام","14 يوماً","30 يوماً","60 يوماً"],"explanation":"يجب على المتقدم أن يحمل تصريح CLP لمدة 14 يوماً على الأقل قبل إجراء اختبار مهارات CDL. المصدر: صفحة CLP لـ Vermont DMV / FMCSA 49 CFR 383.25."},"27":{"q":"للتقدم بطلب للحصول على تصريح المتعلم التجاري (CLP) في فيرمونت، يجب أن يحمل المتقدم بالفعل ماذا؟","options":["رخصة قيادة فيرمونت سارية من الفئة D (العادية)","مصادقة دراجة نارية سارية","بطاقة TWIC فيدرالية","رخصة مشغّل مبتدئ"],"explanation":"تشترط فيرمونت أن يحمل المتقدمون لتصريح CLP رخصة مشغّل فيرمونت سارية من الفئة D. المصدر: صفحة تصريح متعلم القيادة التجارية لـ Vermont DMV."},"28":{"q":"إلى متى يكون تصريح المتعلم التجاري (CLP) في فيرمونت سارياً من تاريخ إصداره؟","options":["90 يوماً","6 أشهر","سنة واحدة","سنتان"],"explanation":"يكون تصريح CLP في فيرمونت سارياً لمدة سنة واحدة (12 شهراً) من تاريخ الإصدار. المصدر: صفحة تصريح متعلم القيادة التجارية لـ Vermont DMV / FMCSA 49 CFR 383.25."},"29":{"q":"أثناء القيادة على الطرق العامة، يجب أن يكون حامل تصريح CLP في فيرمونت مصحوباً بشخص:","options":["يحمل أي رخصة قيادة فيرمونت سارية","يحمل رخصة CDL سارية لفئة المركبة التي تُقاد، بما في ذلك المصادقات المطلوبة","يبلغ من العمر 25 عاماً على الأقل","هو فاحص معتمد من DMV"],"explanation":"يجب أن يكون حامل تصريح CLP مصحوباً، جالساً بجانبه، بشخص يحمل رخصة CDL سارية لنوع المركبة التي تُقاد، مع المصادقات المناسبة. المصدر: صفحة CLP لـ Vermont DMV / FMCSA 49 CFR 383.25."},"30":{"q":"أي مصادقة مطلوبة لتشغيل مركبة صهريج تنقل سوائل أو غازات بكميات كبيرة في فيرمونت؟","options":["مصادقة T","مصادقة P","مصادقة N","مصادقة S"],"explanation":"تُطلب مصادقة N (مركبة الصهريج) لنقل السوائل/الغازات بكميات كبيرة في الصهاريج. المصدر: دليل CDL لفيرمونت (VN-111) / FMCSA 49 CFR 383.93."},"31":{"q":"مركبة الصهريج التي تتطلب مصادقة N هي عموماً تلك التي تحمل سائلاً أو غازاً في صهريج بسعة مقدّرة فردية تتجاوز 119 غالوناً وسعة مقدّرة إجمالية لا تقل عن كم غالوناً؟","options":["500 غالون","1,000 غالون","1,500 غالون","3,000 غالون"],"explanation":"تنطبق مصادقة N على الصهاريج ذات السعة المقدّرة الفردية الأكبر من 119 غالوناً والسعة المقدّرة الإجمالية البالغة 1,000 غالون أو أكثر من السائل أو الغاز. المصدر: دليل CDL لفيرمونت (VN-111) / FMCSA 49 CFR 383.5."},"32":{"q":"أي مصادقة يحتاجها سائق في فيرمونت لتشغيل مقطورات مزدوجة أو ثلاثية؟","options":["مصادقة T","مصادقة N","مصادقة D","مصادقة X"],"explanation":"تخوّل مصادقة T تشغيل المقطورات المزدوجة والثلاثية وتتطلب اجتياز اختبار معرفي فقط. المصدر: دليل CDL لفيرمونت (VN-111) / FMCSA 49 CFR 383.93."},"33":{"q":"لنقل الركاب (مثل في حافلة نقل عام أو حافلة مستأجرة) في فيرمونت، أي مصادقة مطلوبة؟","options":["مصادقة S","مصادقة P","مصادقة N","مصادقة H"],"explanation":"تُطلب مصادقة P (الركاب) لتشغيل مركبة مصممة لنقل الركاب فوق عتبة CDL؛ وتتطلب اختباراً معرفياً واختبار مهارات في مركبة ركاب. المصدر: دليل CDL لفيرمونت (VN-111) / FMCSA 49 CFR 383.93."},"34":{"q":"في فيرمونت، يجب على السائق الذي يشغّل حافلة مدرسية تنقل الطلاب أن يحمل مصادقة P بالإضافة إلى أي مصادقة إضافية؟","options":["مصادقة H","مصادقة T","مصادقة S","مصادقة N"],"explanation":"يحتاج سائقو الحافلات المدرسية إلى مصادقة S (الحافلة المدرسية) بالإضافة إلى مصادقة P. تتطلب مصادقة S اختباراً معرفياً واختبار مهارات في عمليات الحافلات المدرسية. المصدر: صفحات الحافلات المدرسية لـ Vermont DMV / FMCSA 49 CFR 383.93."},"35":{"q":"ما هو الحد الأدنى للسن للحصول على مصادقة المواد الخطرة (H) على رخصة CDL في فيرمونت؟","options":["18 عاماً","19 عاماً","21 عاماً","25 عاماً"],"explanation":"نظراً لأن نقل المواد الخطرة يتطلب تأهيلاً على مستوى التجارة بين الولايات وتصريحاً أمنياً فيدرالياً، تتطلب مصادقة المواد الخطرة أن يكون المتقدم في سن 21 على الأقل. المصدر: صفحة مصادقات HazMat لـ Vermont DMV."},"36":{"q":"قبل أن تتمكن فيرمونت من إصدار أو تجديد مصادقة المواد الخطرة (H)، يجب على المتقدم اجتياز أي فحص إضافي؟","options":["فحص خلفية من إدارة أمن النقل (TSA) مع أخذ البصمات","فحص أخصائي رؤية تابع للولاية","شهادة اختبار طريق من صاحب العمل","مراجعة خدمة الحرس الوطني"],"explanation":"بموجب قانون USA PATRIOT، تتطلب مصادقة المواد الخطرة تقييماً للتهديد الأمني من TSA، بما في ذلك أخذ البصمات وفحص الخلفية، قبل الإصدار أو التجديد. المصدر: صفحة مصادقات HazMat لـ Vermont DMV / 49 CFR 1572."},"37":{"q":"بموجب قواعد ELDT المطبقة في فيرمونت، أين يجب على المتقدم لأول مرة للفئة A إكمال تدريب السائق المبتدئ المطلوب؟","options":["أي كلية مجتمع، بغض النظر عن الإدراج","مزوّد مدرج في سجل مزودي التدريب (TPR) التابع لـ FMCSA","مكتب التدريب التابع لـ Vermont DMV فقط","أي برنامج يديره صاحب عمل من اختيار السائق"],"explanation":"اعتباراً من 7 فبراير 2022، يجب إكمال ELDT (النظري والعملي خلف المقود) مع مزوّد مدرج في سجل مزودي التدريب التابع لـ FMCSA قبل اختبار المهارات. المصدر: قاعدة ELDT لـ FMCSA (49 CFR Part 380) / صفحات تدريب CDL لـ Vermont DMV."},"38":{"q":"أي مما يلي لا يتطلبه تدريب السائق المبتدئ (ELDT) قبل الاختبار؟","options":["المتقدمون لأول مرة لرخصة CDL من الفئة A أو الفئة B","السائقون الساعون للحصول على مصادقة H (المواد الخطرة) لأول مرة","السائقون الذين يرتقون من الفئة B إلى الفئة A","السائقون الذين كانوا يحملون المصادقة بالفعل قبل 7 فبراير 2022"],"explanation":"ELDT ليس بأثر رجعي: السائقون الذين صدرت لهم رخصة CDL أو مصادقة S/P/H قبل 7 فبراير 2022 غير مطالبين بإكمال ELDT. وهو ينطبق على المتقدمين لأول مرة للفئة A/B، والترقيات من B إلى A، ومصادقات S وP وH لأول مرة. المصدر: قاعدة ELDT لـ FMCSA (49 CFR Part 380)."},"39":{"q":"أي مجموعة تصف بشكل أفضل فئات التصديق الذاتي الطبي التي يجب على المتقدم لرخصة CDL في فيرمونت الاختيار من بينها؟","options":["تجارية، خاصة، زراعية، وترفيهية","بين الولايات غير معفاة، بين الولايات معفاة، داخل الولاية غير معفاة، وداخل الولاية معفاة","طبية الفئة A، طبية الفئة B، طبية الفئة C، ومعفاة","فيدرالية، ولائية، محلية، وقبلية"],"explanation":"يصادق المتقدمون لرخصة CDL ذاتياً على إحدى أربع فئات: بين الولايات غير معفاة، بين الولايات معفاة، داخل الولاية غير معفاة، أو داخل الولاية معفاة. يجب على السائقين غير المعفيين الاحتفاظ بشهادة فاحص طبي سارية. المصدر: التصديق الذاتي الطبي لرخصة CDL لـ Vermont DMV / FMCSA 49 CFR 383.71."},"40":{"q":"أثناء تشغيل مركبة آلية تجارية (CMV) في فيرمونت، ما هو الحد الأقصى القانوني لتركيز الكحول في الدم (BAC) قبل أن يُعتبر السائق مشغّلاً بمستوى كحول محظور؟","options":["0.04 بالمئة","0.08 بالمئة","0.02 بالمئة","0.10 بالمئة"],"explanation":"يجعل قانون فيرمونت من غير القانوني تشغيل مركبة CMV بتركيز كحول في الدم (BAC) يبلغ 0.04 بالمئة أو أكثر، أي نصف حد 0.08 للمركبات العادية. المصدر: 23 V.S.A. § 4116؛ دليل CDL لفيرمونت § 1.2.2."},"41":{"q":"في فيرمونت، حامل رخصة CDL الذي يُدان بأول مخالفة كبرى (مثل قيادة مركبة CMV بتركيز كحول في الدم BAC يبلغ 0.04 أو أكثر) يُحرم من تشغيل مركبة CMV لمدة لا تقل عن كم؟","options":["سنة واحدة","60 يوماً","6 أشهر","3 سنوات"],"explanation":"تحرم المخالفة الكبرى الأولى السائق من تشغيل مركبة CMV لمدة سنة واحدة. المصدر: 23 V.S.A. § 4116؛ دليل CDL لفيرمونت § 1.2.2 (المعيار الفيدرالي 49 CFR 383.51 المعتمد من فيرمونت)."},"42":{"q":"بموجب قانون فيرمونت، يُعتبر السائق بتشغيله مركبة آلية تجارية قد فعل ماذا فيما يتعلق بالفحص الكيميائي للكحول؟","options":["أعطى موافقته على فحص الكحول","تنازل عن الحق في جلسة استماع CDL","وافق على غرامة ثابتة قدرها 500 دولار","قبل بحجز المركبة لمدة 30 يوماً"],"explanation":"تنص قاعدة الموافقة الضمنية في فيرمونت على أن أي شخص يشغّل مركبة CMV يُعتبر قد أعطى موافقته على فحص الكحول. المصدر: دليل CDL لفيرمونت § 1.2.2؛ 23 V.S.A. §§ 1202, 4116."},"43":{"q":"إذا أُدين حامل رخصة CDL في فيرمونت بأول مخالفة كبرى أثناء نقل مواد خطرة تتطلب لافتات، تُرفع فترة الحرمان من تشغيل مركبة CMV إلى ما لا يقل عن كم؟","options":["3 سنوات","سنة واحدة","18 شهراً","5 سنوات"],"explanation":"ترفع المخالفة الكبرى الأولى المرتكبة أثناء نقل مواد خطرة تحمل لافتات فترة الحرمان من سنة واحدة إلى ثلاث سنوات. المصدر: 23 V.S.A. § 4116؛ 49 CFR 383.51 الجدول 1 كما اعتمدته فيرمونت."},"44":{"q":"في فيرمونت، ما هي فترة الحرمان للمخالفة الكبرى الثانية المرتكبة في مركبة CMV (على سبيل المثال، مخالفة ثانية متعلقة بالكحول من حادثة منفصلة)؟","options":["حرمان مدى الحياة","3 سنوات","10 سنوات","5 سنوات"],"explanation":"تؤدي مخالفتان كبريان ناشئتان عن حادثتين منفصلتين إلى حرمان مدى الحياة من تشغيل مركبة CMV. المصدر: 23 V.S.A. § 4116؛ دليل CDL لفيرمونت § 1.2.2."},"45":{"q":"سائق مركبة CMV في فيرمونت يرفض الخضوع لفحص الكحول في الدم المطلوب يواجه أي عاقبة على رخصة CDL لهذا الرفض؟","options":["حرمان من رخصة CDL لمدة سنة واحدة على الأقل","تحذير دون حرمان","حرمان من رخصة CDL لمدة 30 يوماً","غرامة مدنية قدرها 250 دولاراً فقط"],"explanation":"يُعامل رفض الخضوع لفحص الكحول على أنه مخالفة كبرى، ويحمل حرماناً لا يقل عن سنة واحدة من تشغيل مركبة CMV (ثلاث سنوات إذا كانت تحمل لافتات مواد خطرة). المصدر: 23 V.S.A. § 4116؛ دليل CDL لفيرمونت § 1.2.2."},"46":{"q":"إلى متى يوضع سائق مركبة CMV في فيرمونت خارج الخدمة إذا وُجد لديه أي كمية قابلة للكشف من الكحول لا تزال تحت 0.04 بالمئة؟","options":["24 ساعة","ساعة واحدة","72 ساعة","30 يوماً"],"explanation":"يوضع سائق مركبة CMV الذي لديه أي كمية كحول قابلة للقياس تحت 0.04 خارج الخدمة لمدة 24 ساعة. المصدر: دليل CDL لفيرمونت § 1.2.2؛ 49 CFR 392.5."},"47":{"q":"في فيرمونت، الإدانة بكم مخالفة مرورية خطيرة خلال فترة ثلاث سنوات تؤدي إلى حرمان من تشغيل مركبة CMV لمدة 60 يوماً؟","options":["مخالفتان خطيرتان","3 مخالفات خطيرة","4 مخالفات خطيرة","مخالفة خطيرة واحدة"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان خلال ثلاث سنوات (حادثتان منفصلتان) إلى حرمان من تشغيل مركبة CMV لمدة 60 يوماً. المصدر: 23 V.S.A. § 4116؛ دليل CDL لفيرمونت § 1.2.3."},"48":{"q":"حامل رخصة CDL في فيرمونت يُدان بثلاث مخالفات مرورية خطيرة خلال فترة ثلاث سنوات يُحرم من تشغيل مركبة CMV لمدة لا تقل عن كم؟","options":["120 يوماً","60 يوماً","180 يوماً","سنة واحدة"],"explanation":"تحمل ثلاث مخالفات مرورية خطيرة خلال ثلاث سنوات حرماناً من تشغيل مركبة CMV لمدة 120 يوماً. المصدر: 23 V.S.A. § 4116؛ دليل CDL لفيرمونت § 1.2.3."},"49":{"q":"بموجب قواعد CDL في فيرمونت، تُعتبر السرعة الزائدة مخالفة مرورية خطيرة عندما يتجاوز السائق الحد المعلن بمقدار كم؟","options":["15 ميلاً في الساعة أو أكثر","10 أميال في الساعة أو أكثر","20 ميلاً في الساعة أو أكثر","5 أميال في الساعة أو أكثر"],"explanation":"تُعد السرعة الزائدة المفرطة بمقدار 15 ميلاً في الساعة أو أكثر فوق الحد المعلن مخالفة مرورية خطيرة. المصدر: دليل CDL لفيرمونت § 1.2.3؛ 49 CFR 383.51 الجدول 2."},"50":{"q":"أي مما يلي يُصنّف على أنه مخالفة مرورية خطيرة لحامل رخصة CDL في فيرمونت؟","options":["اتباع المركبة الأمامية عن قرب أكثر من اللازم","الوقوف في منطقة ممنوع الوقوف فيها","ملصق تسجيل منتهي الصلاحية","مصباح علامة محترق"],"explanation":"اتباع المركبة عن قرب أكثر من اللازم هو إحدى المخالفات المرورية الخطيرة المدرجة، إلى جانب السرعة الزائدة المفرطة والقيادة المتهورة وتغيير المسار غير السليم أو غير المنتظم. المصدر: دليل CDL لفيرمونت § 1.2.3؛ 49 CFR 383.51 الجدول 2."},"51":{"q":"في فيرمونت، ما هي فترة الحرمان من تشغيل مركبة CMV لأول إدانة بمخالفة عبور مزلقان السكة الحديدية مع الطريق السريع؟","options":["60 يوماً على الأقل","120 يوماً على الأقل","30 يوماً على الأقل","سنة واحدة على الأقل"],"explanation":"تؤدي أول مخالفة لعبور مزلقان السكة الحديدية مع الطريق السريع إلى حرمان لا يقل عن 60 يوماً. المصدر: 23 V.S.A. § 4116؛ دليل CDL لفيرمونت § 1.2.5."},"52":{"q":"سائق مركبة CMV في فيرمونت يرتكب ثالث مخالفة لعبور مزلقان السكة الحديدية مع الطريق السريع خلال فترة ثلاث سنوات. الحد الأدنى للحرمان هو:","options":["سنة واحدة","120 يوماً","60 يوماً","6 أشهر"],"explanation":"تحمل ثالث مخالفة لعبور مزلقان السكة الحديدية مع الطريق السريع خلال ثلاث سنوات حرماناً لا يقل عن سنة واحدة (60 يوماً للأولى، 120 يوماً للثانية، سنة واحدة للثالثة). المصدر: 23 V.S.A. § 4116؛ دليل CDL لفيرمونت § 1.2.5."},"53":{"q":"أي إجراء يُعد مخالفة لعبور مزلقان السكة الحديدية مع الطريق السريع يمكن أن يحرم حامل رخصة CDL في فيرمونت؟","options":["عدم وجود مساحة كافية للقيادة عبر المزلقان بالكامل دون توقف","إطلاق البوق قبل عبور المسارات","العبور بسرعة أقل من 10 أميال في الساعة","التوقف على بعد أكثر من 50 قدماً قبل المسارات"],"explanation":"عدم وجود مساحة كافية لاجتياز المزلقان دون توقف هو إحدى المخالفات الست لعبور المزلقان. المصدر: دليل CDL لفيرمونت § 1.2.5؛ 49 CFR 383.51 الجدول 3."},"54":{"q":"في فيرمونت، ما هو الحد الأدنى للحرمان من تشغيل مركبة CMV لأول إدانة بمخالفة أمر خارج الخدمة (لا تتضمن مواد خطرة أو ركاباً)؟","options":["180 يوماً","90 يوماً","30 يوماً","سنة واحدة"],"explanation":"تؤدي أول مخالفة لأمر خارج الخدمة إلى حرمان السائق لمدة لا تقل عن 180 يوماً (حتى سنة واحدة). المصدر: 23 V.S.A. § 4116؛ 49 CFR 383.51 الجدول 4 كما اعتمدته فيرمونت."},"55":{"q":"حامل رخصة CDL في فيرمونت يُدان بثاني مخالفة لأمر خارج الخدمة خلال فترة 10 سنوات. فترة الحرمان هي:","options":["سنتان","سنة واحدة","180 يوماً","5 سنوات"],"explanation":"تحمل ثاني مخالفة لأمر خارج الخدمة خلال 10 سنوات (حادثتان منفصلتان) حرماناً لمدة سنتين. المصدر: 23 V.S.A. § 4116؛ 49 CFR 383.51 الجدول 4."},"56":{"q":"ما هي فترة الحرمان من تشغيل مركبة CMV في فيرمونت لثالث مخالفة لأمر خارج الخدمة أو ما يليها خلال فترة 10 سنوات؟","options":["3 سنوات","سنتان","سنة واحدة","مدى الحياة"],"explanation":"تؤدي ثالث مخالفة لأمر خارج الخدمة أو ما يليها خلال 10 سنوات إلى حرمان لمدة ثلاث سنوات. المصدر: 23 V.S.A. § 4116؛ 49 CFR 383.51 الجدول 4."},"57":{"q":"بموجب قانون CDL في فيرمونت، يُوصف استخدام هاتف محمول يدوي أثناء قيادة مركبة CMV بشكل أفضل بأنه:","options":["فعل محظور يُحتسب كمخالفة مرورية خطيرة","مسموح به إذا كانت المكالمة أقل من دقيقة واحدة","مسموح به فقط على الطرق السريعة بين الولايات","مخالفة غير متحركة دون تأثير على رخصة CDL"],"explanation":"تحظر فيرمونت إرسال الرسائل النصية واستخدام الهاتف المحمول اليدوي أثناء قيادة مركبة CMV؛ وتُحتسب مثل هذه الإدانات كمخالفات مرورية خطيرة تؤدي إلى الحرمان. المصدر: 23 V.S.A. § 4125؛ 49 CFR 383.51 الجدول 2."},"58":{"q":"متى يُسمح بإرسال الرسائل النصية أو استخدام الهاتف المحمول اليدوي أثناء تشغيل مركبة CMV في فيرمونت؟","options":["عند الضرورة للاتصال بإنفاذ القانون أو خدمات الطوارئ","عند التوقف عند إشارة مرور حمراء","عند السير بسرعة أقل من 25 ميلاً في الساعة","عندما يكون الحمل غير خطر"],"explanation":"الاستثناء الوحيد من حظر إرسال الرسائل النصية/استخدام الهاتف المحمول اليدوي هو التواصل مع مسؤولي إنفاذ القانون أو خدمات الطوارئ الأخرى. المصدر: 23 V.S.A. § 4125."},"59":{"q":"حامل رخصة CDL في فيرمونت المحروم مدى الحياة بسبب مخالفتين كبريين قد يتقدم بطلب لاستعادة امتيازات القيادة التجارية فقط بعد أن يكون قد حُرم لمدة لا تقل عن كم، وبعد إكمال أي إعادة تأهيل مطلوبة؟","options":["10 سنوات","5 سنوات","7 سنوات","15 سنة"],"explanation":"يمكن تخفيض الحرمان مدى الحياة من رخصة CDL بعد 10 سنوات على الأقل إذا أكمل السائق برنامج إعادة تأهيل معتمداً واستوفى متطلبات الإفادة الخطية. المصدر: قواعد ولاية فيرمونت Code of Vermont Rules 14-050-044 (تخفيض الحرمان مدى الحياة)؛ 49 CFR 383.51."},"60":{"q":"بموجب قانون \"أفسح الطريق\" (Move Over) في ولاية فيرمونت، عندما تقترب مركبة لإنفاذ القانون أو مركبة طوارئ وصفّارتها تصدر صوتاً أو مصابيح الإشارة الخاصة بها مُضاءة، ماذا يجب على سائق كل مركبة أخرى أن يفعل؟","options":["الاستمرار بشكل طبيعي طالما أن مركبة الطوارئ في مسار مختلف","الانحراف إلى يمين مسار حركة المرور والتوقف توقفاً تاماً حتى تمر المركبة","التحرك مساراً واحداً فقط إلى اليسار والحفاظ على السرعة","تخفيف السرعة إلى 20 mph دون الحد المعلن والاستمرار في المسار نفسه"],"explanation":"تشترط المادة 23 V.S.A. § 1050(a) أنه عند اقتراب مركبة لإنفاذ القانون أو سيارة إسعاف أو مركبة إطفاء أو إنقاذ تُصدر صفّارة أو تعرض مصباح الإشارة الخاص بها، يجب على جميع المركبات الأخرى \"الانحراف إلى يمين مسار حركة المرور والتوقف توقفاً تاماً حتى تمر مركبة إنفاذ القانون أو الطوارئ.\" المصدر: 23 V.S.A. § 1050(a)."},"61":{"q":"على طريق سريع متعدد المسارات في فيرمونت، ماذا يشترط قانون \"أفسح الطريق\" على السائق الذي يقترب من مركبة طوارئ أو مركبة قطر متوقفة (ثابتة) تعرض مصابيح التحذير الخاصة بها؟","options":["تخفيف السرعة إلى 25 mph بالضبط بغض النظر عن الظروف","التوقف فقط إذا كانت المركبة الثابتة سيارة شرطة وليست شاحنة قطر","التوقف توقفاً تاماً دائماً في مسار السير حتى تُعطى إشارة المتابعة","تغيير المسار إلى مسار أبعد إذا سمحت ظروف السلامة بذلك؛ وإلا تخفيف السرعة إلى سرعة معقولة وآمنة وحصيفة"],"explanation":"تنص المادة 23 V.S.A. § 1050(b) على أن السائق الذي يقترب من مركبة طوارئ ثابتة (أو مركبة قطر/إصلاح تعرض مصباحاً كهرمانياً) يجب أن يتابع بحذر، وإذا كان على طريق سريع متعدد المسارات وسمحت السلامة بذلك، أن يتحول إلى مسار أبعد عن المركبة الثابتة؛ وإذا تعذّر تغيير المسار، فعلى السائق تخفيف السرعة إلى \"سرعة معقولة وآمنة وحصيفة.\" المصدر: 23 V.S.A. § 1050(b)."},"62":{"q":"تنطبق قاعدة \"أفسح الطريق\" للمركبات الثابتة في فيرمونت على مركبة القطر والإصلاح المتوقفة عندما تعرض مصباح إشارة بأي لون؟","options":["أزرق","أحمر وأبيض","أخضر","كهرماني"],"explanation":"توسّع المادة 23 V.S.A. § 1050(b) واجب الانحراف/تخفيف السرعة ليشمل \"مركبة قطر وإصلاح ثابتة تعرض مصباح إشارة كهرماني،\" إضافة إلى مركبات الشرطة (الأزرق) ومركبات الإسعاف/الإطفاء/الإنقاذ (الأحمر). المصدر: 23 V.S.A. § 1050(b)."},"63":{"q":"عند توقّف حافلة مدرسية في فيرمونت مُعلّمة ومجهّزة كما هو مطلوب، متى يجب على حركة المرور المقتربة والمتجاوزة أن تتوقف؟","options":["فقط إذا كانت أضواء الحافلة الكهرمانية وامضة","فقط عندما يكون الأطفال واقفين بشكل ظاهر على الطريق","فوراً، والبقاء متوقفاً طوال تشغيل أضواء الإشارة الحمراء الوامضة","في حدود 25 قدماً من الحافلة، ثم المرور بجانبها ببطء"],"explanation":"تشترط المادة 23 V.S.A. § 1075 على السائق، عند مقابلة أو تجاوز حافلة مدرسية مُعلّمة بشكل صحيح ومتوقفة لتحميل أو إنزال أطفال المدارس، أن \"يوقف مركبته فوراً\" وأن يبقيها ثابتة \"طوال تشغيل أضواء الإشارة الحمراء الوامضة.\" المصدر: 23 V.S.A. § 1075."},"64":{"q":"بموجب قانون فيرمونت، الحالة الوحيدة التي لا يلزم فيها السائق التوقف لحافلة مدرسية تُحمّل الأطفال على الجانب المقابل هي عندما تكون الحافلة على:","options":["أي طريق من أربعة مسارات، سواء أكان به فاصل أم لا","أي طريق يسير فيه السائق بسرعة أقل بـ 10 mph على الأقل من الحد","أي طريق به خط مزدوج أصفر مرسوم في الوسط","طريق سريع ذو ممرات منفصلة، مع وجود الحافلة على ممر مختلف"],"explanation":"تُعفي المادة 23 V.S.A. § 1075 من التوقف فقط \"على طريق سريع ذي ممرات منفصلة\" عند مقابلة أو تجاوز حافلة على ممر مختلف (أو عند منطقة تحميل ذات وصول مُتحكَّم به حيث لا يجوز للمشاة العبور). ويجب أن تكون الممرات منفصلة مادياً؛ والخط المرسوم لا يُعدّ كافياً. المصدر: 23 V.S.A. § 1075."},"65":{"q":"في فيرمونت، عندما يجب على مركبة مواد خطرة تحمل لافتات أو على حافلة أن تتوقف عند تقاطع سكة حديد مع الطريق، أين يجب أن تتوقف بالنسبة لأقرب قضيب سكة؟","options":["على بُعد 10 feet بالضبط من أقرب قضيب","في أي مكان ضمن 75 feet من أقرب قضيب","في حدود 50 feet ولكن ليس أقل من 15 feet من أقرب قضيب","في حدود 100 feet ولكن ليس أقل من 25 feet من أقرب قضيب"],"explanation":"اتباعاً للمعيار الفيدرالي CDL/FMCSA المطبّق في فيرمونت (49 CFR 392.10)، يجب على سائق مركبة المواد الخطرة الحاملة للافتات أو الحافلة المطلوب منها التوقف أن يفعل ذلك في حدود 50 feet ولكن ليس أقل من 15 feet من أقرب قضيب. المصدر: دليل فيرمونت لرخصة CDL (تقاطعات السكك الحديدية مع الطرق)؛ 49 CFR 392.10."},"66":{"q":"أثناء عبور مركبة تجارية في فيرمونت لقضبان السكة الحديدية، ما الذي يوجّه دليل CDL السائقَ بألّا يفعله؟","options":["إبقاء كلتا اليدين على المقود","العبور بترس منخفض بما يكفي لتجنّب توقّف المحرك","النظر والإصغاء في كلا الاتجاهين قبل الدخول","تبديل التروس أثناء وجود أي جزء من المركبة على القضبان"],"explanation":"يوجّه دليل فيرمونت لرخصة CDL السائقين بعدم تبديل التروس أبداً أثناء عبور القضبان، لأن التبديل يُخاطر بتوقّف المحرك على التقاطع. وينبغي للسائق اختيار الترس قبل الوصول إلى القضبان وعدم تغييره حتى يتجاوزها. المصدر: دليل فيرمونت لرخصة CDL (تقاطعات السكك الحديدية مع الطرق)."},"67":{"q":"قبل أن يبدأ سائق مركبة تجارية في فيرمونت العبور عبر تقاطع سكة حديد، يقول الدليل إنه يجب على السائق التأكد من وجود مساحة كافية على الجانب الآخر بحيث إن المركبة:","options":["يبقى لها محور واحد على الأقل بين القضبين","تستطيع التوقف على القضبان للتحقق من القطارات القادمة","تستطيع التوقف وصدّامها الأمامي على القضيب الثاني","تستطيع تجاوز القضبان بالكامل دون التوقف عليها"],"explanation":"يحذّر دليل فيرمونت لرخصة CDL من أنه يجب على السائق ألّا يبدأ العبور عبر القضبان أبداً دون التأكد من أن المركبة تستطيع تجاوزها بالكامل دون التوقف. يجب أن يكون لدى السائق مساحة على الجانب الآخر لتجاوز التقاطع بالكامل. المصدر: دليل فيرمونت لرخصة CDL (تقاطعات السكك الحديدية مع الطرق)."},"68":{"q":"توقفت مركبة تجارية في فيرمونت على طريق مستوٍ ومستقيم من مسارين. أين تُوضع أجهزة التحذير الثلاثة (المثلثات العاكسة)؟","options":["على بُعد نحو 25 feet و75 feet و150 feet إلى الخلف","على بُعد نحو 50 feet و150 feet و300 feet إلى الخلف","على بُعد نحو 10 feet و100 feet و200 feet إلى الخلف باتجاه حركة المرور القادمة","على بُعد نحو 10 feet و50 feet و100 feet إلى الخلف"],"explanation":"اتباعاً لمعيار FMCSA/CDL المستخدم في فيرمونت، على طريق من مسارين تُوضع المثلثات على بُعد نحو 10 feet خلف المركبة مباشرة، ونحو 100 feet إلى الخلف، ونحو 200 feet إلى الخلف باتجاه حركة المرور القادمة. المصدر: دليل فيرمونت لرخصة CDL (التوقف على الطريق)؛ 49 CFR 392.22."},"69":{"q":"إذا توقفت مركبة تجارية في فيرمونت ضمن 500 feet من تلّة أو منعطف أو أي عائق آخر يحجب الرؤية، فكيف ينبغي تعديل أجهزة التحذير؟","options":["وضع جهاز باتجاه العائق على بُعد 100 إلى 500 feet من المركبة لإعطاء تحذير كافٍ","لا حاجة لأي مثلثات لأن الخطر مرئي","وضع الأجهزة الثلاثة كلها خلف المركبة مباشرة ضمن 10 feet","وضع جهاز على بُعد 700 feet بالضبط بعد العائق"],"explanation":"يوجّه دليل فيرمونت لرخصة CDL (وفقاً لـ 49 CFR 392.22) أنه إذا كان التوقف ضمن 500 feet من منعطف أو قمة تلّة أو أي عائق آخر للرؤية، فإن السائق يحرّك جهاز التحذير الخلفي باتجاه العائق ليقف على بُعد 100 إلى 500 feet من المركبة. المصدر: دليل فيرمونت لرخصة CDL؛ 49 CFR 392.22."},"70":{"q":"ما هو الحد الأقصى القانوني للسرعة لأي مركبة آلية على طريق سريع ذي وصول محدود (طريق بين الولايات) في فيرمونت، ما لم يُعلن خلاف ذلك؟","options":["55 mph","65 mph","60 mph","70 mph"],"explanation":"تحدد لائحة الطرق السريعة ذات الوصول المحدود في فيرمونت الحد الأقصى عند 65 mph: \"يكون الحد الأقصى للسرعة التي يجوز بها تشغيل أي مركبة آلية على الطرق السريعة ذات الوصول المحدود خمسة وستين (65) ميلاً في الساعة،\" ما لم يُعلن خلاف ذلك. المصدر: Code Vt. R. 14-053-004 (مرافق الوصول المحدود)؛ 23 V.S.A. § 1081."},"71":{"q":"في غياب حد معلن أو تصنيف وصول محدود، ما هو الحد الأقصى القانوني الافتراضي للسرعة على طريق سريع في فيرمونت؟","options":["65 mph","50 mph","45 mph","55 mph"],"explanation":"تُرسي المادة 23 V.S.A. § 1081 حداً أقصى افتراضياً قدره 50 mph على الطرق السريعة ما لم يُعلن أو يُحدَّد حد مختلف بموجب القانون. وتنطبق الحدود الأعلى (حتى 65 mph) فقط على الطرق السريعة ذات الوصول المحدود بصلاحية لجنة المرور. المصدر: 23 V.S.A. § 1081."},"72":{"q":"هل تحدد فيرمونت حداً أقصى منفصلاً وأقل للسرعة للشاحنات والمركبات التجارية مقارنةً بالسيارات على طرقها السريعة؟","options":["لا — الحد المعلن ينطبق على جميع المركبات؛ ولا يوجد حد سرعة منفصل للشاحنات","نعم — الشاحنات محدودة بـ 60 mph على الطرق بين الولايات","نعم — الشاحنات محدودة بـ 55 mph في كل مكان","نعم — يجب أن تبقى الشاحنات أقل بـ 10 mph من حد السيارات المعلن"],"explanation":"لا تفرض فيرمونت حد سرعة منفصلاً وأقل للشاحنات. وينطبق الحد الأقصى نفسه (مثل 65 mph على الطرق السريعة ذات الوصول المحدود، و50 mph افتراضياً) على جميع المركبات الآلية، بما فيها الشاحنات والحافلات. المصدر: 23 V.S.A. § 1081؛ Code Vt. R. 14-053-004."},"73":{"q":"على طريق سريع ذي وصول محدود في فيرمونت، يجوز لشاحنة أو حافلة السير دون الحد الأدنى المعلن للسرعة بسبب الانحدار فقط إذا:","options":["عرضت إشاراتها الوامضة الرباعية أثناء ذلك","تحركت بالكامل إلى الكتف الأيسر","أطلقت بوقها باستمرار","حصلت أولاً على تصريح سفر للأحمال كبيرة الحجم"],"explanation":"تُعفي لائحة الوصول المحدود في فيرمونت الشاحنات الآلية والحافلات من قاعدة الحد الأدنى للسرعة عندما يجعل الانحدار تلك السرعة غير عملية، ولكن فقط إذا عرضت المركبة الإشارات الوامضة الرباعية خلال ذلك الوقت. المصدر: Code Vt. R. 14-053-004 (مرافق الوصول المحدود)."},"74":{"q":"الطريق Vermont Route 108 عبر Smugglers' Notch مغلق أمام أي مركبات؟","options":["أي مركبة أعرض من 8 feet 6 inches","المركبات أحادية الهيكل التي يتجاوز طولها 40 feet وتركيبات الجرّار-المقطورة التي يتجاوز طولها الإجمالي 45 feet","جميع المركبات التي يتجاوز وزنها الإجمالي المسموح به 26,000 pounds","الحافلات التي تنقل أكثر من 15 راكباً"],"explanation":"تحظر المادة 23 V.S.A. § 1006b المركبات الآلية أحادية الهيكل التي يتجاوز طولها 40 feet، ووحدات الجرّار مع مقطورة واحدة أو أكثر التي يتجاوز طولها الإجمالي 45 feet، من مقطع Smugglers' Notch من الطريق Vermont Route 108. فالممر الجبلي الضيق لا يستوعبها. المصدر: 23 V.S.A. § 1006b؛ وكالة فيرمونت للنقل (vtrans.vermont.gov/notch)."},"75":{"q":"سائق شاحنة يتجاهل نظام تحديد المواقع (GPS) فتعلق جرّار-مقطورته في Smugglers' Notch على الطريق Vermont Route 108 يواجه عقوبة مدنية من المقرر أن ترتفع، في حال عرقلة حركة المرور بشكل كبير، في 1 يوليو 2026 إلى:","options":["$2,000","$50,000","$20,000","$5,000"],"explanation":"بموجب المادة 23 V.S.A. § 1006b كانت الغرامة الأساسية $1,000، أو $2,000 إذا أعاقت المخالفة حركة المرور بشكل كبير؛ ويرفع التشريع هذه المبالغ إلى $10,000 و$20,000 (لعرقلة حركة المرور) اعتباراً من 1 يوليو 2026. المصدر: 23 V.S.A. § 1006b؛ وكالة فيرمونت للنقل."},"76":{"q":"بدون تصريح للحجم الزائد، ما هو الحد الأقصى القانوني لعرض المركبة على الطرق السريعة في فيرمونت؟","options":["8 feet 0 inches","8 feet 6 inches","10 feet 0 inches","9 feet 0 inches"],"explanation":"الحد الأقصى القانوني لعرض المركبة في فيرمونت بدون تصريح هو 8 feet 6 inches (102 inches)؛ والارتفاع القانوني هو 13 feet 6 inches والوزن الإجمالي القانوني هو 80,000 pounds. وتجاوز هذه الحدود يتطلب تصريحاً للحجم الزائد/الوزن الزائد من قسم عمليات المركبات التجارية في Vermont DMV. المصدر: قواعد تصاريح الحجم الزائد/الوزن الزائد لعمليات المركبات التجارية في Vermont DMV (CVO-110)."},"77":{"q":"تصاريح الحجم الزائد/الوزن الزائد في فيرمونت تأذن عموماً بالتحرّك فقط خلال أي ساعات؟","options":["من نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروبها","فقط بين منتصف الليل و6:00 صباحاً","24 ساعة في اليوم دون أي قيد","فقط في عطلات نهاية الأسبوع والعطلات الرسمية"],"explanation":"تقصر قواعد التصاريح في فيرمونت السفر بالأحمال كبيرة الحجم/الثقيلة على ساعات النهار: من نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروبها، مع قيود إضافية على أكبر الأحمال خلال عطلات نهاية الأسبوع والعطلات. المصدر: قواعد تصاريح الحجم الزائد/الوزن الزائد لعمليات المركبات التجارية في Vermont DMV (CVO-110)."},"78":{"q":"على طريق في فيرمونت، أين يجب قيادة شاحنة تسير أبطأ من السرعة الطبيعية لحركة المرور؟","options":["في المسار الأيمن المتاح، أو أقرب ما يمكن عملياً إلى الحافة اليمنى، باستثناء عند التجاوز أو الاستعداد للانعطاف يساراً","في المسار الأيسر حتى يتمكن المرور الأسرع من الاندماج يميناً","على الكتف المعبّد حتى تنحسر حركة المرور","في المسار الأوسط لأي طريق متعدد المسارات في جميع الأوقات"],"explanation":"تشترط قاعدة الالتزام باليمين في فيرمونت أن تُقاد المركبة التي تسير دون السرعة الطبيعية لحركة المرور في المسار الأيمن، أو أقرب ما يمكن عملياً إلى الرصيف الأيمن أو الحافة اليمنى، باستثناء عند اللحاق والتجاوز أو الاستعداد لانعطاف يساري. المصدر: 23 V.S.A. § 1038 / § 1031."},"79":{"q":"بموجب قانون فيرمونت، من الذي يجوز له اشتراط سلاسل الإطارات على طرق سريعة محددة تابعة للولاية خلال طقس الشتاء، ولأي مركبات؟","options":["السلاسل مطلوبة فقط على طرق البلدات، وليس أبداً على الطرق السريعة للولاية","الحكومة الفيدرالية وحدها يمكنها فرض السلاسل، وفقط على الطرق بين الولايات","يجوز لمسؤولي الولاية اشتراط السلاسل للمركبات التي يتجاوز وزنها الإجمالي المسموح به (GVWR) أو وزن التركيبة الإجمالي المسموح به (GCWR) 26,000 pounds على أجزاء محددة من الطرق السريعة","السلاسل إلزامية لكل سيارة ركاب من ديسمبر حتى مارس"],"explanation":"تأذن المادة 23 V.S.A. § 1006c لأمين النقل أو مفوض المركبات الآلية أو مفوض السلامة العامة (أو من ينوب عنهم) باشتراط سلاسل الإطارات على أجزاء محددة من الطرق السريعة للولاية خلال طقس الشتاء للمركبات التي يتجاوز وزنها الإجمالي المسموح به (GVWR) أو وزن التركيبة الإجمالي المسموح به (GCWR) 26,000 pounds، مع لافتات إنذار مسبق. المصدر: 23 V.S.A. § 1006c."},"80":{"q":"في فيرمونت، أي جهة تصدر رخص القيادة التجارية (CDLs) وتدير الاختبارات المطلوبة؟","options":["إدارة المركبات الآلية في فيرمونت (DMV)","وكالة فيرمونت للنقل (VTrans)","الإدارة الفيدرالية لسلامة الناقلين بالشاحنات (FMCSA)","وحدة المركبات التجارية في شرطة ولاية فيرمونت"],"explanation":"تُصدر إدارة المركبات الآلية في فيرمونت (DMV) رخص CDL وتدير اختبارات المعرفة والمهارات في الولاية. وتضع FMCSA المعايير الفيدرالية لرخصة CDL لكنها لا تصدر الرخصة. المصدر: Vermont DMV، صفحة رخصة القيادة التجارية (CDL)؛ دليل سائق CDL في فيرمونت (VN-111)."},"81":{"q":"قبل أن يتمكن الشخص من إجراء اختبار مهارات CDL في فيرمونت، ما التصريح الذي يجب أن يحصل عليه ويحمله أولاً؟","options":["تصريح متعلّم القيادة التجارية (CLP)","تصريح متعلّم قيادة عادي في فيرمونت فقط","تصريح تشغيل مؤقت بين الولايات","تصريح حمولة كبيرة الحجم/زائدة الوزن"],"explanation":"تشترط فيرمونت على المتقدمين الحصول على تصريح متعلّم القيادة التجارية (CLP)، الذي يأذن بالتدريب تحت الإشراف في مركبة آلية تجارية قبل اختبار المهارات. المصدر: Vermont DMV، صفحة تصريح متعلّم القيادة التجارية (CLP)؛ دليل سائق CDL في فيرمونت (VN-111)."},"82":{"q":"بعد الحصول على تصريح متعلّم القيادة التجارية في فيرمونت، ما هو الحد الأدنى لعدد الأيام التي يجب على السائق حمله خلالها قبل إجراء اختبار مهارات CDL؟","options":["14 days","7 days","30 days","60 days"],"explanation":"يجب على حامل CLP الانتظار لمدة لا تقل عن 14 days بعد إصدار الـ CLP قبل إجراء اختبار المهارات لرخصة CDL. المصدر: Vermont DMV، صفحات تصريح متعلّم القيادة التجارية (CLP) والتجديدات/التحويلات/الترقيات؛ القانون الفيدرالي 49 CFR 383.25."},"83":{"q":"يتكوّن اختبار مهارات CDL في فيرمونت من أي ثلاثة أجزاء؟","options":["فحص ما قبل الرحلة، والتحكم الأساسي بالمركبة، والقيادة على الطريق","اختبار المعرفة التحريري، وفحص العين، والقيادة على الطريق","فحص فرامل الهواء، ومناولة المواد الخطرة، والقيادة الليلية","فحص ما قبل الرحلة، والركن الموازي، واختبار سرعة الطريق السريع"],"explanation":"يتكوّن اختبار مهارات CDL في فيرمونت من ثلاثة أجزاء، يجب اجتيازها جميعاً: فحص المركبة ما قبل الرحلة، ومناورات التحكم الأساسي بالمركبة، واختبار القيادة على الطريق. المصدر: صفحات CDL في Vermont DMV؛ دليل سائق CDL في فيرمونت (VN-111)."},"84":{"q":"أي نموذج يقدّمه السائق للإقرار الذاتي بنوع قيادته وحالته الطبية لدى Vermont DMV؟","options":["نموذج الشهادة الطبية لرخصة CDL (VL-033)","شهادة الفاحص الطبي الفيدرالية وحدها","إقرار موثّق باللياقة","نموذج التحقق من الخلفية للمواد الخطرة من TSA"],"explanation":"يُقرّ حاملو ومتقدمو CDL في فيرمونت ذاتياً بنوع قيادتهم وحالتهم الطبية عن طريق تعبئة وتقديم نموذج الشهادة الطبية لرخصة CDL، VL-033، إلى DMV. المصدر: Vermont DMV، صفحة المتطلبات الطبية لرخصة CDL ونموذج VL-033."},"85":{"q":"عند الإقرار الذاتي لدى Vermont DMV، من بين كم فئة قيادة يجوز لمتقدم CDL أن يختار؟","options":["أربع","اثنتان","ثلاث","خمس"],"explanation":"هناك أربع فئات للإقرار الذاتي: غير المستثناة بين الولايات (NI)، والمستثناة بين الولايات (EI)، وغير المستثناة داخل الولاية (NA)، والمستثناة داخل الولاية (EA). ويختار السائق واحدة منها في النموذج VL-033. المصدر: الشهادة الطبية لرخصة CDL في Vermont DMV (نموذج VL-033)؛ 49 CFR 383.71."},"86":{"q":"متقدم رخصة CDL في فيرمونت يقود في التجارة بين الولايات ويخضع لقواعد التأهيل البدني الفيدرالية (49 CFR Part 391) ينبغي له الإقرار الذاتي بأي فئة؟","options":["غير المستثناة بين الولايات (NI)","المستثناة بين الولايات (EI)","غير المستثناة داخل الولاية (NA)","المستثناة داخل الولاية (EA)"],"explanation":"السائق الذي يعمل في التجارة بين الولايات ويخضع لـ 49 CFR Part 391 يُقرّ ذاتياً بأنه ضمن فئة غير المستثناة بين الولايات (NI) ويجب أن يقدّم شهادة فاحص طبي سارية. المصدر: نموذج Vermont DMV VL-033؛ 49 CFR 383.71."},"87":{"q":"أي فئة من فئات الإقرار الذاتي في فيرمونت تتطلب من السائق تقديم شهادة فاحص طبي سارية من نوع \"Vermont Only\"؟","options":["غير المستثناة داخل الولاية (NA)","غير المستثناة بين الولايات (NI)","المستثناة بين الولايات (EI)","المستثناة داخل الولاية (EA)"],"explanation":"السائق ضمن فئة غير المستثناة داخل الولاية (NA) يعمل فقط داخل فيرمونت ويجب أن يستوفي المعايير الطبية بتقديم شهادة فاحص طبي سارية من نوع \"Vermont Only\". المصدر: الشهادة الطبية لرخصة CDL في Vermont DMV (نموذج VL-033)."},"88":{"q":"من المخوّل بإجراء فحص DOT البدني الذي يُنتج شهادة فاحص طبي لرخصة CDL مقبولة في فيرمونت؟","options":["فاحص طبي مدرج في السجل الوطني للفاحصين الطبيين المعتمدين لدى FMCSA","أي طبيب مرخّص يختاره السائق","فاحص تابع لـ Vermont DMV في موقع الاختبار","مسؤول السلامة لدى صاحب عمل السائق"],"explanation":"يجب أن يُجري الفحص البدني فاحص طبي مدرج في السجل الوطني للفاحصين الطبيين المعتمدين لدى FMCSA. المصدر: Vermont DMV، صفحة المتطلبات الطبية لرخصة CDL؛ 49 CFR 390.103 / Part 391."},"89":{"q":"ما هي أقصى مدة يمكن أن تكون فيها شهادة فاحص DOT الطبية القياسية سارية لحامل CDL في فيرمونت؟","options":["حتى سنتين (2 years)","حتى سنة واحدة (1 year)","حتى ثلاث سنوات (3 years)","حتى خمس سنوات (5 years)"],"explanation":"شهادة الفاحص الطبي القياسية سارية لمدة تصل إلى سنتين (2 years)، رغم أنه يجوز للفاحص إصدار واحدة لمدة أقصر إذا كانت هناك حالة تحتاج إلى متابعة. المصدر: Vermont DMV، صفحة المتطلبات الطبية لرخصة CDL؛ 49 CFR Part 391."},"90":{"q":"ماذا يمكن أن يحدث لرخصة CDL في فيرمونت إذا أخفق حاملها في الاحتفاظ بشهادة طبية سارية في الملف لدى DMV؟","options":["قد تُخفَّض رتبة رخصة CDL أو تُعلَّق صلاحية القيادة","لا شيء، طالما أن الرخصة نفسها لم تنتهِ صلاحيتها","يُمنح السائق تلقائياً حالة المستثناة بين الولايات","يُرسل تحذير كتابي فقط دون أي تأثير على الرخصة"],"explanation":"إذا لم يُحتفظ بالوثائق الطبية السارية في الملف، يجوز لـ Vermont DMV تخفيض رتبة رخصة CDL (إزالة الامتيازات التجارية) و/أو تعليق صلاحية القيادة. المصدر: Vermont DMV، صفحة المتطلبات الطبية لرخصة CDL؛ 49 CFR 383.73."},"91":{"q":"أي تدريب يجب أن يكمله المتقدم لأول مرة لرخصة CDL من الفئة A أو الفئة B قبل السماح له بإجراء اختبار المهارات في فيرمونت؟","options":["تدريب سائقي المستوى المبتدئ (ELDT) من مزوّد مسجّل لدى FMCSA","دورة قيادة دفاعية معتمدة من Vermont DMV","دورة صفّية مدتها ثماني ساعات تُدرّسها DMV","تلمذة مهنية مسجّلة لدى صاحب العمل فقط"],"explanation":"يجب على المتقدمين لأول مرة من الفئة A/B (وبعض التظهيرات) إكمال تدريب سائقي المستوى المبتدئ (ELDT) من مزوّد مدرج في سجل مزوّدي التدريب لدى FMCSA قبل إجراء اختبار مهارات CDL. المصدر: صفحات CDL في Vermont DMV؛ 49 CFR Part 380 Subpart F."},"92":{"q":"بالنسبة لتظهير المواد الخطرة (HazMat) (H) لأول مرة، متى يجب إكمال تدريب سائقي المستوى المبتدئ المطلوب؟","options":["قبل إجراء اختبار معرفة المواد الخطرة (HazMat)","قبل اختبار المهارات على الطريق فقط","في غضون 30 days بعد إصدار الرخصة","فقط بعد الموافقة على التحقق من الخلفية من TSA"],"explanation":"بما أن تظهير المواد الخطرة (HazMat) لا يتضمن اختبار مهارات، يجب إكمال ELDT لتظهير H لأول مرة قبل أن يجري المتقدم اختبار معرفة المواد الخطرة (HazMat). المصدر: صفحات CDL في Vermont DMV؛ 49 CFR Part 380 Subpart F."},"93":{"q":"أي اختبار معرفة يجب أن يجتازه كل متقدم لرخصة CDL في فيرمونت بغض النظر عن الفئة أو التظهير؟","options":["اختبار المعرفة العامة","اختبار فرامل الهواء","اختبار المركبات المركّبة","اختبار المواد الخطرة"],"explanation":"يجب أن يجتاز كل متقدم لرخصة CDL اختبار المعرفة العامة التحريري؛ أما الاختبارات الإضافية مثل فرامل الهواء والمركبات المركّبة واختبارات التظهير فتنطبق فقط بحسب صلتها بالمركبة أو التظهير. المصدر: دليل سائق CDL في فيرمونت (VN-111)؛ صفحات CDL في Vermont DMV."},"94":{"q":"ما هي الدرجة الدنيا المطلوبة لاجتياز اختبار معرفة (تحريري) لرخصة CDL في فيرمونت؟","options":["80 percent","70 percent","75 percent","90 percent"],"explanation":"تتطلب اختبارات معرفة CDL في فيرمونت درجة نجاح لا تقل عن 80 percent من الأسئلة المُجاب عليها بشكل صحيح. المصدر: دليل سائق CDL في فيرمونت (VN-111)؛ معلومات اختبار CDL لدى Vermont DMV."},"95":{"q":"يجب تجديد رخصة CDL في فيرمونت باستخدام أي طريقة؟","options":["شخصياً في مكتب Vermont DMV","عبر الإنترنت فقط من خلال موقع DMV الإلكتروني","بالبريد باستخدام إشعار التجديد فقط","تلقائياً، دون أي إجراء من السائق"],"explanation":"يجب تجديد رخصة CDL شخصياً في مكتب خدمة العملاء التابع لـ Vermont DMV؛ ويُحضر السائق إشعار التجديد الموقّع والرسوم. المصدر: Vermont DMV، صفحة التجديدات والتحويلات والترقيات."},"96":{"q":"لكم سنة يجوز تجديد رخصة CDL في فيرمونت في المرة الواحدة؟","options":["سنتان أو أربع سنوات","سنة أو سنتان","خمس سنوات","ثماني سنوات"],"explanation":"تُصدر تجديدات رخصة CDL في فيرمونت على دورة من سنتين أو أربع سنوات، مع احتساب أي سنوات كاملة متبقية على الوثيقة الحالية مقابل رسوم التجديد. المصدر: Vermont DMV، صفحة التجديدات والتحويلات والترقيات."},"97":{"q":"الشخص الذي يحمل رخصة CDL سارية من ولاية أخرى وينتقل إلى فيرمونت يجب أن يحوّلها إلى رخصة CDL في فيرمونت خلال أي مدة بعد إثبات الإقامة؟","options":["30 days","10 days","60 days","90 days"],"explanation":"بموجب قانون الولاية والقانون الفيدرالي، يجب على الشخص الذي يحمل رخصة CDL من خارج الولاية أن يحوّلها إلى رخصة CDL في فيرمونت خلال 30 days من إثبات الإقامة في فيرمونت. المصدر: Vermont DMV، صفحة التجديدات والتحويلات والترقيات؛ 49 CFR 383.71."},"98":{"q":"عند ترقية رخصة CDL قائمة في فيرمونت إلى فئة أعلى، ماذا يجب على السائق أن يفعل بخصوص التصريح؟","options":["الحصول على تصريح متعلّم القيادة التجارية وحمله لمدة 14 days على الأقل","لا شيء؛ فرخصة CDL القائمة كافية للاختبار للترقية","الحصول فقط على تصريح متعلّم قيادة عادي للمشغّل","حمل التصريح الجديد لمدة لا تقل عن 90 days"],"explanation":"للترقية إلى فئة أعلى من رخصة CDL، يجب على السائق الحصول على تصريح متعلّم القيادة التجارية، وحمله لمدة 14 days على الأقل، واجتياز اختبارات المعرفة والمهارات المناسبة. المصدر: Vermont DMV، صفحة التجديدات والتحويلات والترقيات."},"99":{"q":"لماذا تنصح Vermont DMV متقدمي CDL باعتبار رسوم الرخصة والاختبار المنشورة قابلة للتغيير؟","options":["تُحدَّد مبالغ الرسوم بموجب القانون وجداول DMV التي يمكن تنقيحها، لذا ينبغي دائماً التأكد من الرسوم المنشورة الحالية","لا تفرض فيرمونت أي رسوم على خدمات CDL، لذا فإن أي مبلغ منشور هو خطأ","تُتفاوض الرسوم بشكل فردي عند المكتب لكل متقدم","الحكومة الفيدرالية وحدها، وليست فيرمونت، يجوز لها تحديد رسوم CDL أو تغييرها"],"explanation":"تُحدَّد رسوم CDL والاختبار بموجب قانون فيرمونت وجداول رسوم DMV التي قد يتم تحديثها، لذا ينبغي للمتقدمين التأكد من المبلغ الحالي مع DMV بدلاً من الاعتماد على رقم ثابت. المصدر: معلومات رسوم Vermont DMV؛ 23 V.S.A. (قوانين رسوم المركبات الآلية)."}}};
